  cebu_surigao:{label:'Cebu → Surigao via Maasin',short:'Surigao',travel:'5h 30m',fare:{'TC/OA':2470,BC:3510,ST:1976,MI:1235},slab:{normal:[30,35,40],fragile:[50,65,85]},trips:[['7:00 AM','OJ 03 + OJ 388','12:30 PM','Via Maasin']]},
