async function clearOldCache(){try{if('serviceWorker'in navigator){const regs=await navigator.serviceWorker.getRegistrations();for(const r of regs)await r.unregister()}if(window.caches){const keys=await caches.keys();for(const k of keys)await caches.delete(k)}audit('Cache cleared','service workers + caches');save();toast('Old cache cleared. Reload now.')}catch(e){toast('Cache clear failed: '+e.message)}}
function system(){setTitle('System Tools','Cache, shift, and settings');$('content').innerHTML=hero('System Tools','Use this after uploading to GitHub Pages if old versions still show.','Admin')+`<div class="grid"><div class="card span6"><h3>Cache Tools</h3><p>Removes old caches/service workers where browser allows.</p><div style="display:grid;gap:8px;margin-top:12px"><button class="danger" onclick="clearOldCache()">Clear Old App Cache</button><button onclick="runDiagnostics()">Run Diagnostics</button><button class="warn" onclick="hardResetData()">Reset V62 Local Data</button></div><div id="diagOut" class="notice" style="margin-top:12px">Ready.</div></div><div class="card span6"><h3>Shift Setup</h3><div class="formGrid"><label>Port<input id="shiftPort" value="${esc(state.data.shift.port||'Cebu')}"></label><label>Staff Name<input id="shiftStaff" value="${esc(state.data.shift.staff||'')}"></label></div><div class="miniActions"><button class="primary" onclick="startShift()">Start / Update Shift</button><button onclick="closeShift()">Close Shift</button></div><div class="notice ${state.data.shift.open?'alertGood':'alertWarn'}" style="margin-top:12px">Shift is ${state.data.shift.open?'open since '+esc(state.data.shift.startedAt):'closed'}.</div></div><div class="card span6"><h3>Staff Credentials</h3><div class="formGrid"><label>Cashier User<input id="setCashierU" value="${esc(state.data.settings.cashier.u)}"></label><label>Cashier Pass<input id="setCashierP" value="${esc(state.data.settings.cashier.p)}"></label><label>Admin User<input id="setAdminU" value="${esc(state.data.settings.admin.u)}"></label><label>Admin Pass<input id="setAdminP" value="${esc(state.data.settings.admin.p)}"></label></div><button class="primary block" style="margin-top:12px" onclick="saveCreds()">Save Credentials</button></div><div class="card span6 dangerZone"><h3>Design Decision</h3><p>This is a scratch app. It does not load legacy V6–V57 scripts, scanner patches, recovery watchers, repeated intervals, observers, or auto-capture. Optional automation is sealed in the Admin Automation Center.</p></div><div class="card span6"><h3>Automation Shortcut</h3><p>Open the sealed automation center. Master switch is off by default.</p><button class="primary block" onclick="renderApp('automation')">Open Automation Center</button></div></div>`}
