NAVS.cashier = [['dashboard','🏠','Home'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['trips','🕐','Trips']];
NAVS.admin = [['dashboard','🏠','Command'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['quality','🧪','Quality'],['reports','📊','Reports'],['automation','🤖','Automation'],['system','⚙️','System']];

function renderApp(view=state.view){if(!allowed(view)) view='dashboard';state.view=view;save();closeSidebar();$('themeBtn').textContent=state.dark?'☀️':'🌙';renderShell();const fn={dashboard,calculator,damage,queue,receipt,trips,reports,automation,system,claim,track,settlement,quality}[view]||dashboard;fn();}
function storageKB(){return Math.round((localStorage.getItem(STORE)||'').length/1024)}
function storagePercent(){return Math.min(100, Math.round(storageKB()/50));}
function dataHealth(){
  const missingPairs=state.data.cases.filter(x=>!x.photos?.stub||!x.photos?.damage);
  const unlinked=state.data.cases.filter(x=>!x.claimId);
  const lowScore=state.data.cases.filter(x=>(x.score||0)<70);
  const openClaims=state.data.claims.filter(x=>!['Done','Rejected','Evidence Received'].includes(x.status||''));
  const keys={};state.data.claims.forEach(c=>{const k=(c.psn+'|'+c.last).toLowerCase();keys[k]=(keys[k]||0)+1});
  const dupClaims=Object.values(keys).filter(n=>n>1).reduce((a,n)=>a+n,0);
  const photos=state.data.cases.reduce((a,x)=>a+(x.photos?.stub?1:0)+(x.photos?.damage?1:0),0);
  const kb=storageKB();
  const score=Math.max(0,100-(missingPairs.length*10)-(lowScore.length*6)-(dupClaims*5)-(kb>3500?15:0));
  return {missingPairs,unlinked,lowScore,openClaims,dupClaims,photos,kb,score:Math.min(100,score)};
}
function dashboard(){setTitle(cap(state.role)+' Dashboard','V70 operations workflow');const h=dataHealth(), c=state.data.cases.length, cl=state.data.claims.length, open=state.data.cases.filter(x=>x.status!=='Done'&&x.status!=='Rejected').length, rev=state.data.transactions.reduce((a,x)=>a+(x.grand||0),0);const actions=state.role==='passenger'?[['claim','📝','Start Claim','Report baggage damage or issue'],['track','🔎','Track Claim','Search local claim status'],['trips','🕐','Schedules','Route trips and fares'],['calculator','🧮','Estimate','Baggage fee estimate']]:state.role==='cashier'?[['calculator','🧮','Official Calculator','Compute and save receipt basis'],['damage','📸','Evidence Studio','Match claim + evidence photos'],['queue','👥','Review Queue','Filter and update status'],['settlement','💵','Settlement','Shift cash and summary']]:[['queue','👥','Review Queue','Manage all cases'],['quality','🧪','Quality Control','Find missing data and cleanup needs'],['settlement','💵','Settlement','Shift totals and report'],['automation','🤖','Automation Center','Sealed helpers']];$('content').innerHTML=hero('OceanJet PortDesk '+APP_VERSION,'Scratch-built clean system with sealed automation, quality control, settlement reports, compressed evidence photos, and no recovery/scanner/navigation loops.',cap(state.role)+' workspace')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Passenger Claims</span><b>${cl}</b><span class="tiny">Local reports</span></div><div class="card span3 kpi"><span class="muted">Evidence Cases</span><b>${c}</b><span class="tiny">Stub + damage pairs</span></div><div class="card span3 kpi"><span class="muted">Open Queue</span><b>${open}</b><span class="tiny">Needs review/action</span></div><div class="card span3 kpi"><span class="muted">Local Revenue</span><b>${peso(rev)}</b><span class="tiny">Saved calculator records</span></div><div class="card span12"><div class="cardHead"><div><h3>Workspace Shortcuts</h3><p>Only tools for the selected role are shown. Admin can access everything.</p></div><span class="badge ok">Operations Core</span></div><div class="quick">${actions.map(a=>`<button onclick="renderApp('${a[0]}')"><span class="ico">${a[1]}</span><b>${a[2]}</b><span class="tiny">${a[3]}</span></button>`).join('')}</div></div><div class="card span7"><div class="cardHead"><div><h3>Recommended Flow</h3><p>One clean process with sealed optional automation.</p></div></div><div class="opSteps"><div class="opStep"><b>1. Claim</b><span>Passenger/staff records PSN + Last Name.</span></div><div class="opStep"><b>2. Evidence</b><span>Staff adds claim-stub and damage photos.</span></div><div class="opStep"><b>3. Queue</b><span>Cashier/Admin reviews and updates status.</span></div><div class="opStep"><b>4. Settlement</b><span>Cashier/Admin reviews shift totals and exports backup.</span></div></div></div><div class="card span5"><div class="cardHead"><div><h3>Device Health</h3><p>Local storage and record quality.</p></div><span class="badge ${h.score>=80?'ok':h.score>=60?'warn':'bad'}">${h.score}%</span></div><div class="compactList"><div class="compactRow"><span>Storage</span><b>${h.kb} KB</b></div><div class="compactRow"><span>Incomplete photo pairs</span><b>${h.missingPairs.length}</b></div><div class="compactRow"><span>Low evidence score</span><b>${h.lowScore.length}</b></div></div><div class="v61Meter" style="margin-top:10px"><span style="width:${storagePercent()}%"></span></div>${state.role==='admin'?'<div class="miniActions"><button class="small primary" onclick="renderApp(\'quality\')">Open Quality Control</button><button class="small" onclick="renderApp(\'system\')">System</button></div>':''}</div></div>`;}

async function imgFileToDataURL(file,maxDim=1280,quality=.72){
  if(!file || !file.type || !file.type.startsWith('image/')) throw new Error('Image file required');
  const bmp = ('createImageBitmap' in window) ? await createImageBitmap(file).catch(()=>null) : null;
  if(!bmp){return await new Promise((resolve,reject)=>{const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsDataURL(file)})}
  const scale=Math.min(1,maxDim/Math.max(bmp.width,bmp.height));
  const w=Math.max(1,Math.round(bmp.width*scale)), h=Math.max(1,Math.round(bmp.height*scale));
  const c=document.createElement('canvas');c.width=w;c.height=h;c.getContext('2d').drawImage(bmp,0,0,w,h);bmp.close?.();
  return c.toDataURL('image/jpeg',quality);
}
function capturePhoto(target=state.cameraTarget){const v=$('cameraVideo');if(!state.camera||!v.videoWidth){toast('Start camera first');return}const maxDim=1280;const scale=Math.min(1,maxDim/Math.max(v.videoWidth,v.videoHeight));const canvas=document.createElement('canvas');canvas.width=Math.round(v.videoWidth*scale);canvas.height=Math.round(v.videoHeight*scale);canvas.getContext('2d').drawImage(v,0,0,canvas.width,canvas.height);state.draftPhotos[target]=canvas.toDataURL('image/jpeg',.72);renderDraftPhoto(target);toast('Captured '+target+' (compressed)')}
async function uploadSingle(ev,target){const f=ev.target.files?.[0];if(!f)return;try{state.draftPhotos[target]=await imgFileToDataURL(f);renderDraftPhoto(target);toast('Uploaded '+target+' (compressed)')}catch(e){toast('Upload failed: '+e.message)}finally{ev.target.value=''}}
async function batchEvidence(ev){const files=[...(ev.target.files||[])];if(!files.length)return;if(autoOn('pairGuard')&&files.length%2){autoAudit('Automation: pair guard warning',files.length+' uploaded files','pairGuard');if(!confirm('Pair Guard: odd number of photos. Last pair will be incomplete. Continue?')){ev.target.value='';return}}const psn=$('dPsn').value.trim(), last=$('dLast').value.trim();if(!psn||!last){$('pairPreview').innerHTML='<div class="notice" style="margin-top:12px">Enter PSN and Last Name first. Files were not saved.</div>';ev.target.value='';return}const pairs=[];try{for(let i=0;i<files.length;i+=2){const stub=files[i]?await imgFileToDataURL(files[i]):null;const damage=files[i+1]?await imgFileToDataURL(files[i+1]):null;pairs.push({stub,damage})}}catch(e){toast('Batch upload failed: '+e.message);ev.target.value='';return}pairs.forEach((p,idx)=>saveEvidenceObject(p,idx+1,true));ev.target.value='';renderCaseList();$('pairPreview').innerHTML=`<div class="notice" style="margin-top:12px">Saved ${pairs.length} compressed batch pair(s). Order used: 1-2, 3-4, 5-6.</div>`;toast('Batch evidence saved')}

function caseCard(x){return `<div class="caseCard"><div style="display:flex;justify-content:space-between;gap:10px"><div><b>${esc(x.psn)} • ${esc(x.last)}</b><div class="tiny">${esc(x.time)} • ${esc(x.routeLabel)} • ${esc(x.type)}</div></div><div class="scoreRing" style="--score:${x.score||0}"><span>${x.score||0}%</span></div></div><div class="chips"><span class="chip">${statusText(x.status)}</span>${x.claimId?`<span class="chip">Claim linked</span>`:''}${x.suggestion?`<span class="chip">Suggest: ${esc(x.suggestion)}</span>`:''}${x.color?`<span class="chip">Color: ${esc(x.color)}</span>`:''}${x.size?`<span class="chip">Size: ${esc(x.size)}</span>`:''}${x.batchNo?`<span class="chip">Batch Pair ${x.batchNo}</span>`:''}</div>${x.notes?`<div class="tiny">${esc(x.notes)}</div>`:''}<div class="casePhotos">${x.photos?.stub?`<img src="${x.photos.stub}" alt="stub">`:'<div class="empty">No stub</div>'}${x.photos?.damage?`<img src="${x.photos.damage}" alt="damage">`:'<div class="empty">No damage</div>'}</div><div class="miniActions"><button class="small" onclick="openCase('${x.id}')">Open Summary</button></div></div>`}

function settlement(){setTitle('Shift Settlement','Cashier/admin shift totals');const tx=state.data.transactions, rec=state.data.receipts;const rev=tx.reduce((a,x)=>a+(x.grand||0),0), receiptTotal=rec.reduce((a,x)=>a+(Number(x.amount)||0),0);const routeTotals={};tx.forEach(x=>{routeTotals[x.routeLabel]=(routeTotals[x.routeLabel]||0)+(x.grand||0)});$('content').innerHTML=hero('Shift Settlement','Review calculator totals, receipt totals, route totals, and export/copy a shift report. No background automation.','Counter')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Transactions</span><b>${tx.length}</b></div><div class="card span3 kpi"><span class="muted">Calculator Total</span><b>${peso(rev)}</b></div><div class="card span3 kpi"><span class="muted">Receipts Total</span><b>${peso(receiptTotal)}</b></div><div class="card span3 kpi"><span class="muted">Difference</span><b>${peso(rev-receiptTotal)}</b></div><div class="card span6"><h3>Shift Info</h3><div class="compactList"><div class="compactRow"><span>Status</span><b>${state.data.shift.open?'Open':'Closed'}</b></div><div class="compactRow"><span>Port</span><b>${esc(state.data.shift.port||'Cebu')}</b></div><div class="compactRow"><span>Staff</span><b>${esc(state.data.shift.staff||'-')}</b></div><div class="compactRow"><span>Started</span><b>${esc(state.data.shift.startedAt||'-')}</b></div></div><div class="miniActions"><button class="primary small" onclick="copyShiftReport()">Copy Shift Report</button><button class="small" onclick="exportShiftCSV()">Export Shift CSV</button></div></div><div class="card span6"><h3>Route Totals</h3>${Object.keys(routeTotals).length?`<div class="tableWrap"><table><thead><tr><th>Route</th><th>Total</th></tr></thead><tbody>${Object.entries(routeTotals).map(([k,v])=>`<tr><td>${esc(k)}</td><td>${peso(v)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No transactions yet.</div>'}</div><div class="card span12"><h3>Latest Transactions</h3>${tx.length?`<div class="tableWrap"><table><thead><tr><th>Time</th><th>PSN</th><th>Route</th><th>KG</th><th>Total</th></tr></thead><tbody>${tx.slice(0,30).map(x=>`<tr><td>${esc(x.time)}</td><td>${esc(x.psn||'-')}</td><td>${esc(x.routeLabel)}</td><td>${Number(x.kg||0).toFixed(1)}</td><td>${peso(x.grand)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No transactions yet.</div>'}</div></div>`}
function shiftReportText(){const tx=state.data.transactions, rec=state.data.receipts;const rev=tx.reduce((a,x)=>a+(x.grand||0),0), receiptTotal=rec.reduce((a,x)=>a+(Number(x.amount)||0),0);return `OceanJet PortDesk V78 Shift Report\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nStarted: ${state.data.shift.startedAt||'-'}\nGenerated: ${today()}\nTransactions: ${tx.length}\nCalculator Total: ${peso(rev)}\nReceipts Total: ${peso(receiptTotal)}\nDifference: ${peso(rev-receiptTotal)}\nOpen Evidence Cases: ${state.data.cases.filter(x=>x.status!=='Done'&&x.status!=='Rejected').length}`}
function copyShiftReport(){navigator.clipboard?.writeText(shiftReportText());audit('Shift report copied','V62 settlement');save();toast('Shift report copied')}
function exportShiftCSV(){const rows=state.data.transactions.map(x=>({time:x.time,psn:x.psn||'',route:x.routeLabel,cls:x.cls,pax:x.pax,kg:x.kg,baggage:x.baggage,grand:x.grand}));download('OceanJet_Shift_Settlement_V62.csv',csv(rows,['time','psn','route','cls','pax','kg','baggage','grand']),'text/csv');audit('Shift CSV export','transactions '+rows.length);save();toast('Shift CSV exported')}

function quality(){setTitle('Quality Control','Data health and safe cleanup');const h=dataHealth();$('content').innerHTML=hero('Quality Control','Find missing photo pairs, unlinked evidence, low scores, duplicate claims, and storage risk. Repairs are manual buttons only.','Admin')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Health Score</span><b>${h.score}%</b></div><div class="card span3 kpi"><span class="muted">Storage</span><b>${h.kb} KB</b></div><div class="card span3 kpi"><span class="muted">Photos</span><b>${h.photos}</b></div><div class="card span3 kpi"><span class="muted">Open Claims</span><b>${h.openClaims.length}</b></div><div class="card span6"><h3>Safe Repair Tools</h3><div class="qcList" style="margin-top:12px"><div class="qcItem"><span>Recalculate evidence scores</span><button class="small primary" onclick="rescoreEvidence()">Run</button></div><div class="qcItem"><span>Relink evidence to matching claims by PSN + Last Name</span><button class="small primary" onclick="relinkClaims()">Run</button></div><div class="qcItem"><span>Export backup before cleanup</span><button class="small" onclick="downloadJSON()">Backup</button></div></div><div class="notice" style="margin-top:12px">V62 does not auto-delete. Cleanup requires confirmation in each tool.</div></div><div class="card span6"><h3>Health Details</h3><div class="v61Meter" style="margin:10px 0"><span style="width:${h.score}%"></span></div><div class="compactList"><div class="compactRow"><span>Incomplete photo pairs</span><b>${h.missingPairs.length}</b></div><div class="compactRow"><span>Unlinked evidence</span><b>${h.unlinked.length}</b></div><div class="compactRow"><span>Low score evidence</span><b>${h.lowScore.length}</b></div><div class="compactRow"><span>Duplicate claim entries</span><b>${h.dupClaims}</b></div></div></div><div class="card span12"><div class="cardHead"><div><h3>Cases Needing Attention</h3><p>Open from here, then update in Review Queue.</p></div><button class="small" onclick="renderApp('queue')">Open Queue</button></div>${qualityTable()}</div></div>`;}
function qualityTable(){const bad=state.data.cases.filter(x=>!x.photos?.stub||!x.photos?.damage||(x.score||0)<70||!x.claimId).slice(0,40);return bad.length?`<div class="tableWrap"><table><thead><tr><th>PSN</th><th>Name</th><th>Issue</th><th>Missing</th><th>Score</th><th></th></tr></thead><tbody>${bad.map(x=>{const miss=[];if(!x.photos?.stub)miss.push('Stub');if(!x.photos?.damage)miss.push('Damage');if(!x.claimId)miss.push('Claim Link');return `<tr><td>${esc(x.psn)}</td><td>${esc(x.last)}</td><td>${esc(x.type)}</td><td>${esc(miss.join(', ')||'Low score')}</td><td>${x.score||0}%</td><td><button class="small" onclick="openCase('${x.id}')">Open</button></td></tr>`}).join('')}</tbody></table></div>`:'<div class="empty">No quality issues found.</div>'}
function rescoreEvidence(){state.data.cases.forEach(x=>{x.score=evidenceScore(x);if(autoOn('statusSuggest'))x.suggestion=suggestEvidenceStatus(x)});audit('Quality repair','Evidence scores recalculated');save();toast('Scores recalculated');quality()}
function relinkClaims(){let linked=0;state.data.cases.forEach(x=>{if(x.claimId)return;const c=state.data.claims.find(c=>(c.psn||'').toLowerCase()===(x.psn||'').toLowerCase()&&(c.last||'').toLowerCase()===(x.last||'').toLowerCase());if(c){x.claimId=c.id;c.status='Evidence Received';c.evidenceId=x.id;linked++}});audit('Quality repair','Relinked '+linked+' evidence case(s)');save();toast('Relinked '+linked+' case(s)');quality()}

function reports(){setTitle('Reports & Backup','Export local records');const h=dataHealth();$('content').innerHTML=hero('Reports & Backup','Export JSON/CSV, import backup, review health, and keep local records safe.','Admin')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Claims</span><b>${state.data.claims.length}</b></div><div class="card span3 kpi"><span class="muted">Evidence</span><b>${state.data.cases.length}</b></div><div class="card span3 kpi"><span class="muted">Transactions</span><b>${state.data.transactions.length}</b></div><div class="card span3 kpi"><span class="muted">Health</span><b>${h.score}%</b></div><div class="card span6"><h3>Export</h3><div style="display:grid;gap:8px;margin-top:10px"><button class="primary" onclick="downloadJSON()">Download Full JSON Backup</button><button onclick="downloadCSV('claims')">Download Claims CSV</button><button onclick="downloadCSV('cases')">Download Evidence CSV</button><button onclick="downloadCSV('transactions')">Download Transactions CSV</button><button onclick="downloadCSV('receipts')">Download Receipts CSV</button><button onclick="exportShiftCSV()">Download Shift CSV</button></div></div><div class="card span6"><h3>Import & Health</h3><p class="muted">Use a V62, V61, V60, V59, or V58 JSON backup. Import keeps the clean V62 code and replaces local records.</p><label><input type="file" accept="application/json" onchange="importJSON(event)"></label><div class="notice" style="margin-top:12px">Storage: ${h.kb} KB • Photos: ${h.photos}. Evidence uploads are compressed in V62.</div><div class="miniActions"><button class="small primary" onclick="renderApp('quality')">Open Quality Control</button><button class="small" onclick="renderApp('settlement')">Open Settlement</button></div></div><div class="card span12"><div class="cardHead"><div><h3>Latest Audit Log</h3><p>Local device actions, latest first.</p></div></div>${renderAudit()}</div></div>`}

function system(){setTitle('System Tools','Cache, shift, and settings');const h=dataHealth();$('content').innerHTML=hero('System Tools','Use this after uploading to GitHub Pages if old versions still show. V62 includes diagnostics and safe reload tools.','Admin')+`<div class="grid"><div class="card span6"><h3>Cache Tools</h3><p>Removes old caches/service workers where browser allows.</p><div style="display:grid;gap:8px;margin-top:12px"><button class="danger" onclick="clearOldCache()">Clear Old App Cache</button><button onclick="location.reload()">Reload App</button><button onclick="runDiagnostics()">Run Diagnostics</button><button class="warn" onclick="hardResetData()">Reset V62 Local Data</button></div><div id="diagOut" class="notice" style="margin-top:12px">Ready. Storage ${h.kb} KB.</div></div><div class="card span6"><h3>Shift Setup</h3><div class="formGrid"><label>Port<input id="shiftPort" value="${esc(state.data.shift.port||'Cebu')}"></label><label>Staff Name<input id="shiftStaff" value="${esc(state.data.shift.staff||'')}"></label></div><div class="miniActions"><button class="primary" onclick="startShift()">Start / Update Shift</button><button onclick="closeShift()">Close Shift</button><button onclick="renderApp('settlement')">Settlement</button></div><div class="notice ${state.data.shift.open?'alertGood':'alertWarn'}" style="margin-top:12px">Shift is ${state.data.shift.open?'open since '+esc(state.data.shift.startedAt):'closed'}.</div></div><div class="card span6"><h3>Staff Credentials</h3><div class="formGrid"><label>Cashier User<input id="setCashierU" value="${esc(state.data.settings.cashier.u)}"></label><label>Cashier Pass<input id="setCashierP" value="${esc(state.data.settings.cashier.p)}"></label><label>Admin User<input id="setAdminU" value="${esc(state.data.settings.admin.u)}"></label><label>Admin Pass<input id="setAdminP" value="${esc(state.data.settings.admin.p)}"></label></div><button class="primary block" style="margin-top:12px" onclick="saveCreds()">Save Credentials</button></div><div class="card span6 dangerZone"><h3>Design Decision</h3><p>This is a scratch app. It does not load legacy V6–V57 scripts, scanner patches, recovery watchers, repeated intervals, observers, or auto-capture. Optional automation is sealed in the Admin Automation Center.</p><div class="miniActions"><button class="small primary" onclick="renderApp('automation')">Automation</button><button class="small" onclick="renderApp('quality')">Quality</button></div></div></div>`}
function runDiagnostics(){const needed=['imgFileToDataURL','uploadSingle','batchEvidence','clearOldCache','settlement','quality','renderClaimMatch'];const missing=needed.filter(k=>typeof window[k]!=='function');const d={version:APP_VERSION,role:state.role,views:NAVS[state.role].map(x=>x[0]).join(', '),cases:state.data.cases.length,claims:state.data.claims.length,transactions:state.data.transactions.length,localStorageKB:storageKB(),health:dataHealth().score,automation:automationStatusText(),forbiddenIntervals:/set\s*Interval\s*\(/i.test(document.documentElement.innerHTML)?'FOUND':'none',forbiddenObservers:document.documentElement.innerHTML.includes('Mutation'+'Observer')?'FOUND':'none',missingFunctions:missing.length?missing:'none',shift:state.data.shift.open?'open':'closed',audit:state.data.audit.length};$('diagOut').innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>'}
function hardResetData(){if(confirm('Reset all V62 local records on this device? Export backup first if needed.')){localStorage.removeItem(STORE);location.reload()}}
function openQuickHelp(){modal(`<div class="modalHead"><h3>V61 Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>Built from scratch base, not old broken recovery layers.</li><li>Fixed missing image upload function and added compressed image storage.</li><li>Camera is manual only. Start Camera must be pressed.</li><li>Batch evidence order is 1-2, 3-4, 5-6.</li><li>Added Settlement page for shift totals and CSV report.</li><li>Added Quality Control page for missing pairs, unlinked evidence, low score cases, and storage health.</li><li>Sealed Automation remains admin-controlled with no intervals, no observers, no recovery, and no scanner loop.</li><li>Use Admin → System → Clear Old App Cache after upload.</li></ul>`)}

/* =========================
   V62 OPS CONTROL LAYER
   Added from V61 scratch/sealed base. No recovery, scanner, navigation repair,
   setInterval, or observer loops. All additions are user-triggered only.
========================= */
NAVS.cashier = [['dashboard','🏠','Home'],['lookup','🔎','Search'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['trips','🕐','Trips']];
NAVS.admin = [['dashboard','🏠','Command'],['lookup','🔎','Search'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['quality','🧪','Quality'],['handover','📋','Handover'],['reports','📊','Reports'],['automation','🤖','Automation'],['system','⚙️','System']];
const V62_HANDOVER_ITEMS = {
  backup:'JSON backup exported',
  settlement:'Shift settlement reviewed',
  pending:'Open claims/evidence queue checked',
  quality:'Quality Control checked',
  cache:'Old app cache cleared after update if needed'
};
function ensureData(){state.data.cases ||= [];state.data.claims ||= [];state.data.transactions ||= [];state.data.receipts ||= [];state.data.audit ||= [];state.data.drafts ||= {claim:null,evidence:null};state.data.automation = {...AUTO_DEFAULTS,...(state.data.automation||{})};state.data.settings ||= {cashier:{u:'cashier',p:'cashier'},admin:{u:'demo',p:'demo'}};state.data.settings.cashier ||= {u:'cashier',p:'cashier'};state.data.settings.admin ||= {u:'demo',p:'demo'};state.data.shift ||= {open:false,staff:'',port:'Cebu',startedAt:''};state.data.handover ||= {checks:{},note:'',updatedAt:''};state.data.handover.checks ||= {};}
function renderApp(view=state.view){if(!allowed(view)) view='dashboard';state.view=view;save();closeSidebar();$('themeBtn').textContent=state.dark?'☀️':'🌙';renderShell();const fn={dashboard,lookup,calculator,damage,queue,receipt,trips,reports,automation,system,claim,track,settlement,quality,handover}[view]||dashboard;fn();}
function dashboard(){setTitle(cap(state.role)+' Dashboard','V70 operations workflow');const h=dataHealth(), c=state.data.cases.length, cl=state.data.claims.length, open=state.data.cases.filter(x=>x.status!=='Done'&&x.status!=='Rejected').length, rev=state.data.transactions.reduce((a,x)=>a+(x.grand||0),0), pending=h.missingPairs.length+h.unlinked.length+h.lowScore.length;const actions=state.role==='passenger'?[['claim','📝','Start Claim','Report baggage damage or issue'],['track','🔎','Track Claim','Search local claim status'],['trips','🕐','Schedules','Route trips and fares'],['calculator','🧮','Estimate','Baggage fee estimate']]:state.role==='cashier'?[['lookup','🔎','Unified Search','Find PSN across claims/evidence/receipts'],['calculator','🧮','Official Calculator','Compute and save receipt basis'],['damage','📸','Evidence Studio','Match claim + evidence photos'],['settlement','💵','Settlement','Shift cash and summary']]:[['lookup','🔎','Unified Search','Find all local records fast'],['quality','🧪','Quality Control','Find missing data and cleanup needs'],['handover','📋','Handover','End-of-shift checklist'],['automation','🤖','Automation Center','Sealed helpers']];$('content').innerHTML=hero('OceanJet PortDesk '+APP_VERSION,'V62 keeps the scratch clean core and adds unified search, handover checklist, compact backup, and clearer daily controls. No recovery, scanner, drawer, interval, or observer loops.',cap(state.role)+' workspace')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Passenger Claims</span><b>${cl}</b><span class="tiny">Local reports</span></div><div class="card span3 kpi"><span class="muted">Evidence Cases</span><b>${c}</b><span class="tiny">Stub + damage pairs</span></div><div class="card span3 kpi"><span class="muted">Open Queue</span><b>${open}</b><span class="tiny">Needs review/action</span></div><div class="card span3 kpi"><span class="muted">Local Revenue</span><b>${peso(rev)}</b><span class="tiny">Saved calculator records</span></div><div class="card span12"><div class="cardHead"><div><h3>Workspace Shortcuts</h3><p>Only tools for the selected role are shown. Admin can access everything.</p></div><span class="badge ok">Operations Core</span></div><div class="quick">${actions.map(a=>`<button onclick="renderApp('${a[0]}')"><span class="ico">${a[1]}</span><b>${a[2]}</b><span class="tiny">${a[3]}</span></button>`).join('')}</div></div><div class="card span7"><div class="cardHead"><div><h3>Daily Operating Flow</h3><p>Designed for port use, not demo scanning.</p></div></div><div class="opSteps"><div class="opStep"><b>1. Search first</b><span>Check PSN/last name before creating duplicate records.</span></div><div class="opStep"><b>2. Capture evidence</b><span>Manual stub + damage pair only.</span></div><div class="opStep"><b>3. Review queue</b><span>Update case status with cashier/admin decision.</span></div><div class="opStep"><b>4. Handover</b><span>Export backup, check quality, copy handover note.</span></div></div></div><div class="card span5"><div class="cardHead"><div><h3>Control Status</h3><p>Local health and pending issues.</p></div><span class="badge ${h.score>=80?'ok':h.score>=60?'warn':'bad'}">${h.score}%</span></div><div class="compactList"><div class="compactRow"><span>Storage</span><b>${h.kb} KB</b></div><div class="compactRow"><span>Photos</span><b>${h.photos}</b></div><div class="compactRow"><span>Quality issues</span><b>${pending}</b></div><div class="compactRow"><span>Handover</span><b>${handoverPercent()}%</b></div></div><div class="v61Meter" style="margin-top:10px"><span style="width:${Math.max(h.score,handoverPercent())}%"></span></div>${state.role==='admin'?'<div class="miniActions"><button class="small primary" onclick="renderApp(\'handover\')">Open Handover</button><button class="small" onclick="renderApp(\'quality\')">Quality</button></div>':''}</div></div>`;}
function recordText(x){return Object.values(x||{}).filter(v=>typeof v==='string'||typeof v==='number').join(' ').toLowerCase()}
function unifiedRecords(){const rows=[];state.data.claims.forEach(x=>rows.push({kind:'Claim',time:x.time,psn:x.psn,last:x.last,route:x.routeLabel,status:x.status||'Open',detail:x.type||x.item||'',id:x.id,raw:x}));state.data.cases.forEach(x=>rows.push({kind:'Evidence',time:x.time,psn:x.psn,last:x.last,route:x.routeLabel,status:x.status||'Review',detail:(x.type||'')+' • Score '+(x.score||0)+'%',id:x.id,raw:x}));state.data.transactions.forEach(x=>rows.push({kind:'Transaction',time:x.time,psn:x.psn||'',last:'',route:x.routeLabel,status:peso(x.grand||0),detail:(x.cls||'')+' • '+(x.kg||0)+'kg',id:x.id,raw:x}));state.data.receipts.forEach(x=>rows.push({kind:'Receipt',time:x.time,psn:x.psn||'',last:x.name||'',route:x.routeLabel||'',status:peso(x.amount||0),detail:x.notes||'',id:x.id,raw:x}));return rows;}
function lookup(){setTitle('Unified Search','Find PSN, last name, route, amount, status, or record ID');$('content').innerHTML=hero('Unified Search','Search all local claims, evidence, transactions, and receipts in one screen. Nothing runs automatically; search happens only when you type or press Search.','V62')+`<div class="grid"><div class="card span12"><div class="searchBox"><label>Search keyword / PSN / Last Name / Route<input id="lookupQ" placeholder="Example: 123456, Dela Cruz, Maasin, Ready" oninput="runLookup()"></label><button class="primary" onclick="runLookup()">Search</button></div><div class="miniActions"><button class="small" onclick="lookupPreset('Ready')">Ready</button><button class="small" onclick="lookupPreset('Needs Review')">Needs Review</button><button class="small" onclick="lookupPreset('Maasin')">Maasin</button><button class="small" onclick="lookupPreset('')">Show All</button></div></div><div class="card span12"><div id="lookupOut">${renderLookupRows(unifiedRecords().slice(0,25))}</div></div></div>`}
function lookupPreset(q){$('lookupQ').value=q;runLookup()}
function runLookup(){const q=($('lookupQ')?.value||'').trim().toLowerCase();let rows=unifiedRecords();if(q){rows=rows.filter(x=>(recordText(x)+' '+recordText(x.raw)).includes(q));}rows=rows.slice(0,60);$('lookupOut').innerHTML=renderLookupRows(rows);}
function renderLookupRows(rows){return rows.length?`<div class="tableWrap"><table><thead><tr><th>Type</th><th>Time</th><th>PSN</th><th>Name</th><th>Route</th><th>Status/Amount</th><th>Details</th><th>Action</th></tr></thead><tbody>${rows.map(x=>`<tr><td><span class="statusPill">${esc(x.kind)}</span></td><td>${esc(x.time||'-')}</td><td>${esc(x.psn||'-')}</td><td>${esc(x.last||'-')}</td><td>${esc(x.route||'-')}</td><td>${esc(x.status||'-')}</td><td>${esc(x.detail||'-')}</td><td>${lookupAction(x)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No matching local records.</div>'}
function lookupAction(x){if(x.kind==='Evidence')return `<button class="small" onclick="openCase('${x.id}')">Open</button>`;if(x.kind==='Claim')return `<button class="small" onclick="renderApp('queue')">Queue</button>`;if(x.kind==='Transaction')return `<button class="small" onclick="renderApp('receipt')">Receipt</button>`;return `<button class="small" onclick="renderApp('reports')">Reports</button>`}
function handoverPercent(){ensureData();const vals=Object.keys(V62_HANDOVER_ITEMS);const done=vals.filter(k=>state.data.handover.checks[k]).length;return Math.round((done/vals.length)*100)}
function toggleHandover(key){ensureData();state.data.handover.checks[key]=!state.data.handover.checks[key];state.data.handover.updatedAt=today();audit('Handover check',key+' = '+state.data.handover.checks[key]);save();handover()}
function saveHandoverNote(){ensureData();state.data.handover.note=$('handoverNote')?.value||'';state.data.handover.updatedAt=today();audit('Handover note saved','Updated local handover note');save();toast('Handover note saved')}
function handover(){setTitle('Shift Handover','End-of-shift checklist and copyable report');ensureData();const h=dataHealth(), p=handoverPercent();$('content').innerHTML=hero('Shift Handover','A controlled end-of-shift page for Admin. Checklist is manual only and logged.','V62')+`<div class="grid"><div class="card span4 stickyMini"><div class="cardHead"><div><h3>Completion</h3><p>Manual checklist progress.</p></div><span class="badge ${p===100?'ok':'warn'}">${p}%</span></div><div class="v61Meter"><span style="width:${p}%"></span></div><div class="compactList" style="margin-top:12px"><div class="compactRow"><span>Health</span><b>${h.score}%</b></div><div class="compactRow"><span>Open queue</span><b>${h.openClaims.length}</b></div><div class="compactRow"><span>Updated</span><b>${esc(state.data.handover.updatedAt||'-')}</b></div></div><div class="miniActions"><button class="primary small" onclick="copyHandoverReport()">Copy Report</button><button class="small" onclick="downloadCompactJSON()">Compact Backup</button></div></div><div class="card span8"><h3>Checklist</h3><div class="handoverGrid" style="margin-top:12px">${Object.entries(V62_HANDOVER_ITEMS).map(([k,label])=>`<div class="handoverItem ${state.data.handover.checks[k]?'done':''}"><span>${state.data.handover.checks[k]?'✅':'⬜'} ${esc(label)}</span><button class="small ${state.data.handover.checks[k]?'warn':'primary'}" onclick="toggleHandover('${k}')">${state.data.handover.checks[k]?'Undo':'Done'}</button></div>`).join('')}</div><label style="margin-top:12px">Handover Note<textarea id="handoverNote" placeholder="Example: 2 claims need admin review; one missing damage image.">${esc(state.data.handover.note||'')}</textarea></label><button class="primary" style="margin-top:10px" onclick="saveHandoverNote()">Save Note</button></div><div class="card span12"><h3>Handover Timeline</h3>${handoverTimeline()}</div></div>`;}
function handoverTimeline(){const rows=state.data.audit.filter(a=>/handover|backup|shift|quality|cache|settlement/i.test((a.action||'')+' '+(a.detail||''))).slice(0,25);return rows.length?`<div class="timeline">${rows.map(x=>`<div class="timelineItem"><b>${esc(x.action)}</b><div class="tiny">${esc(x.time)} • ${esc(x.role)}</div><div>${esc(x.detail)}</div></div>`).join('')}</div>`:'<div class="empty">No handover-related audit actions yet.</div>'}
function copyHandoverReport(){const h=dataHealth();const checks=Object.entries(V62_HANDOVER_ITEMS).map(([k,label])=>(state.data.handover.checks[k]?'[x] ':'[ ] ')+label).join('\n');const txt=`OceanJet PortDesk V78 Handover\nDate: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nHealth: ${h.score}%\nOpen Queue: ${h.openClaims.length}\nStorage: ${h.kb} KB\n\nChecklist:\n${checks}\n\nNote:\n${state.data.handover.note||'-'}`;navigator.clipboard?.writeText(txt);audit('Handover report copied','Checklist '+handoverPercent()+'%');save();toast('Handover report copied')}
function compactData(){const clone=JSON.parse(JSON.stringify(state.data));clone.cases=(clone.cases||[]).map(c=>({...c,photos:{stub:!!c.photos?.stub,damage:!!c.photos?.damage},photoNote:'Photos removed in compact backup; use full JSON for evidence images.'}));return clone;}
function downloadCompactJSON(){audit('Compact backup export','JSON without image data');save();download('OceanJet_PortDesk_V62_Compact_Backup_'+Date.now()+'.json',JSON.stringify({version:APP_VERSION,exportedAt:new Date().toISOString(),compact:true,data:compactData()},null,2),'application/json');toast('Compact backup downloaded')}
function reports(){setTitle('Reports & Backup','Export local records');const h=dataHealth();$('content').innerHTML=hero('Reports & Backup','Export full/compact JSON, CSV files, import backup, and review audit log. Compact backup excludes image data for smaller daily reports.','Admin')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Claims</span><b>${state.data.claims.length}</b></div><div class="card span3 kpi"><span class="muted">Evidence</span><b>${state.data.cases.length}</b></div><div class="card span3 kpi"><span class="muted">Transactions</span><b>${state.data.transactions.length}</b></div><div class="card span3 kpi"><span class="muted">Health</span><b>${h.score}%</b></div><div class="card span6"><h3>Export</h3><div style="display:grid;gap:8px;margin-top:10px"><button class="primary" onclick="downloadJSON()">Download Full JSON Backup With Photos</button><button onclick="downloadCompactJSON()">Download Compact JSON Backup No Photos</button><button onclick="downloadCSV('claims')">Download Claims CSV</button><button onclick="downloadCSV('cases')">Download Evidence CSV</button><button onclick="downloadCSV('transactions')">Download Transactions CSV</button><button onclick="downloadCSV('receipts')">Download Receipts CSV</button><button onclick="exportShiftCSV()">Download Shift CSV</button></div></div><div class="card span6"><h3>Import & Health</h3><p class="muted">Use a V62, V61, V60, V59, or V58 JSON backup. Import keeps the clean V62 code and replaces local records.</p><label><input type="file" accept="application/json" onchange="importJSON(event)"></label><div class="notice" style="margin-top:12px">Storage: ${h.kb} KB • Photos: ${h.photos}. Full backup keeps photos. Compact backup is smaller but not for image evidence archive.</div><div class="miniActions"><button class="small primary" onclick="renderApp('quality')">Open Quality Control</button><button class="small" onclick="renderApp('handover')">Open Handover</button><button class="small" onclick="renderApp('settlement')">Open Settlement</button></div></div><div class="card span12"><div class="cardHead"><div><h3>Latest Audit Log</h3><p>Local device actions, latest first.</p></div></div>${renderAudit()}</div></div>`}
function runDiagnostics(){const needed=['imgFileToDataURL','uploadSingle','batchEvidence','clearOldCache','settlement','quality','lookup','handover','downloadCompactJSON','renderClaimMatch'];const missing=needed.filter(k=>typeof window[k]!=='function');const d={version:APP_VERSION,role:state.role,views:NAVS[state.role].map(x=>x[0]).join(', '),cases:state.data.cases.length,claims:state.data.claims.length,transactions:state.data.transactions.length,localStorageKB:storageKB(),health:dataHealth().score,handover:handoverPercent()+'%',automation:automationStatusText(),forbiddenIntervals:/set\s*Interval\s*\(/i.test(document.documentElement.innerHTML)?'FOUND':'none',forbiddenObservers:document.documentElement.innerHTML.includes('Mutation'+'Observer')?'FOUND':'none',missingFunctions:missing.length?missing:'none',shift:state.data.shift.open?'open':'closed',audit:state.data.audit.length};$('diagOut').innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>'}
function openQuickHelp(){modal(`<div class="modalHead"><h3>V67 Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>Continued from V61 scratch/sealed base.</li><li>Added Unified Search for PSN, last name, route, status, receipt, and transaction lookup.</li><li>Added Admin Handover checklist with copyable report.</li><li>Added compact JSON backup without image data for daily reporting.</li><li>Full JSON backup still preserves photo evidence.</li><li>Sealed Automation remains admin-controlled with no intervals, no observers, no recovery, and no scanner loop.</li><li>Use Admin → System → Clear Old App Cache after upload.</li></ul>`)}


