NAVS.cashier = [['dashboard','🏠','Home'],['intake','🧭','Intake'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['board','📋','Board'],['trips','🕐','Trips']];
NAVS.admin = [['dashboard','🏠','Command'],['intake','🧭','Intake'],['board','📋','Ops Board'],['calculator','🧮','Calculator'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💵','Settlement'],['quality','🧪','Quality'],['reports','📊','Reports'],['handover','🤝','Handover'],['automation','🤖','Automation'],['system','⚙️','System']];
function renderApp(view=state.view){if(!allowed(view)) view='dashboard';state.view=view;save();closeSidebar();$('themeBtn').textContent=state.dark?'☀️':'🌙';renderShell();const fn={dashboard,intake,board,calculator,damage,queue,receipt,trips,reports,automation,system,claim,track,settlement,quality,lookup,handover}[view]||dashboard;fn();}
function v63AllOpenRecords(){return [...state.data.claims.map(x=>({...x,kind:'Claim'})),...state.data.cases.map(x=>({...x,kind:'Evidence'}))].filter(x=>!['Done','Rejected'].includes(x.status||''));}
function casePriority(x){let points=0;const t=((x.type||'')+' '+(x.item||'')+' '+(x.desc||'')+' '+(x.notes||'')).toLowerCase();if(/lost|missing|wet|broken|crack|wheel|handle|accessor/.test(t)) points+=2;if(!x.photos?.stub||!x.photos?.damage) points+=2;if((x.score||100)<70) points+=1;if((x.status||'')==='Review') points+=1;if(/surigao|maasin/.test((x.routeLabel||x.route||'').toLowerCase())) points+=1;return points>=4?'High':points>=2?'Medium':'Normal';}
function priorityBadge(x){const p=casePriority(x);return `<span class="v63Priority ${p.toLowerCase()}">${p}</span>`;}
function copyText(txt,label='Copied'){if(navigator.clipboard){navigator.clipboard.writeText(txt).then(()=>toast(label)).catch(()=>toast('Copy unavailable'))}else{const ta=document.createElement('textarea');ta.value=txt;document.body.appendChild(ta);ta.select();document.execCommand('copy');ta.remove();toast(label)}}
function caseSummaryText(x){const claim=state.data.claims.find(c=>c.id===x.claimId);return `OceanJet Case Summary\nVersion: ${APP_VERSION}\nTime: ${x.time||'-'}\nPSN: ${x.psn||'-'}\nLast Name: ${x.last||'-'}\nRoute: ${x.routeLabel||ROUTES[x.route]?.label||'-'}\nIssue: ${x.type||'-'}\nPriority: ${casePriority(x)}\nStatus: ${x.status||'-'}\nEvidence Score: ${x.score||0}%\nStub Photo: ${x.photos?.stub?'YES':'NO'}\nDamage Photo: ${x.photos?.damage?'YES':'NO'}\nContact: ${claim?.contact||'-'}\nItem: ${claim?.item||x.size||'-'}\nNotes: ${x.notes||claim?.desc||'-'}`;}
function copyCaseSummary(id){const x=state.data.cases.find(a=>a.id===id);if(!x)return;copyText(caseSummaryText(x),'Case summary copied');audit('Case summary copied',x.psn+' '+x.last);save();}
function copyPassengerUpdate(id){const x=state.data.cases.find(a=>a.id===id);if(!x)return;const msg=`OceanJet update for PSN ${x.psn}: your baggage concern for ${x.routeLabel||ROUTES[x.route]?.label||'the trip'} is currently ${x.status||'under review'}. Evidence status: claim stub ${x.photos?.stub?'received':'missing'}, damage photo ${x.photos?.damage?'received':'missing'}. Please keep your claim stub and contact the counter for follow-up.`;copyText(msg,'Passenger update copied');audit('Passenger update copied',x.psn+' '+x.last);save();}
function claimAckText(x){return `OceanJet Claim Acknowledgment\nClaim ID: ${x.id}\nDate: ${x.time}\nPSN: ${x.psn}\nLast Name: ${x.last}\nRoute: ${x.routeLabel}\nIssue: ${x.type}\nStatus: ${x.status}\nReminder: Please keep your claim stub and wait for staff review/evidence capture.`;}
function showClaimDuplicates(){const psn=($('claimPsn')?.value||'').trim().toLowerCase(), last=($('claimLast')?.value||'').trim().toLowerCase();const box=$('claimDupBox');if(!box)return;if(!psn&&!last){box.innerHTML='Enter PSN and Last Name to check possible duplicate records.';return}const rows=[...state.data.claims.map(x=>({...x,kind:'Claim'})),...state.data.cases.map(x=>({...x,kind:'Evidence'}))].filter(x=>(!psn||String(x.psn||'').toLowerCase().includes(psn))&&(!last||String(x.last||'').toLowerCase().includes(last))).slice(0,5);box.innerHTML=rows.length?`<b>Possible existing record found:</b><div style="margin-top:8px" class="compactList">${rows.map(x=>`<div class="compactRow"><span>${esc(x.kind)} • ${esc(x.psn)} ${esc(x.last)}</span><b>${esc(x.status||'-')}</b></div>`).join('')}</div>`:'No duplicate found on this device.';}
function claim(){setTitle('Passenger Claim','Start report with duplicate guard');$('content').innerHTML=hero('Passenger Claim Form','V67 adds duplicate checking before submit, then creates a copyable acknowledgment slip.','Passenger')+`<div class="grid"><div class="card span7"><div class="formGrid"><label>PSN <span class="fieldHelp">Required</span><input id="claimPsn" placeholder="Passenger PSN" oninput="showClaimDuplicates();scheduleClaimDraft()"></label><label>Last Name <span class="fieldHelp">Required</span><input id="claimLast" placeholder="Last name" oninput="showClaimDuplicates();scheduleClaimDraft()"></label><label>Route<select id="claimRoute" onchange="scheduleClaimDraft()">${routeOptions('cebu_maasin')}</select></label><label>Issue Type<select id="claimType" onchange="scheduleClaimDraft()">${damageTypeOptions('Scratch/Scuff')}</select></label><label>Contact / Mobile<input id="claimContact" placeholder="Optional phone or Messenger name" oninput="scheduleClaimDraft()"></label><label>Item / Bag Description<input id="claimItem" placeholder="e.g. white luggage, medium, no hang tag" oninput="scheduleClaimDraft()"></label><label style="grid-column:1/-1">Description<textarea id="claimDesc" placeholder="Describe issue, location of damage, missing accessory, item color/size, etc." oninput="scheduleClaimDraft()"></textarea></label></div><button class="primary block" style="margin-top:12px" onclick="saveClaim()">Submit Claim</button></div><div class="card span5"><h3>V67 Intake Guard</h3><div id="claimDupBox" class="notice" style="margin:10px 0">Enter PSN and Last Name to check possible duplicate records.</div><ol><li>Check duplicate first.</li><li>Submit claim.</li><li>Copy acknowledgment if needed.</li><li>Staff captures stub + damage pair.</li></ol><button class="small" onclick="renderApp('intake')">Open Intake Assistant</button></div></div>`;wireClaimAutomation();restoreClaimDraft();showClaimDuplicates();}
function saveClaim(){const psn=$('claimPsn').value.trim(), last=$('claimLast').value.trim();if(!psn||!last){toast('PSN and Last Name required');return}const same=state.data.claims.filter(c=>String(c.psn).toLowerCase()===psn.toLowerCase()&&String(c.last).toLowerCase()===last.toLowerCase()&&!['Done','Rejected'].includes(c.status||''));if(same.length&&!confirm('Possible duplicate open claim found for this PSN + Last Name. Continue saving new claim?'))return;const route=$('claimRoute').value, item={id:uid('claim'),time:today(),psn,last,route,routeLabel:ROUTES[route].label,type:$('claimType').value,contact:$('claimContact').value.trim(),item:$('claimItem').value.trim(),desc:$('claimDesc').value.trim(),status:'Open'};state.data.claims.unshift(item);state.data.drafts.claim=null;audit('Claim saved',psn+' '+last);save();modal(`<div class="modalHead"><h3>Claim Saved</h3><button class="small" onclick="closeModal();renderApp('track')">✕</button></div><div class="printArea"><h2>OceanJet Claim Acknowledgment</h2><p><b>Claim ID:</b> ${esc(item.id)}<br><b>PSN:</b> ${esc(item.psn)}<br><b>Last Name:</b> ${esc(item.last)}<br><b>Route:</b> ${esc(item.routeLabel)}<br><b>Issue:</b> ${esc(item.type)}<br><b>Status:</b> Open</p><p>Please keep your claim stub. Staff will match evidence using PSN + Last Name.</p></div><div class="v63SplitActions noPrint"><button class="primary" onclick="copyText(claimAckText(state.data.claims.find(x=>x.id==='${item.id}')),'Acknowledgment copied')">Copy Acknowledgment</button><button onclick="window.print()">Print</button><button onclick="closeModal();renderApp('damage')">Go to Evidence</button></div>`);toast('Claim saved');}
function intake(){setTitle('Intake Assistant','Search first, then choose the correct next action');const open=v63AllOpenRecords();$('content').innerHTML=hero('Intake Assistant','One controlled screen for staff: search PSN/last name first, avoid duplicates, then continue to Claim, Evidence, Queue, or Receipt.','V67')+`<div class="grid"><div class="card span12"><div class="searchBox"><label>Search PSN / Last Name / Route / Issue<input id="intakeQ" placeholder="Example: 123456, Maasin, white luggage" oninput="renderIntakeResults()"></label><button class="primary" onclick="renderIntakeResults()">Search</button></div><div class="miniActions"><button class="small primary" onclick="renderApp('claim')">New Claim</button><button class="small" onclick="renderApp('damage')">Add Evidence</button><button class="small" onclick="renderApp('queue')">Review Queue</button><button class="small" onclick="renderApp('receipt')">Receipt</button></div></div><div class="card span4"><h3>Open Work</h3><div class="v63Board" style="grid-template-columns:1fr"><div class="v63BoardCard"><span class="tiny">Open claims/cases</span><b>${open.length}</b></div><div class="v63BoardCard"><span class="tiny">High priority</span><b>${state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||'')).length}</b></div><div class="v63BoardCard"><span class="tiny">Missing photo pair</span><b>${dataHealth().missingPairs.length}</b></div></div></div><div class="card span8"><h3>Search Results</h3><div id="intakeOut" style="margin-top:12px"></div></div></div>`;renderIntakeResults();}
function renderIntakeResults(){const q=($('intakeQ')?.value||'').toLowerCase().trim();let rows=[...state.data.claims.map(x=>({...x,kind:'Claim'})),...state.data.cases.map(x=>({...x,kind:'Evidence'}))];if(q)rows=rows.filter(x=>recordText(x).includes(q));rows=rows.slice(0,35);$('intakeOut').innerHTML=rows.length?`<div class="tableWrap"><table><thead><tr><th>Type</th><th>Passenger</th><th>Route</th><th>Issue</th><th>Status</th><th>Next</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.kind)}</td><td><b>${esc(x.psn||'-')}</b><br>${esc(x.last||'-')}</td><td>${esc(x.routeLabel||ROUTES[x.route]?.label||'-')}</td><td>${esc(x.type||x.item||'-')}</td><td>${x.kind==='Evidence'?priorityBadge(x):''} ${statusChip(x.status||'Open')}</td><td><div class="miniActions"><button class="small" onclick="renderApp('damage')">Evidence</button><button class="small" onclick="renderApp('queue')">Queue</button>${x.kind==='Evidence'?`<button class="small" onclick="copyCaseSummary('${x.id}')">Copy</button>`:''}</div></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No local records yet. Start a new claim or add evidence.</div>';}
function board(){setTitle('Operations Board','Manual dispatch view');const h=dataHealth();const high=state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||''));const open=v63AllOpenRecords();$('content').innerHTML=hero('Operations Board','Manual refresh board for staff handover and priority triage. It does not run in the background.','V67')+`<div class="grid"><div class="card span12"><div class="v63Board"><div class="v63BoardCard"><span class="tiny">Open work</span><b>${open.length}</b><span>${state.data.claims.length} claims / ${state.data.cases.length} evidence cases</span></div><div class="v63BoardCard"><span class="tiny">High priority</span><b>${high.length}</b><span>Lost/missing/broken or incomplete evidence</span></div><div class="v63BoardCard"><span class="tiny">Health</span><b>${h.score}%</b><span>${h.kb} KB local storage</span></div></div><div class="miniActions"><button class="small primary" onclick="board()">Refresh Board</button><button class="small" onclick="copyBoardReport()">Copy Board Report</button><button class="small" onclick="renderApp('handover')">Handover</button></div></div><div class="card span7"><h3>Priority Cases</h3>${high.length?`<div class="tableWrap"><table><thead><tr><th>Priority</th><th>Passenger</th><th>Route</th><th>Issue</th><th>Action</th></tr></thead><tbody>${high.slice(0,20).map(x=>`<tr><td>${priorityBadge(x)}</td><td><b>${esc(x.psn)}</b><br>${esc(x.last)}</td><td>${esc(x.routeLabel)}</td><td>${esc(x.type)}<br><span class="tiny">Score ${x.score}%</span></td><td><button class="small" onclick="openCase('${x.id}')">Open</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No high-priority open cases.</div>'}</div><div class="card span5"><h3>Route Load</h3><div style="display:grid;gap:8px;margin-top:10px">${routeLoadRows()}</div></div></div>`;}
function routeLoadRows(){const counts={};v63AllOpenRecords().forEach(x=>{const k=x.routeLabel||ROUTES[x.route]?.label||'Unspecified';counts[k]=(counts[k]||0)+1});const rows=Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,10);return rows.length?rows.map(([r,n])=>`<div class="v63RouteLoad"><span>${esc(r)}</span><b>${n}</b></div>`).join(''):'<div class="empty">No open route load.</div>';}
function copyBoardReport(){const h=dataHealth();const high=state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||''));const txt=`OceanJet V67 Operations Board\nDate: ${today()}\nOpen work: ${v63AllOpenRecords().length}\nHigh priority: ${high.length}\nHealth: ${h.score}%\nStorage: ${h.kb} KB\n\nHigh Priority Cases:\n${high.slice(0,15).map(x=>`- ${x.psn} ${x.last} / ${x.routeLabel} / ${x.type} / ${x.status}`).join('\n')||'- none'}`;copyText(txt,'Board report copied');audit('Board report copied','High priority '+high.length);save();}
function dashboard(){setTitle(cap(state.role)+' Dashboard','V67 intake and operations workflow');const h=dataHealth(), c=state.data.cases.length, cl=state.data.claims.length, open=v63AllOpenRecords().length, rev=state.data.transactions.reduce((a,x)=>a+(x.grand||0),0);const actions=state.role==='passenger'?[['claim','📝','Start Claim','Report baggage damage or issue'],['track','🔎','Track Claim','Search local claim status'],['trips','🕐','Schedules','Route trips and fares'],['calculator','🧮','Estimate','Baggage fee estimate']]:state.role==='cashier'?[['intake','🧭','Intake Assistant','Search first and avoid duplicates'],['calculator','🧮','Official Calculator','Compute and save receipt basis'],['damage','📸','Evidence Studio','Match claim + evidence photos'],['board','📋','Ops Board','Priority and route load']]:[['board','📋','Ops Board','Priority and route load'],['intake','🧭','Intake Assistant','Search first workflow'],['quality','🧪','Quality Control','Find missing data'],['handover','🤝','Handover','Checklist and copyable report']];$('content').innerHTML=hero('OceanJet PortDesk '+APP_VERSION,'Scratch-built clean system with V67 intake assistant, operations board, priority labels, sealed automation, and no background recovery/scanner loops.',cap(state.role)+' workspace')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Passenger Claims</span><b>${cl}</b><span class="tiny">Local reports</span></div><div class="card span3 kpi"><span class="muted">Evidence Cases</span><b>${c}</b><span class="tiny">Stub + damage pairs</span></div><div class="card span3 kpi"><span class="muted">Open Work</span><b>${open}</b><span class="tiny">Claims + evidence not closed</span></div><div class="card span3 kpi"><span class="muted">Local Revenue</span><b>${peso(rev)}</b><span class="tiny">Saved calculator records</span></div><div class="card span12"><div class="cardHead"><div><h3>Workspace Shortcuts</h3><p>Only tools for the selected role are shown. Admin can access everything.</p></div><span class="badge ok">Operations Core</span></div><div class="quick">${actions.map(a=>`<button onclick="renderApp('${a[0]}')"><span class="ico">${a[1]}</span><b>${a[2]}</b><span class="tiny">${a[3]}</span></button>`).join('')}</div></div><div class="card span7"><div class="cardHead"><div><h3>V67 Operating Flow</h3><p>Search before creating, capture evidence in pairs, then board/queue/handover.</p></div></div><div class="opSteps"><div class="opStep"><b>1. Intake</b><span>Check PSN/Last Name before duplicate claim.</span></div><div class="opStep"><b>2. Evidence</b><span>Manual stub + damage pair only.</span></div><div class="opStep"><b>3. Board</b><span>Watch priority and route load manually.</span></div><div class="opStep"><b>4. Handover</b><span>Export backup and copy end-shift report.</span></div></div></div><div class="card span5"><div class="cardHead"><div><h3>Control Status</h3><p>Local health and pending issues.</p></div><span class="badge ${h.score>=80?'ok':h.score>=60?'warn':'bad'}">${h.score}%</span></div><div class="compactList"><div class="compactRow"><span>Storage</span><b>${h.kb} KB</b></div><div class="compactRow"><span>High Priority</span><b>${state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||'')).length}</b></div><div class="compactRow"><span>Missing photo pairs</span><b>${h.missingPairs.length}</b></div><div class="compactRow"><span>Handover</span><b>${typeof handoverPercent==='function'?handoverPercent():0}%</b></div></div><div class="v61Meter" style="margin-top:10px"><span style="width:${Math.min(100,h.score)}%"></span></div></div></div>`;}
function queue(){setTitle('Review Queue','Case status management with V67 priority');$('content').innerHTML=hero('Review Queue','Cashier/Admin can review evidence, filter status, update cases, copy summaries, and open printable case details.','Counter')+`<div class="grid"><div class="card span12"><div class="opSteps"><div class="opStep"><b>${state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||'')).length}</b><span>High Priority</span></div><div class="opStep"><b>${state.data.cases.filter(x=>x.status==='Review').length}</b><span>Review</span></div><div class="opStep"><b>${state.data.cases.filter(x=>x.status==='Open').length}</b><span>Open</span></div><div class="opStep"><b>${state.data.cases.filter(x=>x.status==='Done').length}</b><span>Done</span></div></div></div><div class="card span12"><div class="floatingSearch"><input id="queueQ" placeholder="Search PSN, name, route, type" oninput="renderQueue()"><select id="queueStatus" onchange="renderQueue()"><option value="">All Status</option><option>Review</option><option>Open</option><option>Done</option><option>Rejected</option></select><button onclick="renderQueue()">Search</button></div><div class="miniActions"><button class="small" onclick="document.getElementById('queueQ').value='';document.getElementById('queueStatus').value='';renderQueue()">Show All</button><button class="small warn" onclick="document.getElementById('queueStatus').value='Review';renderQueue()">Needs Review</button><button class="small" onclick="renderApp('board')">Ops Board</button></div><div id="queueTable" style="margin-top:12px"></div></div></div>`;renderQueue();}
function renderQueue(){const q=($('queueQ')?.value||'').toLowerCase().trim(), status=$('queueStatus')?.value||'';let rows=state.data.cases;if(status)rows=rows.filter(x=>x.status===status);if(q)rows=rows.filter(x=>(x.psn+' '+x.last+' '+x.routeLabel+' '+x.type+' '+(x.color||'')+' '+(x.size||'')).toLowerCase().includes(q));$('queueTable').innerHTML=rows.length?`<div class="tableWrap"><table><thead><tr><th>Priority</th><th>Time</th><th>Passenger</th><th>Route</th><th>Type</th><th>Score</th><th>Status</th><th>Action</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${priorityBadge(x)}</td><td>${esc(x.time)}</td><td><b>${esc(x.psn)}</b><br>${esc(x.last)}${x.claimId?'<br><span class="tiny">Claim linked</span>':''}</td><td>${esc(x.routeLabel)}</td><td>${esc(x.type)}<br><span class="tiny">${esc(x.suggestion||'-')}</span></td><td>${x.score}%</td><td>${statusChip(x.status)}</td><td><select onchange="updateCaseStatus('${x.id}',this.value)"><option ${x.status==='Review'?'selected':''}>Review</option><option ${x.status==='Open'?'selected':''}>Open</option><option ${x.status==='Done'?'selected':''}>Done</option><option ${x.status==='Rejected'?'selected':''}>Rejected</option></select><div class="miniActions"><button class="small" onclick="openCase('${x.id}')">Open</button><button class="small" onclick="copyCaseSummary('${x.id}')">Copy</button><button class="small" onclick="copyPassengerUpdate('${x.id}')">Msg</button><button class="small danger" onclick="deleteCase('${x.id}')">Delete</button></div></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No cases found.</div>';}
function openCase(id){const x=state.data.cases.find(a=>a.id===id);if(!x)return;const claim=state.data.claims.find(c=>c.id===x.claimId);modal(`<div class="modalHead"><h3>Evidence Summary</h3><button class="small" onclick="closeModal()">✕</button></div><div class="printArea" id="casePrint"><h2>OceanJet Damage Evidence Summary</h2><p><b>PSN:</b> ${esc(x.psn)}<br><b>Last Name:</b> ${esc(x.last)}<br><b>Route:</b> ${esc(x.routeLabel)}<br><b>Type:</b> ${esc(x.type)}<br><b>Priority:</b> ${casePriority(x)}<br><b>Status:</b> ${esc(x.status)}<br><b>Score:</b> ${x.score}%<br><b>Time:</b> ${esc(x.time)}</p>${claim?`<p><b>Matched Claim:</b> ${esc(claim.id)}<br><b>Claim Contact:</b> ${esc(claim.contact||'-')}<br><b>Claim Item:</b> ${esc(claim.item||'-')}</p>`:''}<p><b>Color:</b> ${esc(x.color||'-')}<br><b>Size/Brand:</b> ${esc(x.size||'-')}</p><p>${esc(x.notes||'')}</p><div class="casePhotos">${x.photos?.stub?`<img src="${x.photos.stub}">`:''}${x.photos?.damage?`<img src="${x.photos.damage}">`:''}</div></div><div class="v63SplitActions noPrint" style="margin-top:10px"><button class="primary" onclick="window.print()">Print Summary</button><button onclick="copyCaseSummary('${x.id}')">Copy Summary</button><button onclick="copyPassengerUpdate('${x.id}')">Copy Passenger Update</button></div>`);}
function downloadAuditCSV(){download('OceanJet_PortDesk_V73_Audit_'+Date.now()+'.csv',csv(state.data.audit),'text/csv');audit('Audit CSV export','V73 audit log');save();toast('Audit CSV downloaded');}
function downloadDailyPacket(){const h=dataHealth();const txt=`OceanJet V67 Daily Packet\nDate: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nClaims: ${state.data.claims.length}\nEvidence cases: ${state.data.cases.length}\nReceipts: ${state.data.receipts.length}\nTransactions: ${state.data.transactions.length}\nHealth: ${h.score}%\nStorage: ${h.kb} KB\nOpen work: ${v63AllOpenRecords().length}\nHigh priority: ${state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||'')).length}\n\nRoute Load:\n${routeLoadRows().replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim()||'-'}\n\nLatest Audit:\n${state.data.audit.slice(0,15).map(a=>`- ${a.time} / ${a.action} / ${a.detail}`).join('\n')}`;audit('Daily packet export','V67 text packet');save();download('OceanJet_PortDesk_V67_Daily_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Daily packet downloaded');}
function reports(){setTitle('Reports & Backup','Export local records');const h=dataHealth();$('content').innerHTML=hero('Reports & Backup','Export full/compact JSON, CSV files, audit log, daily packet, import backup, and review audit log.','Admin')+`<div class="grid"><div class="card span3 kpi"><span class="muted">Claims</span><b>${state.data.claims.length}</b></div><div class="card span3 kpi"><span class="muted">Evidence</span><b>${state.data.cases.length}</b></div><div class="card span3 kpi"><span class="muted">Open Work</span><b>${v63AllOpenRecords().length}</b></div><div class="card span3 kpi"><span class="muted">Health</span><b>${h.score}%</b></div><div class="card span6"><h3>Export</h3><div style="display:grid;gap:8px;margin-top:10px"><button class="primary" onclick="downloadJSON()">Download Full JSON Backup With Photos</button><button onclick="downloadCompactJSON()">Download Compact JSON Backup No Photos</button><button onclick="downloadDailyPacket()">Download V67 Daily Packet TXT</button><button onclick="downloadCSV('claims')">Download Claims CSV</button><button onclick="downloadCSV('cases')">Download Evidence CSV</button><button onclick="downloadCSV('transactions')">Download Transactions CSV</button><button onclick="downloadCSV('receipts')">Download Receipts CSV</button><button onclick="downloadAuditCSV()">Download Audit CSV</button><button onclick="exportShiftCSV()">Download Shift CSV</button></div></div><div class="card span6"><h3>Import & Health</h3><p class="muted">Use a V67, V62, V61, V60, V59, or V58 JSON backup. Import keeps the clean V67 code and replaces local records.</p><label><input type="file" accept="application/json" onchange="importJSON(event)"></label><div class="notice" style="margin-top:12px">Storage: ${h.kb} KB • Photos: ${h.photos}. Full backup keeps photos. Compact backup is smaller but not for image evidence archive.</div><div class="miniActions"><button class="small primary" onclick="renderApp('quality')">Quality Control</button><button class="small" onclick="renderApp('board')">Ops Board</button><button class="small" onclick="renderApp('handover')">Handover</button><button class="small" onclick="renderApp('settlement')">Settlement</button></div></div><div class="card span12"><div class="cardHead"><div><h3>Latest Audit Log</h3><p>Local device actions, latest first.</p></div></div>${renderAudit()}</div></div>`;}
function system(){setTitle('System Tools','Cache and settings');$('content').innerHTML=hero('System Tools','Safe device controls only. No automatic recovery or repair loops are installed.','Admin')+`<div class="grid"><div class="card span6"><h3>Cache & Diagnostics</h3><p>Use after GitHub Pages upload to remove old cached app files and service workers where browser allows.</p><div style="display:grid;gap:8px;margin-top:12px"><button class="danger" onclick="clearOldCache()">Clear Old App Cache</button><button onclick="runDiagnostics()">Run Diagnostics</button><button class="warn" onclick="hardResetData()">Reset Local Data</button></div><div id="diagOut" class="notice" style="margin-top:12px">Ready.</div></div><div class="card span6"><h3>Shift Setup</h3><div class="formGrid"><label>Port<input id="shiftPort" value="${esc(state.data.shift.port||'Cebu')}"></label><label>Staff Name<input id="shiftStaff" value="${esc(state.data.shift.staff||'')}"></label></div><div class="miniActions"><button class="primary" onclick="startShift()">Start / Update Shift</button><button onclick="closeShift()">Close Shift</button><button onclick="renderApp('board')">Open Ops Board</button></div><div class="notice ${state.data.shift.open?'alertGood':'alertWarn'}" style="margin-top:12px">Shift is ${state.data.shift.open?'open since '+esc(state.data.shift.startedAt):'closed'}.</div></div><div class="card span6"><h3>Staff Credentials</h3><div class="formGrid"><label>Cashier User<input id="setCashierU" value="${esc(state.data.settings.cashier.u)}"></label><label>Cashier Pass<input id="setCashierP" value="${esc(state.data.settings.cashier.p)}"></label><label>Admin User<input id="setAdminU" value="${esc(state.data.settings.admin.u)}"></label><label>Admin Pass<input id="setAdminP" value="${esc(state.data.settings.admin.p)}"></label></div><button class="primary block" style="margin-top:12px" onclick="saveCreds()">Save Credentials</button></div><div class="card span6 dangerZone"><h3>Clean Core</h3><p>This scratch app keeps automation sealed. It does not load legacy recovery scripts, auto scanner, repeated intervals, observers, drawer guards, or navigation repair systems.</p><div class="miniActions"><button class="small" onclick="renderApp('automation')">Automation Center</button><button class="small" onclick="renderApp('reports')">Reports</button></div></div></div>`;}
function runDiagnostics(){const needed=['imgFileToDataURL','uploadSingle','batchEvidence','clearOldCache','settlement','quality','lookup','handover','downloadCompactJSON','intake','board','copyCaseSummary','downloadDailyPacket'];const missing=needed.filter(k=>typeof window[k]!=='function');const html=document.documentElement.innerHTML;const d={version:APP_VERSION,role:state.role,views:NAVS[state.role].map(x=>x[0]).join(', '),cases:state.data.cases.length,claims:state.data.claims.length,transactions:state.data.transactions.length,receipts:state.data.receipts.length,localStorageKB:storageKB(),health:dataHealth().score,openWork:v63AllOpenRecords().length,highPriority:state.data.cases.filter(x=>casePriority(x)==='High'&&!['Done','Rejected'].includes(x.status||'')).length,handover:typeof handoverPercent==='function'?handoverPercent()+'%':'n/a',automation:automationStatusText(),forbiddenIntervals:/set\s*Interval\s*\(/i.test(html)?'FOUND':'none',forbiddenObservers:html.includes('Mutation'+'Observer')?'FOUND':'none',missingFunctions:missing.length?missing:'none',shift:state.data.shift.open?'open':'closed',audit:state.data.audit.length};$('diagOut').innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>';}
function hardResetData(){if(confirm('Reset all local records on this device?')){localStorage.removeItem(STORE);location.reload()}}
async function clearOldCache(){try{if('serviceWorker' in navigator){const regs=await navigator.serviceWorker.getRegistrations();for(const r of regs)await r.unregister()}if(window.caches){const keys=await caches.keys();for(const k of keys)await caches.delete(k)}OLD_STORES.forEach(k=>{try{localStorage.removeItem(k)}catch(e){}});audit('Cache cleared','service workers + caches + old PortDesk stores');save();toast('Old cache cleared. Reload now.')}catch(e){toast('Cache clear failed: '+e.message)}}
function openQuickHelp(){modal(`<div class="modalHead"><h3>V67 Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>Continued from the V67 clean base.</li><li>Added Intake Assistant to search before creating duplicate claims.</li><li>Added Operations Board for manual priority and route-load triage.</li><li>Added priority labels, copyable case summaries, and passenger update messages.</li><li>Added Daily Packet TXT and Audit CSV exports.</li><li>No intervals, no observers, no recovery overlay, no auto scanner, and no navigation repair loops.</li><li>Use Admin → System → Clear Old App Cache after upload.</li></ul>`)}

function verifyCoreFunctions(){const missing=['imgFileToDataURL','uploadSingle','batchEvidence','clearOldCache','settlement','quality','lookup','handover','downloadCompactJSON','intake','board','downloadDailyPacket'].filter(k=>typeof window[k]!=='function');if(missing.length){console.warn('V67 missing functions:',missing.join(', '));}else{console.info('OceanJet V67 core functions OK')}}

/* =========================
   V67 ROLE + CLEAN DAMAGE HARDENING LAYER
   Single event-based controller. No intervals, no observers, no scanner loop, no recovery.
   ========================= */
function storageKB(){try{return Math.round((localStorage.getItem(STORE)||'').length/1024)}catch(e){return 0}}
function storagePercent(){return Math.min(100, Math.round(storageKB()/50));}
function roleMeta(role){return role==='admin'?{icon:'🛡️',label:'Admin',cls:'bad',sub:'Full access workspace'}:role==='cashier'?{icon:'💼',label:'Cashier',cls:'warn',sub:'Counter tools workspace'}:{icon:'👤',label:'Passenger',cls:'ok',sub:'Public passenger workspace'};}
function normalizeRole(role){return ['passenger','cashier','admin'].includes(role)?role:'passenger'}
function setActiveRole(role, view='dashboard'){
  role=normalizeRole(role);
  stopCamera(false);
  state.role=role;
  state.loginRole=role;
  state.view=allowed(view)?view:'dashboard';
  audit('Role changed', roleMeta(role).label+' workspace opened');
  save();
  updateLoginRoleButtons(role);
  $('login')?.classList.add('hide');
  document.activeElement?.blur?.();
  closeSidebar();
  renderApp(state.view);
  requestAnimationFrame(()=>{ refreshRoleUI(); window.scrollTo(0,0); });
}
function updateLoginRoleButtons(role=state.loginRole){
  role=normalizeRole(role);
  state.loginRole=role;
  ['Passenger','Cashier','Admin'].forEach(x=>$('login'+x)?.classList.toggle('active',role===x.toLowerCase()));
  $('staffLogin')?.classList.toggle('hide',role==='passenger');
  if(role==='passenger'){ if($('loginUser')) $('loginUser').value=''; if($('loginPass')) $('loginPass').value=''; }
}
function chooseLoginRole(role){
  updateLoginRoleButtons(role);
  setTimeout(()=>{ if(role!=='passenger') $('loginUser')?.focus({preventScroll:true}); }, 80);
}
function loginNow(){
  const role=normalizeRole(state.loginRole);
  if(role!=='passenger'){
    const u=($('loginUser')?.value||'').trim();
    const p=($('loginPass')?.value||'').trim();
    const want=state.data.settings[role]||{};
    if(u!==want.u||p!==want.p){ toast('Invalid '+role+' login'); return; }
  }
  setActiveRole(role,'dashboard');
  toast(roleMeta(role).label+' workspace unlocked');
}
function logout(){
  stopCamera(false);
  state.role='passenger';
  state.loginRole='passenger';
  state.view='dashboard';
  save();
  updateLoginRoleButtons('passenger');
  if($('loginUser')) $('loginUser').value='';
  if($('loginPass')) $('loginPass').value='';
  $('login')?.classList.remove('hide');
  renderShell();
  dashboard();
}
function setRole(role){
  role=normalizeRole(role);
  if(role==='passenger'){ setActiveRole('passenger','dashboard'); return; }
  state.loginRole=role;
  updateLoginRoleButtons(role);
  $('login')?.classList.remove('hide');
  document.activeElement?.blur?.();
  setTimeout(()=>{$('loginUser')?.focus({preventScroll:true});},120);
}
function refreshRoleUI(){
  const meta=roleMeta(state.role);
  const badge=$('roleBadge');
  if(badge){ badge.className='badge '+meta.cls; badge.innerHTML='<span>'+meta.icon+'</span><span class="roleLabelText">'+meta.label+'</span>'; }
  const tb=$('themeBtn'); if(tb) tb.textContent=state.dark?'☀️':'🌙';
  document.body.dataset.role=state.role;
}
function renderShell(){
  const role=normalizeRole(state.role), nav=NAVS[role]||NAVS.passenger;
  refreshRoleUI();
  $('roleSwitch').innerHTML=`<button class="roleBtn ${role==='passenger'?'active':''}" onclick="setRole('passenger')">👤 Passenger</button><button class="roleBtn ${role==='cashier'?'active':''}" onclick="setRole('cashier')">💼 Cashier</button><button class="roleBtn ${role==='admin'?'active':''}" onclick="setRole('admin')">🛡️ Admin</button>`;
  $('sideNav').innerHTML=nav.map(n=>`<button class="${state.view===n[0]?'active':''}" onclick="renderApp('${n[0]}')"><span>${n[1]}</span>${n[2]}</button>`).join('')+'<div class="sep"></div><button onclick="openQuickHelp()">❔ Help / Notes</button>';
  $('bottomNav').innerHTML=nav.slice(0,5).map(n=>`<button class="${state.view===n[0]?'active':''}" onclick="renderApp('${n[0]}')"><i>${n[1]}</i>${n[2]}</button>`).join('');
}
function renderApp(view=state.view){
  view = allowed(view) ? view : 'dashboard';
  state.view=view;
  save();
  closeSidebar();
  renderShell();
  const fn={dashboard,intake,board,calculator,damage,queue,receipt,trips,reports,automation,system,claim,track,settlement,quality,lookup,handover}[view]||dashboard;
  fn();
  refreshRoleUI();
}
function damage(){
  setTitle('Damage Evidence Studio','Fresh manual module only');
  state.draftPhotos={stub:null,damage:null};
  $('content').innerHTML=hero('Damage Evidence Studio','Fresh V67 manual evidence module. No default scanner, no demo evidence, no old version labels, no auto-capture, and no recovery/repair loop.','Clean manual evidence')+`<div class="grid"><div class="card span5"><div class="cardHead"><div><h3>Case Details</h3><p>Enter passenger identity first. Evidence is saved only after staff presses Save.</p></div><span class="badge ok">PSN + Last Name</span></div><div class="formGrid"><label>PSN<input id="dPsn" placeholder="PSN" oninput="renderClaimMatch();scheduleEvidenceDraft()"></label><label>Last Name<input id="dLast" placeholder="Last name" oninput="renderClaimMatch();scheduleEvidenceDraft()"></label><label>Route<select id="dRoute" onchange="scheduleEvidenceDraft()">${routeOptions('cebu_maasin')}</select></label><label>Damage Type<select id="dType" onchange="scheduleEvidenceDraft()">${damageTypeOptions('Scratch/Scuff')}</select></label><label>Item Color<input id="dColor" placeholder="e.g. white" oninput="scheduleEvidenceDraft()"></label><label>Size / Brand<input id="dSize" placeholder="e.g. medium luggage" oninput="scheduleEvidenceDraft()"></label><label style="grid-column:1/-1">Notes<textarea id="dNotes" placeholder="Missing hang tag, broken wheel, scratch location, missing accessory, etc." oninput="scheduleEvidenceDraft()"></textarea></label></div><div id="claimMatchBox" class="notice" style="margin-top:12px">Enter PSN + Last Name to match an open passenger claim.</div><button class="primary block" style="margin-top:12px" onclick="saveEvidenceCase()">Save Evidence Case</button></div><div class="card span7"><div class="cardHead"><div><h3>Manual Capture / Upload</h3><p>Camera starts only when staff presses Start Camera. Batch upload pairs photos as 1-2, 3-4, 5-6.</p></div><span class="badge warn">No Auto Scan</span></div><div class="photoGrid"><div><b>Claim Stub</b><div class="photoSlot" id="stubSlot"><small>No claim-stub photo yet</small></div><div class="cameraBar"><button class="small" onclick="startCamera('stub')">Start Camera</button><button class="small good" onclick="capturePhoto('stub')">Capture Stub</button><label class="fileBtn">Upload Stub<input type="file" accept="image/*" onchange="uploadSingle(event,'stub')"></label></div></div><div><b>Damage Image</b><div class="photoSlot" id="damageSlot"><small>No damage photo yet</small></div><div class="cameraBar"><button class="small" onclick="startCamera('damage')">Start Camera</button><button class="small good" onclick="capturePhoto('damage')">Capture Damage</button><label class="fileBtn">Upload Damage<input type="file" accept="image/*" onchange="uploadSingle(event,'damage')"></label></div></div></div><div id="cameraBox" class="photoSlot hide" style="margin-top:12px;height:260px"><video id="cameraVideo" playsinline muted></video></div><div class="miniActions"><button class="danger small" onclick="stopCamera()">Stop Camera</button><label class="fileBtn" style="background:linear-gradient(135deg,#f7b731,#d99012);color:#1e1600;border-color:transparent">Batch Upload 1-2 / 3-4 / 5-6<input id="batchFiles" type="file" accept="image/*" multiple onchange="batchEvidence(event)"></label><button class="small" onclick="clearDraftPhotos()">Clear draft photos</button></div><div id="pairPreview"></div></div><div class="card span12"><div class="cardHead"><div><h3>Evidence Cases on This Device</h3><p>Fresh V67 storage. Old cached demo evidence is not imported automatically.</p></div><div class="chips"><span class="chip cleanEvidenceBadge">Fresh Store</span><span class="chip">Manual Only</span></div></div><div id="caseList"></div></div></div>`;
  renderClaimMatch(); wireEvidenceAutomation(); renderCaseList(); refreshRoleUI();
}
