function v71FindTrip(id){return state.data.trips.find(t=>t.id===id)}
function v71SetTripStatus(id,status){
  const t=v71FindTrip(id);if(!t)return;
  t.manualStatus=status;t.updatedAt=today();
  const action=status==='Boarding'?'Boarding opened':status==='Closed'?'Boarding closed':status==='Departed'?'Trip departed':status==='Delayed'?'Trip delayed':status==='Cancelled'?'Trip cancelled':'Trip status changed';
  audit(action,`${t.code} ${t.routeLabel}`);save();toast(status+' saved');if(state.view==='board') board(); else v71RenderTripList(false);
}
function v71ApplySuggestedStatus(id){const t=v71FindTrip(id);if(!t)return;const s=v71TripStatus(t).suggested;v71SetTripStatus(id,s)}
function v71ClearManualStatus(id){const t=v71FindTrip(id);if(!t)return;t.manualStatus='';t.updatedAt=today();audit('Trip returned to time suggestion',`${t.code} ${t.routeLabel}`);save();toast('Automatic suggestion restored');board()}
function v71EditTrip(id){
  const t=v71FindTrip(id);if(!t)return;
  modal(`<div class="modalHead"><h3>Edit Trip ${esc(t.code)}</h3><button class="small" onclick="closeModal()">✕</button></div><div class="formGrid"><label>Trip Code<input id="editTripCode" value="${esc(t.code)}"></label><label>Vessel Name<input id="editTripVessel" value="${esc(t.vessel||'')}"></label><label>Route<select id="editTripRoute">${v71RouteOptions(t.route)}</select></label><label>Date<input id="editTripDate" type="date" value="${esc(t.date||v71YMD())}"></label><label>Departure Time<input id="editTripTime" type="time" value="${esc(t.time||'07:00')}"></label><label>Boarding Window<select id="editTripBoard"><option value="10" ${Number(t.boardingMins)===10?'selected':''}>10 minutes before</option><option value="15" ${Number(t.boardingMins)!==10?'selected':''}>15 minutes before</option></select></label><label style="grid-column:1/-1">Gate / Pier<input id="editTripGate" value="${esc(t.gate||'')}"></label><label style="grid-column:1/-1">Notes<textarea id="editTripNote">${esc(t.note||'')}</textarea></label></div><div class="miniActions"><button class="primary" onclick="v71SaveTripEdit('${t.id}')">Save Changes</button><button class="danger" onclick="v71DeleteTrip('${t.id}')">Delete Trip</button></div>`);
}
function v71SaveTripEdit(id){
  const t=v71FindTrip(id);if(!t)return;
  const old=`${t.code} ${t.routeLabel} ${v71DisplayTime(t.time)}`;
  t.code=$('editTripCode').value.trim()||t.code;t.vessel=$('editTripVessel').value.trim()||t.vessel;t.route=$('editTripRoute').value;t.routeLabel=v71RouteLabel(t.route);t.date=$('editTripDate').value||t.date;t.time=$('editTripTime').value||t.time;t.boardingMins=Number($('editTripBoard').value)||V72_BOARDING_DEFAULT_MIN;t.gate=$('editTripGate').value.trim()||'Gate TBA';t.note=$('editTripNote').value.trim();t.updatedAt=today();
  audit('Trip updated',`${old} → ${t.code} ${t.routeLabel} ${v71DisplayTime(t.time)}`);save();closeModal();toast('Trip updated');board();
}
function v71DeleteTrip(id){const t=v71FindTrip(id);if(!t||!confirm('Delete this trip from this device?'))return;state.data.trips=state.data.trips.filter(x=>x.id!==id);audit('Trip deleted',`${t.code} ${t.routeLabel}`);save();closeModal();toast('Trip deleted');board()}
function v71TripHistory(id){const t=v71FindTrip(id);if(!t)return;const needle=t.code;const rows=state.data.audit.filter(a=>(a.detail||'').includes(needle)).slice(0,20);modal(`<div class="modalHead"><h3>Trip History · ${esc(t.code)}</h3><button class="small" onclick="closeModal()">✕</button></div>${rows.length?`<div class="compactList">${rows.map(a=>`<div class="compactRow"><span>${esc(a.time)} · ${esc(a.role)}</span><b>${esc(a.action)}</b><small>${esc(a.detail)}</small></div>`).join('')}</div>`:'<div class="empty">No trip audit entries yet.</div>'}`)}
function v71ResetTodayTrips(){if(!confirm('Replace current trip board with today\'s default Cebu operations trips?'))return;v71SeedTrips(true);audit('Trip board reset','Today Cebu operations trips');save();toast('Trip board reset');board()}
function v71ExportTripsCSV(){const rows=state.data.trips.map(t=>({...t,status:v71TripStatus(t).status,boardingTime:v71DisplayTimeFromDate(v71TripStatus(t).boarding),departureTime:v71DisplayTime(t.time)}));download('OceanJet_V72_Trip_Board_'+Date.now()+'.csv',csv(rows),'text/csv');audit('Trip board CSV export',String(rows.length)+' trips');save();toast('Trip CSV downloaded')}

board = function(){
  ensureData();setTitle('Port Operations','Vessel boarding and trip control');
  const summary=v71TripSummary();
  $('content').innerHTML=hero('Port Operations Board','Monitor vessels, boarding windows, departure grace periods, and manual staff actions from one clean board.','Vessel Board')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span12"><div class="cardHead"><div><h3>Boarding Monitor</h3><p>Boarding starts 10–15 minutes before departure. Departed is suggested after the departure grace period.</p></div><div class="tripFilters"><input id="tripSearch" placeholder="Search trip, vessel, route, gate" oninput="v71RenderTripList(true)"><select id="tripStatusFilter" onchange="v71RenderTripList(true)"><option value="">All status</option><option>Scheduled</option><option>Boarding</option><option>Departing Soon</option><option>Departed</option><option>Delayed</option><option>Closed</option><option>Cancelled</option></select><button class="small" onclick="board()">Refresh Status</button><button class="small" onclick="v71ExportTripsCSV()">Export CSV</button></div></div><div id="tripRows"></div></div>${v71TripForm()}<div class="card span7"><div class="cardHead"><div><h3>Operations Policy</h3><p>Time suggestions are visible. Staff confirms important status changes.</p></div><span class="badge ok">No background loop</span></div><div class="opSteps"><div class="opStep"><b>1. Scheduled</b><span>Trip record is created with vessel, gate, route, and departure time.</span></div><div class="opStep"><b>2. Boarding</b><span>Suggested 10–15 minutes before departure or opened manually by staff.</span></div><div class="opStep"><b>3. Closing</b><span>Departing Soon appears near departure. Staff can close boarding.</span></div><div class="opStep"><b>4. Departed</b><span>Suggested after a 10-minute grace period, then staff confirms if needed.</span></div></div><div class="miniActions"><button class="warn" onclick="v71ResetTodayTrips()">Reset Today Trips</button><button onclick="renderApp('queue')">Open Review Queue</button><button onclick="renderApp('calculator')">Open Baggage Estimate</button></div></div></div>`;
  v71RenderTripList(true);
};

trips = function(){
  ensureData();setTitle('Trips & Vessel Status','Public schedule and boarding monitor');
  const summary=v71TripSummary();
  $('content').innerHTML=hero('Trips & Boarding Status','View Cebu routes, vessel code, departure time, boarding time, gate, and current status.','Passenger Schedule')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span12"><div class="cardHead"><div><h3>Today\'s Vessel Board</h3><p>Passenger view is read-only. Staff controls are available in Port Operations.</p></div><div class="tripFilters"><input id="tripSearch" placeholder="Search route or vessel" oninput="v71RenderTripList(false)"><select id="tripStatusFilter" onchange="v71RenderTripList(false)"><option value="">All status</option><option>Scheduled</option><option>Boarding</option><option>Departing Soon</option><option>Departed</option><option>Delayed</option><option>Closed</option><option>Cancelled</option></select><button class="small" onclick="trips()">Refresh</button></div></div><div id="tripRows"></div></div><div class="card span12"><div class="cardHead"><div><h3>Main Cebu Destinations</h3><p>Route list used by the baggage estimate and trip board.</p></div></div><div class="routeChipGrid">${V72_TRIP_ROUTES.map(r=>`<span class="routeChip">${esc(v71RouteLabel(r))}</span>`).join('')}</div></div></div>`;
  v71RenderTripList(false);
};

dashboard = function(){
  ensureData();setTitle(state.role==='admin'?'Admin Command Center':state.role==='cashier'?'Cashier Counter':'Passenger Hub','PortDesk V73 operations workflow');
  const c=state.data.cases.length, cl=state.data.claims.length, openCases=state.data.cases.filter(x=>!['Done','Rejected'].includes(x.status||'')).length, openClaims=state.data.claims.filter(x=>!['Done','Rejected'].includes(x.status||'')).length, estimates=state.data.transactions.length;
  const summary=v71TripSummary(), next=summary.next;
  const actions=state.role==='passenger'?[['trips','🕐','Trips & Boarding','View vessel status and boarding time'],['claim','📝','Start Claim','Report baggage damage or issue'],['track','🔎','Track Claim','Search local claim status'],['calculator','🧮','Baggage Estimate','Estimate baggage fee only']]:state.role==='cashier'?[['board','🛳️','Port Operations','Monitor boarding and trips'],['calculator','🧮','Baggage Estimate','Compute and save estimate'],['damage','📸','Evidence Studio','Pair claim stub + damage image'],['queue','👥','Review Queue','Update claim/evidence status']]:[['board','🛳️','Port Operations','Full vessel and boarding control'],['queue','👥','Review Queue','Manage all cases'],['reports','📊','Reports','Export backup and CSV'],['system','⚙️','System Tools','Shift, cache, credentials']];
  $('content').innerHTML=hero(state.role==='admin'?'Admin Command Center':state.role==='cashier'?'Cashier Counter':'Passenger Hub','Clean role-based dashboard with vessel boarding, baggage estimate, claim review, and manual evidence workflows.','PortDesk')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span3 kpi"><span class="muted">Trips Today</span><b>${state.data.trips.length}</b><span class="tiny">${summary.nowBoarding.length} boarding now</span></div><div class="card span3 kpi"><span class="muted">Next Trip</span><b>${next?esc(next.trip.code):'-'}</b><span class="tiny">${next?v71DisplayTime(next.trip.time):'No schedule'}</span></div><div class="card span3 kpi"><span class="muted">Open Claims</span><b>${openClaims}</b><span class="tiny">${cl} total reports</span></div><div class="card span3 kpi"><span class="muted">Evidence Queue</span><b>${openCases}</b><span class="tiny">${c} evidence cases</span></div><div class="card span12"><div class="cardHead"><div><h3>Workspace Shortcuts</h3><p>Only tools for the active role are shown. Admin has full control.</p></div><span class="badge ok">Operations V73</span></div><div class="quick">${actions.map(a=>`<button onclick="renderApp('${a[0]}')"><span class="ico">${a[1]}</span><b>${a[2]}</b><span class="tiny">${a[3]}</span></button>`).join('')}</div></div><div class="card span7"><div class="cardHead"><div><h3>Recommended Port Flow</h3><p>Use one active navigation system and confirm important operations manually.</p></div></div><div class="opSteps"><div class="opStep"><b>1. Trip</b><span>Open Port Operations and confirm boarding/departure status.</span></div><div class="opStep"><b>2. Baggage</b><span>Compute baggage-only estimate and save receipt basis.</span></div><div class="opStep"><b>3. Claim</b><span>Record PSN + Last Name before evidence matching.</span></div><div class="opStep"><b>4. Review</b><span>Update queue and export backup for handover.</span></div></div></div><div class="card span5"><div class="cardHead"><div><h3>Local Workload</h3><p>Device-local records.</p></div><span class="badge ${summary.delayed?'warn':'ok'}">${summary.delayed?summary.delayed+' delayed':'Normal'}</span></div><div class="compactList"><div class="compactRow"><span>Baggage estimates</span><b>${estimates}</b></div><div class="compactRow"><span>Closed / departed trips</span><b>${summary.closed+summary.departed}</b></div><div class="compactRow"><span>Cancelled trips</span><b>${summary.cancelled}</b></div><div class="compactRow"><span>Port</span><b>${esc(state.data.shift.port||'Cebu')}</b></div></div></div></div>`;
};

const v71BaseSystem = system;
system = function(){
  v71BaseSystem();
  const grid=document.querySelector('#content .grid');
  if(grid){grid.insertAdjacentHTML('beforeend',`<div class="card span12"><div class="cardHead"><div><h3>Trip Board Tools</h3><p>Manual controls for the V72 Port Operations Board.</p></div><span class="badge ok">${state.data.trips.length} trips</span></div><div class="miniActions"><button onclick="renderApp('board')">Open Port Operations</button><button onclick="v71ExportTripsCSV()">Export Trip CSV</button><button class="warn" onclick="v71ResetTodayTrips()">Reset Today Trips</button></div><div class="notice" style="margin-top:12px">Trip status suggestions are calculated only when the board is opened or refreshed. No background timer or auto-repair behavior is installed.</div></div>`)};
};

const v71BaseDownloadDailyPacket = typeof downloadDailyPacket==='function'?downloadDailyPacket:null;
downloadDailyPacket = function(){
  const summary=v71TripSummary();
  const tripLines=[...state.data.trips].sort(v71TripCodeSort).map(t=>{const info=v71TripStatus(t);return `- ${t.code} / ${t.vessel||'-'} / ${t.routeLabel||v71RouteLabel(t.route)} / Boarding ${v71DisplayTimeFromDate(info.boarding)} / Departure ${v71DisplayTime(t.time)} / ${info.status}`}).join('\n');
  const txt=`OceanJet V73 Daily Packet\nDate: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nTrips today: ${state.data.trips.length}\nNow boarding: ${summary.nowBoarding.length}\nDeparted: ${summary.departed}\nDelayed: ${summary.delayed}\nClosed: ${summary.closed}\nClaims: ${state.data.claims.length}\nEvidence cases: ${state.data.cases.length}\nBaggage estimates: ${state.data.transactions.length}\n\nTrip Board:\n${tripLines||'-'}\n\nLatest Audit:\n${state.data.audit.slice(0,20).map(a=>`- ${a.time} / ${a.action} / ${a.detail}`).join('\n')}`;
  audit('Daily packet export','V73 operations packet');save();download('OceanJet_PortDesk_V73_Daily_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Daily packet downloaded');
};

openQuickHelp = function(){modal(`<div class="modalHead"><h3>V73 Port Operations Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>V72 adds a vessel boarding board with trip code, vessel, route, gate, boarding time, departure time, status, and last updated time.</li><li>Boarding is suggested 10–15 minutes before departure; Departing Soon appears near departure; Departed is suggested after the grace period.</li><li>Status suggestions are visible and staff-controlled. Important records are not changed secretly.</li><li>Baggage Estimate remains baggage-only, with Cebu destination buttons and detailed tier computation.</li><li>Damage Evidence Studio remains manual-only with paired claim-stub and damage-image evidence.</li><li>No recovery system, blank-screen watcher, scanner loop, auto-capture, DOM observer, setInterval UI repair, or navigation auto-fixer is added.</li></ul>`)};



/* ======================================================================
   V72 OPERATIONS WORKFLOW PASS
   Deepening the trip board, dashboard summaries, and trip links across
   baggage, claims, evidence, queue, and audit. Event-driven only.
   ====================================================================== */
const V72_STATUS_ORDER = ['Boarding','Departing Soon','Scheduled','Delayed','Closed','Departed','Cancelled'];
const V72_ACTIVE_STATUSES = ['Scheduled','Boarding','Departing Soon','Delayed','Closed'];

function v72TripDecorated(){return v71TripSummary().decorated.sort((a,b)=>a.info.dep-b.info.dep)}
function v72TripsByStatus(){const groups={};V72_STATUS_ORDER.forEach(s=>groups[s]=[]);v72TripDecorated().forEach(x=>{(groups[x.info.status] ||= []).push(x)});return groups}
function v72TripShortLine(x){const t=x.trip, info=x.info;return `<div class="tinyTrip"><b>${esc(t.code)} · ${esc(t.vessel||'OceanJet')}</b><span>${esc(t.routeLabel||v71RouteLabel(t.route))}</span><span>${v71DisplayTimeFromDate(info.boarding)} boarding · ${v71DisplayTime(t.time)} depart · ${esc(t.gate||'Gate TBA')}</span></div>`}
function v72StatusLanes(){const groups=v72TripsByStatus();return `<div class="v72Lanes">${V72_STATUS_ORDER.map(s=>`<div class="v72Lane"><h4>${v71StatusIcon(s)} ${esc(s)} <span class="badge ${s==='Delayed'?'warn':s==='Cancelled'?'bad':'ok'}">${groups[s]?.length||0}</span></h4>${(groups[s]||[]).slice(0,3).map(v72TripShortLine).join('')||'<div class="tiny">No trips.</div>'}</div>`).join('')}</div>`}
function v72OpsSummaryCards(summary){
  const soon=summary.decorated.filter(x=>x.info.status==='Departing Soon').length;
  const scheduled=summary.decorated.filter(x=>x.info.status==='Scheduled').length;
  const claims=state.data.claims?.filter(c=>!['Done','Rejected'].includes(c.status||'')).length||0;
  const evidence=state.data.cases?.filter(c=>!['Done','Rejected'].includes(c.status||'')).length||0;
  const estimates=state.data.transactions?.length||0;
  const next=summary.next;
  return `<div class="opsSummary"><div class="opsMini"><span>Now Boarding</span><b>${summary.nowBoarding.length}</b><small>${summary.nowBoarding.map(x=>x.trip.code).slice(0,2).join(', ')||'No active boarding'}</small></div><div class="opsMini"><span>Departing Soon</span><b>${soon}</b><small>Within final minutes</small></div><div class="opsMini"><span>Next Departure</span><b>${next?esc(next.trip.code):'-'}</b><small>${next?v71DisplayTime(next.trip.time):'No trip'}</small></div><div class="opsMini"><span>Total Trips Today</span><b>${state.data.trips.length}</b><small>${scheduled} scheduled</small></div><div class="opsMini"><span>Departed</span><b>${summary.departed}</b><small>Confirmed or suggested</small></div><div class="opsMini"><span>Delayed / Cancelled</span><b>${summary.delayed+summary.cancelled}</b><small>${summary.delayed} delayed · ${summary.cancelled} cancelled</small></div><div class="opsMini"><span>Closed Boarding</span><b>${summary.closed}</b><small>Not accepting boarding</small></div><div class="opsMini"><span>Work Queue</span><b>${claims+evidence}</b><small>${claims} claims · ${evidence} evidence · ${estimates} estimates</small></div></div>`;
}
v71OpsSummaryCards = v72OpsSummaryCards;

function v72BestActiveTrip(){const d=v72TripDecorated();return d.find(x=>x.info.status==='Boarding')||d.find(x=>x.info.status==='Departing Soon')||d.find(x=>V72_ACTIVE_STATUSES.includes(x.info.status))||d[0]||null}
function v72NowBoardingPanel(summary){
  const active = summary.nowBoarding[0] || v72BestActiveTrip();
  if(!active){return `<div class="opsNow"><span class="label">Port Operations</span><h2>No Trips</h2><p>Add a vessel trip to start the operations board.</p></div>`}
  const t=active.trip, info=active.info;
  const heading=info.status==='Boarding'?`Now Boarding: ${esc(t.code)}`:info.status==='Departing Soon'?`Departing Soon: ${esc(t.code)}`:info.status==='Delayed'?`Delayed: ${esc(t.code)}`:info.status==='Closed'?`Boarding Closed: ${esc(t.code)}`:`Next Departure: ${esc(t.code)}`;
  return `<div class="opsNow"><span class="label">${esc(info.status)}</span><h2>${heading}</h2><p class="vesselName">Vessel: ${esc(t.vessel||'OceanJet Vessel')}</p><p>${esc(t.routeLabel||v71RouteLabel(t.route))}</p><p class="bigTime">Boarding ${v71DisplayTimeFromDate(info.boarding)} · Departure ${v71DisplayTime(t.time)}</p><p>Gate: ${esc(t.gate||'Counter / Gate TBA')}</p><div style="margin-top:12px">${v71StatusBadge(info.status)}</div><div class="v72OpsStrip"><span class="chip">Boarding window: ${Number(t.boardingMins)||15} min before</span><span class="chip">Departed suggestion: +${Number(t.departGraceMins)||10} min</span><span class="chip">Last updated: ${esc(t.updatedAt||'-')}</span></div></div>`;
}
v71NowBoardingPanel = v72NowBoardingPanel;

function v72TripOptionLabel(t){const info=v71TripStatus(t);return `${t.code} · ${t.vessel||'OceanJet'} · ${t.routeLabel||v71RouteLabel(t.route)} · ${v71DisplayTime(t.time)} · ${info.status}`}
function v72TripOptions(selected='', includeBlank=true){ensureData();const rows=[...state.data.trips].sort(v71TripCodeSort);return `${includeBlank?`<option value="">No linked trip</option>`:''}${rows.map(t=>`<option value="${esc(t.id)}" ${selected===t.id?'selected':''}>${esc(v72TripOptionLabel(t))}</option>`).join('')}`}
function v72FindTrip(id){return state.data.trips.find(t=>t.id===id)||null}
function v72SelectedTrip(id){const t=v72FindTrip(id);if(!t)return null;const info=v71TripStatus(t);return {id:t.id,code:t.code,vessel:t.vessel,route:t.route,routeLabel:t.routeLabel||v71RouteLabel(t.route),gate:t.gate,time:t.time,date:t.date,status:info.status,boardingTime:v71DisplayTimeFromDate(info.boarding),departureTime:v71DisplayTime(t.time)}}
function v72TripBadgeFromRecord(x){if(!x?.tripCode)return '';return `<div class="v72TripLink"><b>Trip:</b> ${esc(x.tripCode)} · ${esc(x.vessel||'OceanJet')}<br><span class="tiny">${esc(x.routeLabel||'')} · ${esc(x.gate||'Gate TBA')} · ${esc(x.departureTime||'')}</span></div>`}
function v72SyncRouteFromTrip(selectId, routeId){const trip=v72SelectedTrip($(selectId)?.value);if(!trip)return;const r=$(routeId);if(r){r.value=trip.route;r.dispatchEvent(new Event('change',{bubbles:true}))}if(typeof v68RefreshRouteButtons==='function')v68RefreshRouteButtons();}

function v72SetTripStatus(id,status){const t=v71FindTrip(id);if(!t)return;t.manualStatus=status;t.updatedAt=today();const action=status==='Boarding'?'Boarding opened':status==='Departing Soon'?'Trip marked departing soon':status==='Closed'?'Boarding closed':status==='Departed'?'Trip departed':status==='Delayed'?'Trip delayed':status==='Cancelled'?'Trip cancelled':status==='Scheduled'?'Trip rescheduled':'Trip status changed';audit(action,`${t.code} ${t.routeLabel}`);save();toast(status+' saved');if(state.view==='board') board(); else v71RenderTripList(false)}
v71SetTripStatus = v72SetTripStatus;
function v72ReopenBoarding(id){v72SetTripStatus(id,'Boarding')}
function v72TripStatusActionButtons(t,info){return `<div class="tripActions"><button class="small primary" onclick="v71ApplySuggestedStatus('${t.id}')">Confirm ${esc(info.suggested)}</button><button class="small good" onclick="v71SetTripStatus('${t.id}','Boarding')">Open Boarding</button><button class="small warn" onclick="v71SetTripStatus('${t.id}','Departing Soon')">Departing Soon</button><button class="small warn" onclick="v71SetTripStatus('${t.id}','Closed')">Close Boarding</button><button class="small" onclick="v71SetTripStatus('${t.id}','Departed')">Mark Departed</button><button class="small warn" onclick="v71SetTripStatus('${t.id}','Delayed')">Delay</button><button class="small danger" onclick="v71SetTripStatus('${t.id}','Cancelled')">Cancel</button><button class="small good" onclick="v72ReopenBoarding('${t.id}')">Reopen</button><button class="small" onclick="v71ClearManualStatus('${t.id}')">Auto Suggest</button><button class="small" onclick="v71EditTrip('${t.id}')">Edit</button><button class="small" onclick="v71TripHistory('${t.id}')">History</button><button class="small danger" onclick="v71DeleteTrip('${t.id}')">Delete</button></div>`}
function v72TripCard(t, staffMode){
  const info=v71TripStatus(t), route=t.routeLabel||v71RouteLabel(t.route);
  const suggestion=info.manual?`Manual status is active. Time suggestion: ${info.suggested}.` : info.message;
  const cls=info.status==='Boarding'?'v72Boarding':info.status==='Departing Soon'?'v72Urgent':info.status==='Cancelled'?'v72Cancelled':'';
  return `<div class="tripCard ${cls}" data-trip="${esc(t.id)}"><div><h3>${esc(t.code||'Trip')} · ${esc(route)}</h3><p class="muted">${esc(t.vessel||'OceanJet Vessel')} · ${esc(t.note||'Port operations trip')}</p><div class="tripMeta"><div><span>Departure</span><b>${v71DisplayDate(t.date)} · ${v71DisplayTime(t.time)}</b></div><div><span>Boarding Time</span><b>${v71DisplayTimeFromDate(info.boarding)}</b></div><div><span>Gate / Pier</span><b>${esc(t.gate||'TBA')}</b></div><div><span>Last Updated</span><b>${esc(t.updatedAt||'-')}</b></div></div>${v71TripTimeline(info)}</div><div class="tripSide">${v71StatusBadge(info.status)}<small class="tiny">${info.manual?'Manual staff status':'Time-based suggestion'}</small></div><div class="tripSuggest"><b>Suggestion:</b> ${esc(suggestion)}</div>${staffMode?v72TripStatusActionButtons(t,info):''}</div>`;
}
v71TripCard = v72TripCard;

function v72TripForm(){
  const d=v71YMD();
  return `<div class="card span5"><div class="cardHead"><div><h3>Add Trip</h3><p>Create vessel trips with route, gate, boarding window, and departure grace.</p></div></div><div class="formGrid"><label>Trip Code<input id="newTripCode" placeholder="OJ388"></label><label>Vessel Name<input id="newTripVessel" placeholder="OceanJet vessel name"></label><label>Route<select id="newTripRoute">${v71RouteOptions('cebu_maasin')}</select></label><label>Date<input id="newTripDate" type="date" value="${d}"></label><label>Departure Time<input id="newTripTime" type="time" value="07:00"></label><label>Boarding Window<select id="newTripBoard"><option value="10">10 minutes before</option><option value="15" selected>15 minutes before</option></select></label><label>Departure Grace<select id="newTripGrace"><option value="5">5 minutes after</option><option value="10" selected>10 minutes after</option><option value="15">15 minutes after</option></select></label><label>Gate / Pier<input id="newTripGate" placeholder="Pier 1 / Gate A"></label><label style="grid-column:1/-1">Notes<textarea id="newTripNote" placeholder="Connection, counter reminder, vessel remark"></textarea></label></div><button class="primary block" style="margin-top:12px" onclick="v72AddTrip()">Add Trip to Board</button><div class="opsFormNote" style="margin-top:12px">Status suggestions calculate only when staff opens or refreshes the board.</div></div>`;
}
function v72AddTrip(){
  const code=$('newTripCode').value.trim()||('OJ'+Math.floor(100+Math.random()*899));
  const vessel=$('newTripVessel').value.trim()||('OceanJet '+code.replace(/[^0-9]/g,''));
  const route=$('newTripRoute').value;
  const item={id:uid('trip'),code,vessel,route,routeLabel:v71RouteLabel(route),date:$('newTripDate').value||v71YMD(),time:$('newTripTime').value||'07:00',gate:$('newTripGate').value.trim()||'Gate TBA',boardingMins:Number($('newTripBoard').value)||V72_BOARDING_DEFAULT_MIN,departGraceMins:Number($('newTripGrace')?.value)||V72_DEPART_GRACE_MIN,manualStatus:'',note:$('newTripNote').value.trim(),createdAt:today(),updatedAt:today()};
  state.data.trips.unshift(item);audit('Trip created',`${item.code} ${item.routeLabel} ${v71DisplayTime(item.time)} ${item.gate}`);save();toast('Trip added');board();
}
v71TripForm = v72TripForm;
v71AddTrip = v72AddTrip;

const v72BaseEditTrip = v71EditTrip;
v71EditTrip = function(id){
  const t=v71FindTrip(id);if(!t)return;
  modal(`<div class="modalHead"><h3>Edit Trip ${esc(t.code)}</h3><button class="small" onclick="closeModal()">✕</button></div><div class="formGrid"><label>Trip Code<input id="editTripCode" value="${esc(t.code)}"></label><label>Vessel Name<input id="editTripVessel" value="${esc(t.vessel||'')}"></label><label>Route<select id="editTripRoute">${v71RouteOptions(t.route)}</select></label><label>Date<input id="editTripDate" type="date" value="${esc(t.date||v71YMD())}"></label><label>Departure Time<input id="editTripTime" type="time" value="${esc(t.time||'07:00')}"></label><label>Boarding Window<select id="editTripBoard"><option value="10" ${Number(t.boardingMins)===10?'selected':''}>10 minutes before</option><option value="15" ${Number(t.boardingMins)!==10?'selected':''}>15 minutes before</option></select></label><label>Departure Grace<select id="editTripGrace"><option value="5" ${Number(t.departGraceMins)===5?'selected':''}>5 minutes after</option><option value="10" ${Number(t.departGraceMins)!==5&&Number(t.departGraceMins)!==15?'selected':''}>10 minutes after</option><option value="15" ${Number(t.departGraceMins)===15?'selected':''}>15 minutes after</option></select></label><label>Gate / Pier<input id="editTripGate" value="${esc(t.gate||'')}"></label><label style="grid-column:1/-1">Notes<textarea id="editTripNote">${esc(t.note||'')}</textarea></label></div><div class="miniActions"><button class="primary" onclick="v72SaveTripEdit('${t.id}')">Save Changes</button><button class="danger" onclick="v71DeleteTrip('${t.id}')">Delete Trip</button></div>`);
}
function v72SaveTripEdit(id){
  const t=v71FindTrip(id);if(!t)return;const old=`${t.code} ${t.routeLabel} ${v71DisplayTime(t.time)}`;
  t.code=$('editTripCode').value.trim()||t.code;t.vessel=$('editTripVessel').value.trim()||t.vessel;t.route=$('editTripRoute').value;t.routeLabel=v71RouteLabel(t.route);t.date=$('editTripDate').value||t.date;t.time=$('editTripTime').value||t.time;t.boardingMins=Number($('editTripBoard').value)||V72_BOARDING_DEFAULT_MIN;t.departGraceMins=Number($('editTripGrace')?.value)||V72_DEPART_GRACE_MIN;t.gate=$('editTripGate').value.trim()||'Gate TBA';t.note=$('editTripNote').value.trim();t.updatedAt=today();
  audit('Trip edited',`${old} → ${t.code} ${t.routeLabel} ${v71DisplayTime(t.time)} ${t.gate}`);save();closeModal();toast('Trip updated');board();
}
v71SaveTripEdit = v72SaveTripEdit;

board = function(){
  ensureData();setTitle('Port Operations','Vessel boarding and trip control');
  const summary=v71TripSummary();
  $('content').innerHTML=hero('Port Operations Board','Monitor vessel status, boarding windows, departure grace, delays, cancellations, and staff-controlled trip actions.','Vessel Board')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span12"><div class="cardHead"><div><h3>Operations Overview</h3><p>Grouped by live suggested/manual status for fast counter decisions.</p></div><div class="v72ActionCluster"><button class="small" onclick="board()">Refresh Status</button><button class="small" onclick="v71ExportTripsCSV()">Export CSV</button><button class="small" onclick="downloadDailyPacket()">Daily Packet</button></div></div>${v72StatusLanes()}</div><div class="card span12"><div class="cardHead"><div><h3>Boarding Monitor</h3><p>Search, filter, and confirm staff actions. Delayed and Cancelled override time suggestions.</p></div><div class="tripFilters"><input id="tripSearch" placeholder="Search trip, vessel, route, gate" oninput="v71RenderTripList(true)"><select id="tripStatusFilter" onchange="v71RenderTripList(true)"><option value="">All status</option>${V72_STATUS_ORDER.map(s=>`<option>${s}</option>`).join('')}</select></div></div><div id="tripRows"></div></div>${v71TripForm()}<div class="card span7"><div class="cardHead"><div><h3>Connected Workflow</h3><p>Trips can now be linked to baggage estimates, claims, evidence, review queue records, and audit entries.</p></div><span class="badge ok">Event-based</span></div><div class="opSteps"><div class="opStep"><b>1. Trip</b><span>Create or confirm vessel status.</span></div><div class="opStep"><b>2. Estimate</b><span>Select trip in Baggage Estimate so receipt carries vessel details.</span></div><div class="opStep"><b>3. Claim</b><span>Select trip during intake for clearer review.</span></div><div class="opStep"><b>4. Evidence</b><span>Optional trip link appears in Review Queue.</span></div></div><div class="miniActions"><button class="warn" onclick="v71ResetTodayTrips()">Reset Today Trips</button><button onclick="renderApp('claim')">Open Claim Intake</button><button onclick="renderApp('calculator')">Open Baggage Estimate</button></div><div class="v72FinePrint">No automatic tab/role switching is used. Staff confirms all operational changes.</div></div></div>`;
  v71RenderTripList(true);
};

trips = function(){
  ensureData();setTitle('Trips & Vessel Status','Passenger schedule and boarding monitor');
  const summary=v71TripSummary();
  $('content').innerHTML=hero('Trips & Boarding Status','Read-only vessel board showing trip code, vessel, route, gate, boarding time, departure time, and current status.','Passenger Schedule')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span12"><div class="cardHead"><div><h3>Today\'s Vessel Board</h3><p>Passenger view is read-only. Staff controls are available after Cashier/Admin login.</p></div><div class="tripFilters"><input id="tripSearch" placeholder="Search route, vessel, trip" oninput="v71RenderTripList(false)"><select id="tripStatusFilter" onchange="v71RenderTripList(false)"><option value="">All status</option>${V72_STATUS_ORDER.map(s=>`<option>${s}</option>`).join('')}</select><button class="small" onclick="trips()">Refresh</button></div></div><div id="tripRows"></div></div><div class="card span12"><div class="cardHead"><div><h3>Main Cebu Destinations</h3><p>Route list used by Baggage Estimate and Port Operations.</p></div></div><div class="routeChipGrid">${V72_TRIP_ROUTES.map(r=>`<span class="routeChip">${esc(v71RouteLabel(r))}</span>`).join('')}</div></div></div>`;
  v71RenderTripList(false);
};

function v72TripWorkflowSelect(id, routeId, selected=''){return `<label class="v72LinkedSelect">Trip / Vessel<select id="${id}" onchange="v72SyncRouteFromTrip('${id}','${routeId}')">${v72TripOptions(selected,true)}</select><small class="tiny">Optional. Selecting a trip also updates the route.</small></label>`}

const v72BaseCompute = compute;
compute = function(saveAsOriginal){
  const d=v72BaseCompute(saveAsOriginal);
  const trip=v72SelectedTrip($('calcTrip')?.value||'');
  if(trip){Object.assign(d,{tripId:trip.id,tripCode:trip.code,vessel:trip.vessel,gate:trip.gate,tripStatus:trip.status,boardingTime:trip.boardingTime,departureTime:trip.departureTime});state.lastCalc={...state.lastCalc,...d};v67LastCalc={...v67LastCalc,...d};
    if($('receipt')){$('receipt').querySelector('.rSub')?.insertAdjacentHTML('afterend',`<div class="rLine"><span>Trip / Vessel</span><b>${esc(trip.code)} · ${esc(trip.vessel)}</b></div><div class="rLine"><span>Gate / Depart</span><b>${esc(trip.gate||'Gate TBA')} · ${esc(trip.departureTime)}</b></div>`)}
    if(typeof v67LastReceiptText==='string'){v67LastReceiptText=v67LastReceiptText.replace('Route:',`Trip: ${trip.code}\nVessel: ${trip.vessel}\nGate: ${trip.gate||'Gate TBA'}\nDeparture: ${trip.departureTime}\nRoute:`)}
    if($('routeTripBox')){$('routeTripBox').insertAdjacentHTML('afterbegin',`<div class="notice alertGood"><b>Linked Trip:</b> ${esc(trip.code)} · ${esc(trip.vessel)}<br>${esc(trip.gate||'Gate TBA')} · ${esc(trip.status)} · Departure ${esc(trip.departureTime)}</div>`)}
  }
  return d;
};
function calculator(){
  const current=V69_CALC_ROUTES.includes(state.lastCalc?.route)?state.lastCalc.route:(V69_CALC_ROUTES.includes(v67LastCalc?.route)?v67LastCalc.route:'cebu_maasin');
  const oldCls=state.lastCalc?.cls==='BC'||state.lastCalc?.cls==='business'?'business':'tourist';
  setTitle('Baggage Calculator','Baggage estimate only with optional trip link');
  $('content').innerHTML=hero(state.role==='passenger'?'Baggage Estimate':'Official Baggage Estimate','Clean destination-first baggage calculator. Link a vessel trip when the estimate belongs to a scheduled departure.','Baggage estimate')+`<div class="grid baggageV70"><div class="card span12 v70RoutePanel"><div class="cardHead"><div><h3>Choose Destination</h3><p>Select one Cebu route or choose an active trip below.</p></div><span class="badge ok">Cebu routes</span></div>${v67QuickRoutes(current)}<select id="calcRoute" class="v70HiddenSelect" aria-label="Selected route" onchange="compute(false);v68RefreshRouteButtons()">${routeOptions(current)}</select></div><div class="card span5"><div class="cardHead"><div><h3>Trip & Baggage Details</h3><p>Enter passenger count and total baggage weight.</p></div><span class="badge ok" id="calcBadge">Ready</span></div><div class="formGrid">${v72TripWorkflowSelect('calcTrip','calcRoute',state.lastCalc?.tripId||'')}<label>Mode<select id="calcMode" onchange="v67ToggleMode();compute(false)"><option value="normal" ${state.lastCalc?.type==='fragile'||state.lastCalc?.mode==='fragile'?'':'selected'}>Normal</option><option value="fragile" ${state.lastCalc?.type==='fragile'||state.lastCalc?.mode==='fragile'?'selected':''}>Fragile / Special</option></select></label><label class="normalOnly">Class<select id="calcClass" onchange="compute(false)">${classOptions(oldCls)}</select></label><label class="normalOnly">Passengers<input id="pax" type="number" min="1" value="${state.lastCalc?.pax||1}" oninput="compute(false)"></label><label>Total Weight KG<input id="weight" type="number" min="0" step="0.1" value="${state.lastCalc?.kg||state.lastCalc?.weight||0}" oninput="compute(false)"></label><label>Rounding<select id="rounding" onchange="compute(false)"><option value="exact">Exact</option><option value="floor">Floor excess kg</option><option value="ceil">Ceiling excess kg</option></select></label><label>PSN / Reference<input id="calcPsn" placeholder="Optional" value="${esc(state.lastCalc?.psn||'')}"></label></div><div class="calcActions"><button class="primary" onclick="compute(true)">Compute Baggage Estimate</button><button class="accent" onclick="cashierAdjust()">Smart Adjustment</button><button onclick="saveTransaction()">Save Estimate</button><button onclick="copyCalcQuote()">Copy Estimate</button></div></div><div class="card span7"><div class="cardHead"><div><h3>Detailed Baggage Computation</h3><p>Allowance, excess weight, tiers, and passenger multiplication are shown step-by-step.</p></div><span class="badge ok">Always visible</span></div><div id="resultCard"><div class="v68EstimateHero"><div class="amount" id="totalDisplay">₱0.00</div><div id="perPaxDisplay" class="sub">Enter details to calculate the baggage estimate.</div></div><div class="v68MathBox" id="stepsDisplay"></div></div></div><div class="card span7"><div class="cardHead"><div><h3>Baggage Fee Estimate Receipt</h3><p>Receipt contains baggage estimate details only.</p></div></div><div class="v68Receipt" id="receipt"></div></div><div class="card span5"><div class="cardHead"><div><h3>Route / Trip Information</h3><p>Trip status appears here when linked.</p></div></div><div id="routeTripBox"></div></div><div class="card span12"><div class="cardHead"><div><h3>Recent Baggage Estimates</h3><p>Saved on this device only.</p></div><button class="small" onclick="clearTransactions()">Clear estimates</button></div><div id="txnList"></div></div></div>`;
  $('calcRoute').value=current;v67ToggleMode();compute(false);renderTransactions();
}
function saveTransaction(){const d=compute(false);d.psn=($('calcPsn')?.value||'').trim();d.clsLabel=d.cls==='business'?'Business':'Tourist';d.grand=d.baggage;state.data.transactions.unshift(d);state.data.transactions=state.data.transactions.slice(0,200);audit('Baggage estimate saved',`${d.routeLabel} ${d.tripCode?d.tripCode+' ':''}${v67Money(d.baggage)}`);save();renderTransactions();toast('Baggage estimate saved')}
function copyCalcQuote(){const d=v67LastCalc||compute(false);const trip=d.tripCode?`\nTrip: ${d.tripCode}\nVessel: ${d.vessel||'-'}\nGate: ${d.gate||'-'}\nDeparture: ${d.departureTime||'-'}`:'';const text=`OceanJet Baggage Estimate${trip}\n${d.routeLabel}\nMode: ${d.mode}\nClass: ${d.cls}\nPassengers: ${d.pax}\nTotal Weight: ${d.kg}kg\nFree Allowance: ${d.freeTotal.toFixed(1)}kg\nChargeable Excess: ${d.excess.toFixed(1)}kg\nPer Passenger Baggage: ${v67Money(d.perPax)}\nBaggage Total: ${v67Money(d.baggage)}`;navigator.clipboard?.writeText(text);toast('Estimate copied')}
function renderTransactions(){const box=$('txnList');if(!box)return;const rows=state.data.transactions.slice(0,12);box.innerHTML=rows.length?`<div class="tableWrap"><table><thead><tr><th>Time</th><th>Trip</th><th>Route</th><th>Mode/Class</th><th>KG</th><th>Baggage Estimate</th><th></th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.time)}</td><td>${x.tripCode?`<b>${esc(x.tripCode)}</b><br><span class="tiny">${esc(x.vessel||'')}</span>`:'-'}</td><td>${esc(x.routeLabel)}</td><td>${esc((x.mode||x.type||'normal')+' / '+(x.clsLabel||x.cls||''))}</td><td>${Number(x.kg||x.weight||0).toFixed(1)}</td><td>${v67Money(x.baggage||x.grand||0)}</td><td><button class="small" onclick="makeReceiptFromTxn('${x.id}')">View</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No baggage estimates yet.</div>'}
function makeReceiptFromTxn(id){const x=state.data.transactions.find(a=>a.id===id);if(!x){toast('Estimate not found');return}const amount=Number(x.baggage||x.grand||0);state.data.receipts.unshift({id:uid('receipt'),time:today(),psn:x.psn||'',name:'',route:x.route,routeLabel:x.routeLabel,amount,tripCode:x.tripCode||'',vessel:x.vessel||'',gate:x.gate||'',departureTime:x.departureTime||'',notes:`Baggage estimate only: ${Number(x.kg||x.weight||0).toFixed(1)}kg, ${x.pax||1} pax, per passenger ${peso(x.perPax||0)}`});audit('Baggage estimate receipt created',`${x.tripCode||x.routeLabel} ${peso(amount)}`);save();toast('Baggage receipt created');renderApp('receipt')}
function printReceipt(id){const x=state.data.receipts.find(a=>a.id===id);if(!x)return;modal(`<div class="modalHead"><h3>Baggage Estimate Receipt</h3><button class="small" onclick="closeModal()">✕</button></div><div class="printArea"><h2>OceanJet</h2><h3>Baggage Estimate Receipt</h3><p><b>Date:</b> ${esc(x.time)}<br>${x.tripCode?`<b>Trip:</b> ${esc(x.tripCode)} · ${esc(x.vessel||'')}<br><b>Gate/Departure:</b> ${esc(x.gate||'-')} · ${esc(x.departureTime||'-')}<br>`:''}<b>Ref:</b> ${esc(x.psn||x.id)}<br><b>Route:</b> ${esc(x.routeLabel)}<br><b>Baggage Total:</b> ${peso(x.amount)}</p><p>${esc(x.notes||'')}</p><hr><p>Prepared via PortDesk baggage estimate.</p></div><button class="primary block noPrint" style="margin-top:10px" onclick="window.print()">Print</button>`)}

function claim(){setTitle('Passenger Claim','Start report with trip link');$('content').innerHTML=hero('Passenger Claim Form','Create the passenger report first. Link a trip when known so evidence and review records carry vessel details.','Passenger')+`<div class="grid"><div class="card span7"><div class="formGrid"><label>PSN <span class="fieldHelp">Required</span><input id="claimPsn" placeholder="Passenger PSN" oninput="showClaimDuplicates();scheduleClaimDraft()"></label><label>Last Name <span class="fieldHelp">Required</span><input id="claimLast" placeholder="Last name" oninput="showClaimDuplicates();scheduleClaimDraft()"></label>${v72TripWorkflowSelect('claimTrip','claimRoute','')}<label>Route<select id="claimRoute" onchange="scheduleClaimDraft()">${routeOptions('cebu_maasin')}</select></label><label>Issue Type<select id="claimType" onchange="scheduleClaimDraft()">${damageTypeOptions('Scratch/Scuff')}</select></label><label>Contact / Mobile<input id="claimContact" placeholder="Optional phone or Messenger name" oninput="scheduleClaimDraft()"></label><label>Item / Bag Description<input id="claimItem" placeholder="e.g. white luggage, medium, no hang tag" oninput="scheduleClaimDraft()"></label><label style="grid-column:1/-1">Description<textarea id="claimDesc" placeholder="Describe issue, location of damage, missing accessory, item color/size, etc." oninput="scheduleClaimDraft()"></textarea></label></div><button class="primary block" style="margin-top:12px" onclick="saveClaim()">Submit Claim</button></div><div class="card span5"><h3>Intake Guard</h3><div id="claimDupBox" class="notice" style="margin:10px 0">Enter PSN and Last Name to check possible duplicate records.</div><ol><li>Check duplicate first.</li><li>Link the trip if known.</li><li>Submit claim.</li><li>Staff captures stub + damage pair.</li></ol><button class="small" onclick="renderApp('board')">Open Port Operations</button></div></div>`;wireClaimAutomation();restoreClaimDraft();showClaimDuplicates()}
function saveClaim(){const psn=$('claimPsn').value.trim(),last=$('claimLast').value.trim();if(!psn||!last){toast('PSN and Last Name required');return}const same=state.data.claims.filter(c=>String(c.psn).toLowerCase()===psn.toLowerCase()&&String(c.last).toLowerCase()===last.toLowerCase()&&!['Done','Rejected'].includes(c.status||''));if(same.length&&!confirm('Possible duplicate open claim found for this PSN + Last Name. Continue saving new claim?'))return;const route=$('claimRoute').value, trip=v72SelectedTrip($('claimTrip')?.value||'');const item={id:uid('claim'),time:today(),psn,last,route,routeLabel:ROUTES[route].label,type:$('claimType').value,contact:$('claimContact').value.trim(),item:$('claimItem').value.trim(),desc:$('claimDesc').value.trim(),status:'Open'};if(trip)Object.assign(item,{tripId:trip.id,tripCode:trip.code,vessel:trip.vessel,gate:trip.gate,departureTime:trip.departureTime,tripStatus:trip.status});state.data.claims.unshift(item);state.data.drafts.claim=null;audit('Claim created',`${psn} ${last}${trip?' · '+trip.code:''}`);save();modal(`<div class="modalHead"><h3>Claim Saved</h3><button class="small" onclick="closeModal();renderApp('track')">✕</button></div><div class="printArea"><h2>OceanJet Claim Acknowledgment</h2><p><b>Claim ID:</b> ${esc(item.id)}<br><b>PSN:</b> ${esc(item.psn)}<br><b>Last Name:</b> ${esc(item.last)}<br>${item.tripCode?`<b>Trip:</b> ${esc(item.tripCode)} · ${esc(item.vessel||'')}<br>`:''}<b>Route:</b> ${esc(item.routeLabel)}<br><b>Issue:</b> ${esc(item.type)}<br><b>Status:</b> Open</p><p>Please keep your claim stub. Staff will match evidence using PSN + Last Name.</p></div><div class="v63SplitActions noPrint"><button class="primary" onclick="copyText(claimAckText(state.data.claims.find(x=>x.id==='${item.id}')),'Acknowledgment copied')">Copy Acknowledgment</button><button onclick="window.print()">Print</button><button onclick="closeModal();renderApp('damage')">Go to Evidence</button></div>`);toast('Claim saved')}
const v72BaseClaimAckText = claimAckText;
claimAckText = function(x){const base=v72BaseClaimAckText(x);return x?.tripCode?base.replace('Route:',`Trip: ${x.tripCode} / ${x.vessel||'-'}\nGate/Departure: ${x.gate||'-'} / ${x.departureTime||'-'}\nRoute:`):base}

const v72BaseDamage = damage;
damage = function(){v72BaseDamage();const routeLabel=$('dRoute')?.closest('label');if(routeLabel&&!$('dTrip')){routeLabel.insertAdjacentHTML('beforebegin',v72TripWorkflowSelect('dTrip','dRoute',''))}renderClaimMatch()}
const v72BaseRenderClaimMatch = renderClaimMatch;
renderClaimMatch = function(){v72BaseRenderClaimMatch();const box=$('claimMatchBox');const m=findMatchingClaim();if(box&&m?.tripCode){box.innerHTML += `<br><span class="tiny">Linked trip: ${esc(m.tripCode)} · ${esc(m.vessel||'')} · ${esc(m.departureTime||'')}</span>`}}
function saveEvidenceObject(photos,batchNo,skipToast){const route=$('dRoute').value;const match=findMatchingClaim();const trip=v72SelectedTrip($('dTrip')?.value||'')||v72SelectedTrip(match?.tripId||'');const item={id:uid('case'),time:today(),psn:$('dPsn').value.trim(),last:$('dLast').value.trim(),route,routeLabel:ROUTES[route].label,type:$('dType').value,color:$('dColor').value.trim(),size:$('dSize').value.trim(),notes:$('dNotes').value.trim(),batchNo,status:'Review',claimId:match?.id||'',photos:{stub:photos.stub,damage:photos.damage}};if(trip)Object.assign(item,{tripId:trip.id,tripCode:trip.code,vessel:trip.vessel,gate:trip.gate,departureTime:trip.departureTime,tripStatus:trip.status});item.score=evidenceScore(item);if(autoOn('statusSuggest'))item.suggestion=suggestEvidenceStatus(item);state.data.cases.unshift(item);state.data.cases=state.data.cases.slice(0,150);if(match){match.status='Evidence Received';match.evidenceId=item.id;audit('Claim linked to evidence',`${item.psn} ${item.last}${trip?' · '+trip.code:''}`)}if(autoOn('statusSuggest'))autoAudit('Automation: status suggested',item.psn+' → '+item.suggestion,'statusSuggest');audit('Evidence uploaded',`${item.psn} ${item.last} score ${item.score}%${item.tripCode?' · '+item.tripCode:''}`);save();if(!skipToast)toast(match?'Evidence saved and claim linked':'Evidence saved')}

function renderQueue(){const q=($('queueQ')?.value||'').toLowerCase().trim(),status=$('queueStatus')?.value||'';let rows=state.data.cases;if(status)rows=rows.filter(x=>x.status===status);if(q)rows=rows.filter(x=>(x.psn+' '+x.last+' '+x.routeLabel+' '+x.type+' '+(x.color||'')+' '+(x.size||'')+' '+(x.tripCode||'')+' '+(x.vessel||'')).toLowerCase().includes(q));$('queueTable').innerHTML=rows.length?`<div class="tableWrap"><table><thead><tr><th>Priority</th><th>Time</th><th>Passenger</th><th>Trip</th><th>Route</th><th>Type</th><th>Score</th><th>Status</th><th>Action</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${priorityBadge(x)}</td><td>${esc(x.time)}</td><td><b>${esc(x.psn)}</b><br>${esc(x.last)}${x.claimId?'<br><span class="tiny">Claim linked</span>':''}</td><td><div class="v72QueueTrip">${x.tripCode?`<b>${esc(x.tripCode)}</b><small>${esc(x.vessel||'')}</small><small>${esc(x.departureTime||'')}</small>`:'-'}</div></td><td>${esc(x.routeLabel)}</td><td>${esc(x.type)}<br><span class="tiny">${esc(x.suggestion||'-')}</span></td><td>${x.score}%</td><td>${statusChip(x.status)}</td><td><select onchange="updateCaseStatus('${x.id}',this.value)"><option ${x.status==='Review'?'selected':''}>Review</option><option ${x.status==='Open'?'selected':''}>Open</option><option ${x.status==='Done'?'selected':''}>Done</option><option ${x.status==='Rejected'?'selected':''}>Rejected</option></select><div class="miniActions"><button class="small" onclick="openCase('${x.id}')">Open</button><button class="small" onclick="copyCaseSummary('${x.id}')">Copy</button><button class="small" onclick="copyPassengerUpdate('${x.id}')">Msg</button><button class="small danger" onclick="deleteCase('${x.id}')">Delete</button></div></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No cases found.</div>'}
const v72BaseOpenCase = openCase;
openCase = function(id){v72BaseOpenCase(id);const x=state.data.cases.find(c=>c.id===id);if(x?.tripCode){const pa=document.querySelector('.printArea');if(pa)pa.insertAdjacentHTML('beforeend',`<p><b>Trip:</b> ${esc(x.tripCode)} · ${esc(x.vessel||'')}<br><b>Gate/Departure:</b> ${esc(x.gate||'-')} · ${esc(x.departureTime||'-')}</p>`)} }
function updateCaseStatus(id,status){const x=state.data.cases.find(c=>c.id===id);if(!x)return;x.status=status;audit('Claim reviewed',`${x.psn} ${x.last} → ${status}${x.tripCode?' · '+x.tripCode:''}`);save();renderQueue();renderCaseList();toast('Status updated')}

function dashboard(){ensureData();setTitle(state.role==='admin'?'Admin Command Center':state.role==='cashier'?'Cashier Counter':'Passenger Hub','PortDesk V73 operations workflow');const c=state.data.cases.length,cl=state.data.claims.length,openCases=state.data.cases.filter(x=>!['Done','Rejected'].includes(x.status||'')).length,openClaims=state.data.claims.filter(x=>!['Done','Rejected'].includes(x.status||'')).length,estimates=state.data.transactions.length;const summary=v71TripSummary(),next=summary.next;const actions=state.role==='passenger'?[['trips','🕐','Trips & Boarding','View vessel status and boarding time'],['claim','📝','Start Claim','Report baggage damage or issue'],['track','🔎','Track Claim','Search local claim status'],['calculator','🧮','Baggage Estimate','Estimate baggage fee only']]:state.role==='cashier'?[['board','🛳️','Port Operations','Monitor boarding and trips'],['calculator','🧮','Baggage Estimate','Compute and save estimate'],['damage','📸','Evidence Studio','Pair claim stub + damage image'],['queue','👥','Review Queue','Update claim/evidence status']]:[['board','🛳️','Port Operations','Full vessel and boarding control'],['queue','👥','Review Queue','Manage all cases'],['reports','📊','Reports','Export backup and CSV'],['system','⚙️','System Tools','Shift, cache, credentials']];$('content').innerHTML=hero(state.role==='admin'?'Admin Command Center':state.role==='cashier'?'Cashier Counter':'Passenger Hub','Professional role-based workspace with vessel boarding, baggage estimate, claim review, and manual evidence workflows.','PortDesk')+`<div class="opsHero">${v71NowBoardingPanel(summary)}${v71OpsSummaryCards(summary)}</div><div class="grid"><div class="card span12"><div class="cardHead"><div><h3>Today\'s Operations Snapshot</h3><p>Grouped trip status for fast mobile review.</p></div><button class="small" onclick="renderApp('board')">Open Port Operations</button></div>${v72StatusLanes()}</div><div class="card span3 kpi"><span class="muted">Trips Today</span><b>${state.data.trips.length}</b><span class="tiny">${summary.nowBoarding.length} boarding now</span></div><div class="card span3 kpi"><span class="muted">Next Trip</span><b>${next?esc(next.trip.code):'-'}</b><span class="tiny">${next?v71DisplayTime(next.trip.time):'No schedule'}</span></div><div class="card span3 kpi"><span class="muted">Open Claims</span><b>${openClaims}</b><span class="tiny">${cl} total reports</span></div><div class="card span3 kpi"><span class="muted">Evidence Queue</span><b>${openCases}</b><span class="tiny">${c} evidence cases</span></div><div class="card span12"><div class="cardHead"><div><h3>Workspace Shortcuts</h3><p>Only tools for the active role are shown. Admin has full control.</p></div><span class="badge ok">Operations V73</span></div><div class="quick">${actions.map(a=>`<button onclick="renderApp('${a[0]}')"><span class="ico">${a[1]}</span><b>${a[2]}</b><span class="tiny">${a[3]}</span></button>`).join('')}</div></div><div class="card span7"><div class="cardHead"><div><h3>Connected Port Flow</h3><p>Trip code can travel with baggage estimates, claims, evidence, and queue review.</p></div></div><div class="opSteps"><div class="opStep"><b>1. Vessel</b><span>Confirm boarding/departure status.</span></div><div class="opStep"><b>2. Counter</b><span>Link trip in baggage estimate if known.</span></div><div class="opStep"><b>3. Claim</b><span>Use PSN + Last Name and optional trip link.</span></div><div class="opStep"><b>4. Handover</b><span>Export daily packet and audit trail.</span></div></div></div><div class="card span5"><div class="cardHead"><div><h3>Local Workload</h3><p>Device-local records.</p></div><span class="badge ${summary.delayed?'warn':'ok'}">${summary.delayed?summary.delayed+' delayed':'Normal'}</span></div><div class="compactList"><div class="compactRow"><span>Baggage estimates</span><b>${estimates}</b></div><div class="compactRow"><span>Closed / departed trips</span><b>${summary.closed+summary.departed}</b></div><div class="compactRow"><span>Cancelled trips</span><b>${summary.cancelled}</b></div><div class="compactRow"><span>Port</span><b>${esc(state.data.shift.port||'Cebu')}</b></div></div></div></div>`}

function downloadJSON(){state.data.automation.lastBackup=today();audit('Backup export','JSON');save();download('OceanJet_PortDesk_V73_Backup_'+Date.now()+'.json',JSON.stringify({version:APP_VERSION,exportedAt:new Date().toISOString(),data:state.data},null,2),'application/json');toast('Backup downloaded')}
function downloadAuditCSV(){download('OceanJet_PortDesk_V73_Audit_'+Date.now()+'.csv',csv(state.data.audit),'text/csv');audit('Audit CSV export','V73 audit log');save();toast('Audit CSV downloaded')}
function downloadDailyPacket(){const summary=v71TripSummary();const tripLines=[...state.data.trips].sort(v71TripCodeSort).map(t=>{const info=v71TripStatus(t);return `- ${t.code} / ${t.vessel||'-'} / ${t.routeLabel||v71RouteLabel(t.route)} / ${t.gate||'-'} / Boarding ${v71DisplayTimeFromDate(info.boarding)} / Departure ${v71DisplayTime(t.time)} / ${info.status}`}).join('\n');const txt=`OceanJet V73 Daily Packet\nDate: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nTrips today: ${state.data.trips.length}\nNow boarding: ${summary.nowBoarding.length}\nDeparted: ${summary.departed}\nDelayed: ${summary.delayed}\nClosed: ${summary.closed}\nCancelled: ${summary.cancelled}\nClaims: ${state.data.claims.length}\nEvidence cases: ${state.data.cases.length}\nBaggage estimates: ${state.data.transactions.length}\n\nTrip Board:\n${tripLines||'-'}\n\nLatest Audit:\n${state.data.audit.slice(0,25).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail}`).join('\n')}`;audit('Daily packet export','V73 operations packet');save();download('OceanJet_PortDesk_V73_Daily_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Daily packet downloaded')}
openQuickHelp = function(){modal(`<div class="modalHead"><h3>V73 Port Operations Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>V72 expands the Vessel Board with status lanes, richer dashboard cards, safe delete controls, and departure-grace editing.</li><li>Baggage Estimate can link to a trip/vessel while keeping the receipt baggage-only.</li><li>Claim Intake and Damage Evidence can link to a trip, then Review Queue shows the trip code/vessel when available.</li><li>Boarding logic remains staff-controlled: Scheduled, Boarding, Departing Soon, Departed, Delayed, Cancelled, and Closed are visible and logged.</li><li>Damage Evidence Studio remains manual-only with claim-stub + damage-image pairing.</li><li>No recovery system, blank-screen watcher, scanner loop, auto-capture, DOM observer, interval UI repair, or navigation auto-fixer is added.</li></ul>`)}

const v72BaseSelectCalcRoute = typeof selectCalcRoute==='function'?selectCalcRoute:null;
selectCalcRoute = function(route){if($('calcTrip')){$('calcTrip').value=''};if(v72BaseSelectCalcRoute){return v72BaseSelectCalcRoute(route)}const el=$('calcRoute');if(el&&ROUTES[route]){el.value=route;compute(false);if(typeof v68RefreshRouteButtons==='function')v68RefreshRouteButtons()}};
function verifyCoreFunctions(){const missing=['imgFileToDataURL','uploadSingle','batchEvidence','clearOldCache','settlement','quality','lookup','handover','downloadCompactJSON','intake','board','downloadDailyPacket','setActiveRole','selectCalcRoute','v71AddTrip','v71SetTripStatus','v72AddTrip','v72TripOptions'].filter(k=>typeof window[k]!=='function');if(missing.length){console.warn('V72 missing functions:',missing.join(', '));}else{console.info('OceanJet V72 core functions OK')}}



/* ======================================================================
   V73 OPERATIONS COMMAND REBUILD
   Event-driven improvements only. Staff controls confirm important changes.
   ====================================================================== */
const V73_BOARDING_DEFAULT_MIN = 15;
const V73_CLOSE_BEFORE_MIN = 3;
const V73_DEPART_GRACE_MIN = 10;
const V73_MAIN_ROUTES = ['cebu_maasin','cebu_surigao','cebu_tagbilaran','cebu_dumaguete','cebu_siquijor','cebu_ormoc','cebu_getafe','cebu_palompon'];
const V73_READINESS_KEYS = [
  ['gate','Gate signage ready'],
  ['counter','Counter / manifest checked'],
  ['baggage','Baggage estimate desk ready'],
  ['evidence','Evidence desk ready'],
  ['announcement','Boarding announcement made']
];

NAVS.passenger = [['dashboard','🏠','Home'],['trips','🕐','Trips'],['claim','📝','Claim'],['track','🔎','Track'],['calculator','🧮','Estimate']];
NAVS.cashier = [['dashboard','🏠','Counter'],['board','🛳️','Port Ops'],['calculator','🧮','Baggage'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['trips','🕐','Trips']];
NAVS.admin = [['dashboard','🏠','Command'],['board','🛳️','Port Ops'],['queue','👥','Queue'],['damage','📸','Evidence'],['calculator','🧮','Baggage'],['reports','📊','Reports'],['system','⚙️','System'],['automation','🤖','Automation'],['trips','🕐','Trips']];

const v73BaseEnsureData = ensureData;
ensureData = function(){
  v73BaseEnsureData();
  state.data.trips ||= [];
  state.data.tripHistory ||= [];
  state.data.opsSettings = {boardingMinutes:V73_BOARDING_DEFAULT_MIN, closeBeforeMinutes:V73_CLOSE_BEFORE_MIN, departGraceMinutes:V73_DEPART_GRACE_MIN, ...(state.data.opsSettings||{})};
  state.data.readiness ||= {};
  const d=v71YMD();
  state.data.readiness[d] ||= {};
  V73_READINESS_KEYS.forEach(x=>{state.data.readiness[d][x[0]] ??= false});
  if(!state.data.trips.length && typeof v71SeedTrips==='function') v71SeedTrips(false);
};

function v73Settings(){ensureData();return state.data.opsSettings||{boardingMinutes:V73_BOARDING_DEFAULT_MIN, closeBeforeMinutes:V73_CLOSE_BEFORE_MIN, departGraceMinutes:V73_DEPART_GRACE_MIN}}
function v73TodayReadiness(){ensureData();return state.data.readiness[v71YMD()]||{}}
function v73TripDateTime(t){return v71TripDeparture(t)}
function v73MinutesUntil(date){return Math.round((date.getTime()-Date.now())/60000)}
function v73TripInfo(t){
  const s=v73Settings();
  const dep=v73TripDateTime(t);
  const boarding=v71AddMinutes(dep,-(Number(t.boardingMins)||s.boardingMinutes||V73_BOARDING_DEFAULT_MIN));
  const close=v71AddMinutes(dep,-(s.closeBeforeMinutes||V73_CLOSE_BEFORE_MIN));
  const departed=v71AddMinutes(dep,Number(t.departGraceMins)||s.departGraceMinutes||V73_DEPART_GRACE_MIN);
  const now=new Date();
  let suggested='Scheduled', message='Trip is scheduled. Prepare counter, gate, and baggage desk.';
  if(now>=departed){suggested='Departed'; message='Departure grace period has passed. Confirm departure if vessel already left.';}
  else if(now>=close){suggested='Departing Soon'; message='Boarding should be closing. Check manifest and gate before departure.';}
  else if(now>=boarding){suggested='Boarding'; message='Trip is inside boarding window. Open boarding if gate is ready.';}
  const manual=t.manualStatus||'';
  const status=manual||suggested;
  const total=Math.max(1, departed.getTime()-boarding.getTime());
  const pct=Math.max(0, Math.min(100, ((now.getTime()-boarding.getTime())/total)*100));
  return {status,suggested,manual:!!manual,message,dep,boarding,close,departed,pct,mins:v73MinutesUntil(dep)};
}
function v73StatusClass(status){return v71StatusClass(status)}
function v73StatusBadge(status){return v71StatusBadge(status)}
function v73ActiveTrips(){ensureData();return state.data.trips.filter(t=>!['Cancelled','Departed'].includes(v73TripInfo(t).status)).sort(v71TripCodeSort)}
function v73TripOptionList(selected){
  const rows=[...state.data.trips].sort(v71TripCodeSort);
  return '<option value="">No trip selected</option>'+rows.map(t=>{const info=v73TripInfo(t);return `<option value="${esc(t.id)}" ${selected===t.id?'selected':''}>${esc(t.code)} · ${esc(t.vessel||'Vessel')} · ${esc(t.routeLabel||v71RouteLabel(t.route))} · ${v71DisplayTime(t.time)} · ${esc(info.status)}</option>`}).join('');
}
function v73TripById(id){ensureData();return state.data.trips.find(t=>t.id===id)||null}
function v73TripLine(t){return t?`${t.code} / ${t.vessel||'-'} / ${t.routeLabel||v71RouteLabel(t.route)} / ${v71DisplayTime(t.time)}`:'No trip'}
function v73Summary(){
  ensureData();
  const rows=state.data.trips.map(t=>({trip:t,info:v73TripInfo(t)})).sort((a,b)=>a.info.dep-b.info.dep);
  const byStatus={Scheduled:[],Boarding:[],Soon:[],Departed:[],Delayed:[],Cancelled:[],Closed:[]};
  rows.forEach(r=>{if(r.info.status==='Departing Soon')byStatus.Soon.push(r);else if(byStatus[r.info.status])byStatus[r.info.status].push(r)});
  const active=rows.filter(r=>!['Cancelled','Departed','Closed'].includes(r.info.status));
  const nowBoarding=rows.filter(r=>['Boarding','Departing Soon'].includes(r.info.status));
  const next=active[0]||rows.find(r=>r.info.dep>=new Date())||null;
  const readiness=v73TodayReadiness();
  const readyCount=V73_READINESS_KEYS.filter(x=>readiness[x[0]]).length;
  return {rows,byStatus,active,nowBoarding,next,total:rows.length,departed:byStatus.Departed.length,delayed:byStatus.Delayed.length,cancelled:byStatus.Cancelled.length,closed:byStatus.Closed.length,scheduled:byStatus.Scheduled.length,soon:byStatus.Soon.length,readiness,readyCount};
}
function v73NowPanel(summary){
  const item=summary.nowBoarding[0]||summary.next;
  if(!item) return `<div class="opsNow"><span class="statusPill statusScheduled">No trips</span><h2>No vessel scheduled</h2><p>Add today\'s trips in Port Operations.</p></div>`;
  const t=item.trip, info=item.info;
  return `<div class="opsNow v73CommandNow"><div class="v73NowTop"><span class="statusPill ${v73StatusClass(info.status)}">${v71StatusIcon(info.status)} ${esc(info.status)}</span><span class="tiny">Last updated ${esc(t.updatedAt||'-')}</span></div><h2>${info.status==='Boarding'||info.status==='Departing Soon'?'Now Boarding':'Next Vessel'}: ${esc(t.code)}</h2><p class="vesselName">${esc(t.vessel||'OceanJet Vessel')}</p><div class="bigTime">Departure ${v71DisplayTime(t.time)} · Boarding ${v71DisplayTimeFromDate(info.boarding)}</div><p>${esc(t.routeLabel||v71RouteLabel(t.route))} · ${esc(t.gate||'Gate TBA')}</p><div class="v73TimeStrip"><span>${info.mins>0?info.mins+' min to departure':Math.abs(info.mins)+' min after departure'}</span><span>Close gate ${v71DisplayTimeFromDate(info.close)}</span><span>Grace ${v71DisplayTimeFromDate(info.departed)}</span></div>${v71TripTimeline(info)}</div>`;
}
function v73KpiCards(summary){
  const openClaims=state.data.claims.filter(x=>!['Done','Rejected'].includes(x.status||'')).length;
  const evidence=state.data.cases.filter(x=>!['Done','Rejected'].includes(x.status||'')).length;
  const estimates=state.data.transactions.length;
  const next=summary.next;
  return `<div class="v73Kpis"><div class="opsMini"><span>Now Boarding</span><b>${summary.nowBoarding.length}</b><small>${summary.nowBoarding[0]?.trip.code||'No active gate'}</small></div><div class="opsMini"><span>Next Departure</span><b>${next?esc(next.trip.code):'-'}</b><small>${next?v71DisplayTime(next.trip.time):'No schedule'}</small></div><div class="opsMini"><span>Trips Today</span><b>${summary.total}</b><small>${summary.departed} departed · ${summary.closed} closed</small></div><div class="opsMini"><span>Issues Queue</span><b>${openClaims+evidence}</b><small>${openClaims} claims · ${evidence} evidence</small></div><div class="opsMini"><span>Exceptions</span><b>${summary.delayed+summary.cancelled}</b><small>${summary.delayed} delayed · ${summary.cancelled} cancelled</small></div><div class="opsMini"><span>Readiness</span><b>${summary.readyCount}/${V73_READINESS_KEYS.length}</b><small>${estimates} baggage estimates</small></div></div>`;
}
function v73MiniTrip(r){
  const t=r.trip, info=r.info;
  return `<button type="button" class="v73MiniTrip" onclick="v73FocusTrip('${t.id}')"><b>${esc(t.code)}</b><span>${esc(t.routeLabel||v71RouteLabel(t.route))}</span><small>${esc(t.vessel||'-')} · ${v71DisplayTime(t.time)} · ${esc(t.gate||'TBA')}</small></button>`;
}
function v73StatusLanes(summary){
  const lanes=[['Boarding','Boarding',summary.byStatus.Boarding.concat(summary.byStatus.Soon)],['Next','Scheduled',summary.byStatus.Scheduled.slice(0,4)],['Delayed','Delayed',summary.byStatus.Delayed],['Cancelled','Cancelled',summary.byStatus.Cancelled],['Departed','Departed',summary.byStatus.Departed],['Closed','Closed',summary.byStatus.Closed]];
  return `<div class="v73Lanes">${lanes.map(([title,status,rows])=>`<div class="v73Lane"><div class="v73LaneHead">${v73StatusBadge(status)}<b>${rows.length}</b></div><h3>${title}</h3><div class="v73LaneRows">${rows.length?rows.map(v73MiniTrip).join(''):'<div class="tiny">No trips in this lane.</div>'}</div></div>`).join('')}</div>`;
}
function v73ReadinessCard(){
  const ready=v73TodayReadiness();
  return `<div class="card span5"><div class="cardHead"><div><h3>Port Readiness</h3><p>Simple checklist for the current day. It does not run in the background.</p></div><span class="badge ok">Manual</span></div><div class="v73CheckList">${V73_READINESS_KEYS.map(x=>`<label class="v73Check"><input type="checkbox" ${ready[x[0]]?'checked':''} onchange="v73ToggleReadiness('${x[0]}',this.checked)"><span>${esc(x[1])}</span></label>`).join('')}</div><div class="miniActions"><button class="small" onclick="v73ResetReadiness()">Reset Checklist</button><button class="small" onclick="downloadDailyPacket()">Daily Packet</button></div></div>`;
}
function v73OpsPolicyCard(){
  const s=v73Settings();
  return `<div class="card span7"><div class="cardHead"><div><h3>Boarding Logic</h3><p>Suggestions are calculated only when staff opens or refreshes the board.</p></div><span class="badge ok">Staff-confirmed</span></div><div class="formGrid"><label>Boarding starts<input id="v73BoardingMin" type="number" min="5" max="30" value="${Number(s.boardingMinutes)||15}"><small class="tiny">minutes before departure</small></label><label>Gate closes<input id="v73CloseMin" type="number" min="0" max="15" value="${Number(s.closeBeforeMinutes)||3}"><small class="tiny">minutes before departure</small></label><label>Departed grace<input id="v73GraceMin" type="number" min="0" max="30" value="${Number(s.departGraceMinutes)||10}"><small class="tiny">minutes after departure</small></label><label>Port label<input id="v73PortLabel" value="${esc(state.data.shift.port||'Cebu Pier 1')}"></label></div><div class="miniActions"><button class="primary small" onclick="v73SaveOpsSettings()">Save Logic</button><button class="small" onclick="board()">Refresh Board</button></div><div class="opSteps" style="margin-top:12px"><div class="opStep"><b>Scheduled</b><span>Before boarding window.</span></div><div class="opStep"><b>Boarding</b><span>Inside boarding window, before gate close.</span></div><div class="opStep"><b>Departing Soon</b><span>Gate close window through departure grace.</span></div><div class="opStep"><b>Departed</b><span>After grace period; staff can still override.</span></div></div></div>`;
}
function v73ToggleReadiness(key,val){ensureData();state.data.readiness[v71YMD()][key]=!!val;audit('Readiness updated',`${key}: ${val?'ready':'not ready'}`);save();toast('Readiness updated')}
function v73ResetReadiness(){if(!confirm('Reset today\'s port readiness checklist?'))return;state.data.readiness[v71YMD()]={};V73_READINESS_KEYS.forEach(x=>state.data.readiness[v71YMD()][x[0]]=false);audit('Readiness reset','Today checklist');save();board()}
function v73SaveOpsSettings(){const s=v73Settings();s.boardingMinutes=Math.max(5,Math.min(30,Number($('v73BoardingMin').value)||15));s.closeBeforeMinutes=Math.max(0,Math.min(15,Number($('v73CloseMin').value)||3));s.departGraceMinutes=Math.max(0,Math.min(30,Number($('v73GraceMin').value)||10));state.data.shift.port=$('v73PortLabel').value.trim()||state.data.shift.port||'Cebu';audit('Boarding policy updated',`${s.boardingMinutes}/${s.closeBeforeMinutes}/${s.departGraceMinutes} minutes`);save();toast('Boarding logic saved');board()}
