function v75Risks(t){
  const i=v75TripInfo(t), ops=t.ops||{}, risks=[];
  if(!t.vessel || /Vessel$/i.test(t.vessel)) risks.push('Confirm vessel name');
  if(!t.gate || /TBA/i.test(t.gate)) risks.push('Gate not assigned');
  if(i.suggested==='Boarding' && !t.manualStatus) risks.push('Boarding window active');
  if(i.suggested==='Departed' && !t.manualStatus) risks.push('Departure confirmation needed');
  if(Number(ops.booked)>Number(ops.capacity||0) && Number(ops.capacity)>0) risks.push('Booked over capacity');
  if(i.status==='Boarding' && Number(ops.checkedIn||0)<Math.ceil(Number(ops.booked||0)*0.5)) risks.push('Low check-in count');
  if(i.status==='Delayed' && !ops.delayReason) risks.push('Delay reason missing');
  const ready=v75Readiness(), readyCount=V75_CHECKS.filter(x=>ready[x[0]]).length;
  if(['Boarding','Departing Soon'].includes(i.status) && readyCount<V75_CHECKS.length) risks.push('Readiness incomplete');
  return risks;
}
