const V77_CALC_ROUTES = ['cebu_tagbilaran','cebu_maasin','cebu_surigao','cebu_siquijor','cebu_dumaguete','cebu_ormoc','cebu_palompon','cebu_getafe'];
const V77_CLASS_ALLOWANCE = {tourist:10,business:20};
let v76ReceiptText = '';
function v76Money(n){return (typeof peso==='function'?peso(n):('₱'+Number(n||0).toFixed(2)))}
function v76RouteLabel(route){return V69_ROUTE_META?.[route]?.title || ROUTES?.[route]?.label || String(route||'').replace(/_/g,' → ')}
function v76RouteOptions(selected){return V77_CALC_ROUTES.filter(r=>ROUTES[r]).map(r=>`<option value="${r}" ${selected===r?'selected':''}>${esc(v76RouteLabel(r))}</option>`).join('')}
function v76ClassLabel(cls){return cls==='business'?'Business Class':'Tourist / Open Air'}
function v76RouteNote(route){return V69_ROUTE_META?.[route]?.note || ROUTES?.[route]?.travel || ''}
