function v76SelectedTrip(){
  const id = $('calcTripLink')?.value || $('calcTrip')?.value || state?.lastCalc?.tripId || '';
  if(!id) return null;
  if(typeof v72SelectedTrip==='function') return v72SelectedTrip(id);
  if(typeof v73TripById==='function'){
    const t=v73TripById(id); if(!t) return null;
    return {id:t.id,code:t.code,vessel:t.vessel,route:t.route,routeLabel:t.routeLabel||v71RouteLabel(t.route),gate:t.gate,departureTime:v71DisplayTime(t.time)};
  }
  return null;
}
function v76TripChanged(){const trip=v76SelectedTrip();if(trip && $('calcRoute')){$('calcRoute').value=trip.route;}compute(false);}
function v76ToggleMode(){const fragile=$('calcMode')?.value==='fragile';document.querySelectorAll('.normalOnly').forEach(el=>el.style.display=fragile?'none':'grid');compute(false);}
function v76CalcParams(){return {route:$('calcRoute')?.value||'cebu_maasin',mode:$('calcMode')?.value||'normal',cls:$('calcClass')?.value||'tourist',pax:Math.max(1,Number($('pax')?.value)||1),weight:Math.max(0,Number($('weight')?.value)||0),rounding:$('rounding')?.value||'exact',psn:($('calcPsn')?.value||'').trim()};}
function v76ComputeData(override){
  const p=override||v76CalcParams();const routeData=ROUTES[p.route]||ROUTES.cebu_maasin;const rates=routeData.slab?.[p.mode]||routeData.slab?.normal||[0,0,0];
  const allowance=p.mode==='normal'?(V77_CLASS_ALLOWANCE[p.cls]||10):0;const freeTotal=allowance*p.pax;const excessRaw=Math.max(0,p.weight-freeTotal);const excess=p.rounding==='ceil'?Math.ceil(excessRaw):p.rounding==='floor'?Math.floor(excessRaw):excessRaw;
  const charge=p.mode==='normal'?excess/p.pax:p.weight;const slab=slabCost(charge,rates);const perPax=slab.total;const baggage=p.mode==='normal'?perPax*p.pax:perPax;
  const trip=v76SelectedTrip();const d={id:uid('txn'),time:today(),route:p.route,routeLabel:v76RouteLabel(p.route),routeNote:v76RouteNote(p.route),mode:p.mode,cls:p.cls,clsLabel:v76ClassLabel(p.cls),pax:p.pax,kg:p.weight,weight:p.weight,rounding:p.rounding,allowance,free:freeTotal,freeTotal,excess,charge,slab,perPax,baggage,grand:baggage,psn:p.psn,rates,passenger:0,passengerPerPax:0};
  if(trip){Object.assign(d,{tripId:trip.id,tripCode:trip.code,vessel:trip.vessel,gate:trip.gate,departureTime:trip.departureTime,boardingTime:trip.boardingTime,tripStatus:trip.status});}
  return d;
}
