function v76StepHtml(list){return list.map((x,i)=>`<div class="oj76Step ${x.total?'total':''}"><span class="num">${i+1}</span><span>${esc(x.text)}<small>${esc(x.note||'')}</small></span><b>${esc(x.value||'')}</b></div>`).join('')}
