  if($('receipt')){$('receipt').innerHTML=v76ReceiptHtml(d,steps);$('receipt').style.display='block';}
  const trip=v76SelectedTrip();if($('calcTripSummary')){$('calcTripSummary').innerHTML=trip?`<b>${esc(trip.code)} · ${esc(trip.vessel||'OceanJet')}</b><span>${esc(trip.routeLabel||d.routeLabel)} · Gate ${esc(trip.gate||'TBA')} · Depart ${esc(trip.departureTime||'-')}</span>`:`<b>${esc(d.routeLabel)}</b><span>${esc(v76RouteNote(d.route)||'No linked trip selected.')}</span>`;}
  v76ReceiptText=v76PlainReceipt(d,steps);v67LastReceiptText=v76ReceiptText;
