function computeCalc(){return compute(false)}
function downloadReceipt(){if(!v76ReceiptText){toast('Compute first');return;}download('OceanJet_Baggage_Estimate_'+Date.now()+'.txt',v76ReceiptText,'text/plain');toast('Receipt downloaded')}
function cashierAdjust(){const p=v76CalcParams();if(p.weight<=0){toast('Enter weight first');return;}if(p.mode==='fragile'){for(let w=Math.floor(p.weight)-1;w>=0;w--){const slab=slabCost(w,(ROUTES[p.route]||ROUTES.cebu_maasin).slab.fragile);if(Math.abs(slab.total%1)<0.001&&slab.total>0){$('weight').value=w;compute(true);toast(`Adjusted to ${w}kg → ${v76Money(slab.total)}`);return;}}toast('No whole-peso total found for fragile');return;}const free=(V77_CLASS_ALLOWANCE[p.cls]||10)*p.pax;const excess=p.weight-free;if(excess<=0){toast('No excess to adjust');return;}for(let e=Math.floor(excess)-1;e>=0;e--){const testW=e+free;const E=e/p.pax;const slab=slabCost(E,(ROUTES[p.route]||ROUTES.cebu_maasin).slab.normal);const tot=slab.total*p.pax;if(Math.abs(tot%1)<0.001){$('weight').value=testW;compute(true);toast(`Adjusted to ${testW}kg → ${v76Money(tot)}`);return;}}toast('No whole-peso total found')}
function saveTransaction(){const d=compute(false);d.psn=($('calcPsn')?.value||'').trim();d.grand=d.baggage;state.data.transactions.unshift(d);state.data.transactions=state.data.transactions.slice(0,200);audit('Baggage estimate saved',`${d.tripCode?d.tripCode+' · ':''}${d.routeLabel} ${v76Money(d.baggage)}`);save();renderTransactions();toast('Baggage estimate saved')}
function copyCalcQuote(){const d=v67LastCalc||compute(false);const trip=d.tripCode?`\nTrip: ${d.tripCode}\nVessel: ${d.vessel||'-'}\nGate: ${d.gate||'-'}\nDeparture: ${d.departureTime||'-'}`:'';const text=`OceanJet Baggage Estimate${trip}\n${d.routeLabel}\nMode: ${d.mode}\nClass: ${d.mode==='normal'?d.clsLabel:'Fragile/Special'}\nPassengers: ${d.mode==='normal'?d.pax:1}\nTotal Weight: ${d.kg.toFixed(1)} kg\nFree Allowance: ${d.freeTotal.toFixed(1)} kg\nExcess Baggage: ${d.excess.toFixed(1)} kg\nPer Passenger: ${v76Money(d.perPax)}\nBaggage Estimate: ${v76Money(d.baggage)}`;navigator.clipboard?.writeText(text);toast('Estimate copied')}
function renderTransactions(){const box=$('txnList');if(!box)return;const rows=state.data.transactions.slice(0,12);box.innerHTML=rows.length?`<div class="tableWrap"><table><thead><tr><th>Time</th><th>Trip</th><th>Route</th><th>Mode / Class</th><th>KG</th><th>Baggage Estimate</th><th></th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.time)}</td><td>${x.tripCode?`<b>${esc(x.tripCode)}</b><br><span class="tiny">${esc(x.vessel||'')}</span>`:'-'}</td><td>${esc(x.routeLabel||v76RouteLabel(x.route))}</td><td>${esc((x.mode||x.type||'normal')+' / '+(x.clsLabel||x.cls||''))}</td><td>${Number(x.kg||x.weight||0).toFixed(1)}</td><td><b>${v76Money(x.baggage||x.grand||0)}</b></td><td><button class="small" onclick="makeReceiptFromTxn('${x.id}')">View</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No baggage estimates yet.</div>'}
function makeReceiptFromTxn(id){const x=state.data.transactions.find(a=>a.id===id);if(!x){toast('Estimate not found');return}const amount=Number(x.baggage||x.grand||0);state.data.receipts.unshift({id:uid('receipt'),time:today(),psn:x.psn||'',name:'',route:x.route,routeLabel:x.routeLabel||v76RouteLabel(x.route),amount,tripCode:x.tripCode||'',vessel:x.vessel||'',gate:x.gate||'',departureTime:x.departureTime||'',notes:`Baggage estimate only: ${Number(x.kg||x.weight||0).toFixed(1)}kg, ${x.pax||1} pax, per passenger ${v76Money(x.perPax||0)}`});audit('Baggage estimate receipt created',`${x.tripCode||x.routeLabel||''} ${v76Money(amount)}`);save();toast('Baggage receipt created');renderApp('receipt')}
