function v77QuickSearch(){
  const q=($('v77DashSearch')?.value||'').trim().toLowerCase(), out=$('v77DashSearchOut'); if(!out) return;
  if(!q){out.innerHTML='<div class="tiny">Enter PSN, last name, trip, route, or receipt number.</div>';return;}
  const claims=state.data.claims.filter(x=>[x.psn,x.last,x.routeLabel,x.type,x.status,x.tripCode].join(' ').toLowerCase().includes(q)).slice(0,5).map(x=>`<div class="v77Result"><b>Claim: ${v77SafeText(x.psn)} · ${v77SafeText(x.last)}</b><div class="tiny">${v77SafeText(x.routeLabel)} · ${v77SafeText(x.status||'Open')}</div></div>`);
  const cases=state.data.cases.filter(x=>[x.psn,x.last,x.routeLabel,x.type,x.status,x.tripCode,x.vessel].join(' ').toLowerCase().includes(q)).slice(0,5).map(x=>`<div class="v77Result"><b>Evidence: ${v77SafeText(x.psn)} · ${v77SafeText(x.last)}</b><div class="tiny">${v77SafeText(x.type)} · score ${x.score||0}% · ${x.locked?'Locked':'Open'}</div></div>`);
  const trips=(state.data.trips||[]).filter(t=>[t.code,t.vessel,t.routeLabel,t.gate,t.manualStatus].join(' ').toLowerCase().includes(q)).slice(0,5).map(t=>`<div class="v77Result"><b>Trip: ${v77SafeText(t.code)} · ${v77SafeText(t.vessel)}</b><div class="tiny">${v77SafeText(t.routeLabel)} · ${v77SafeText(t.gate)} · ${v77SafeText(t.time)}</div></div>`);
  out.innerHTML=[...trips,...claims,...cases].join('')||'<div class="empty">No local match found.</div>';
  audit('Quick search',q); save();
}
