function v77SuggestSize(text){const q=String(text||'').toLowerCase();if(q.includes('large')||q.includes('big'))return 'Large luggage';if(q.includes('medium'))return 'Medium luggage';if(q.includes('small'))return 'Small bag';if(q.includes('box'))return 'Box / carton';return $('dSize')?.value||'';}
