/* V77 final visible-label cleanup and packet output */
const v77PreviousBoard = board;
board = function(){ v77PreviousBoard(); const chips=[...document.querySelectorAll('.hero .chip,.badge')]; chips.forEach(ch=>{ if(/V7[0-6]|V6[0-9]/.test(ch.textContent||'')) ch.textContent=(ch.textContent||'').replace(/V7[0-6]|V6[0-9]/g,'Operations'); }); const h=document.querySelector('.hero h2'); if(h&&/Command Control/.test(h.textContent)) h.textContent='Operations Command Center'; };
const v77PreviousTrips = trips;
trips = function(){ v77PreviousTrips(); const h=document.querySelector('.hero h2'); if(h) h.textContent='Trips & Boarding Status'; };
downloadDailyPacket = function(){ensureData();const s=v77OpsSummary();const tripLines=s.rows.map(r=>{const t=r.trip,i=r.info;return `- ${t.code||'-'} / ${t.vessel||'-'} / ${t.routeLabel||v77RouteLabel(t.route)} / ${t.gate||'-'} / ${i.status||'-'} / ${t.time||'-'}`}).join('\n');const txt=`OceanJet PortDesk Daily Packet\nVersion: ${APP_VERSION}\nDate: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nTrips today: ${state.data.trips.length}\nNow boarding: ${s.boarding.length}\nDeparting soon: ${s.soon.length}\nDeparted: ${s.departed.length}\nDelayed: ${s.delayed.length}\nClosed: ${s.closed.length}\nCancelled: ${s.cancelled.length}\nClaims: ${state.data.claims.length}\nEvidence cases: ${state.data.cases.length}\nLocked evidence: ${state.data.cases.filter(x=>x.locked).length}\nBaggage estimates: ${state.data.transactions.length}\n\nTrip Board:\n${tripLines||'-'}\n\nLatest Audit:\n${state.data.audit.slice(0,25).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail}`).join('\n')}`;audit('Daily packet export','V78 operations packet');save();download('OceanJet_PortDesk_V78_Daily_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Daily packet downloaded');};
printReceipt = function(id){const x=state.data.receipts.find(a=>a.id===id);if(!x)return;modal(`<div class="modalHead"><h3>Baggage Estimate Receipt</h3><button class="small" onclick="closeModal()">✕</button></div><div class="printArea"><h2>OceanJet</h2><h3>Baggage Estimate Receipt</h3><p><b>Date:</b> ${esc(x.time)}<br>${x.tripCode?`<b>Trip:</b> ${esc(x.tripCode)} · ${esc(x.vessel||'')}<br><b>Gate/Departure:</b> ${esc(x.gate||'-')} · ${esc(x.departureTime||'-')}<br>`:''}<b>Ref:</b> ${esc(x.psn||x.id)}<br><b>Route:</b> ${esc(x.routeLabel)}<br><b>Baggage Total:</b> ${peso(x.amount)}</p><p>${esc(x.notes||'')}</p><hr><p>Prepared via OceanJet PortDesk baggage estimate.</p></div><button class="primary block noPrint" style="margin-top:10px" onclick="window.print()">Print</button>`)};



/* =========================
   V78 AI-MANAGED OPERATIONS QUALITY UPGRADE
   Real code layer built on latest source. No background repair loops, observers, or scanner automation.
   ========================= */
NAVS.passenger = [['dashboard','🏠','Passenger Hub'],['trips','🕐','Trips'],['claim','📝','Claim'],['track','🔎','Track'],['calculator','🧮','Estimate']];
NAVS.cashier = [['dashboard','🏠','Cashier'],['board','🛳️','Board'],['calculator','🧮','Baggage'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💼','Settlement'],['trips','🕐','Trips']];
NAVS.admin = [['dashboard','🏠','Command'],['board','🛳️','Port Ops'],['calculator','🧮','Baggage'],['damage','📸','Evidence'],['queue','👥','Queue'],['receipt','🧾','Receipt'],['settlement','💼','Settlement'],['quality','✅','Quality'],['reports','📊','Reports'],['automation','🤖','Automation'],['system','⚙️','System']];
function v78EnsureData(){ensureData();state.data.v78 ||= {checklists:{},handoverNotes:[],lastQualityRun:'',lastPacket:''};state.data.v78.checklists ||= {};state.data.v78.handoverNotes ||= [];state.data.trips ||= [];state.data.claims ||= [];state.data.cases ||= [];state.data.transactions ||= [];state.data.receipts ||= [];}
function v78Rows(){v78EnsureData();if(typeof v77TripRows==='function') return v77TripRows();if(typeof v75Rows==='function') return v75Rows();return (state.data.trips||[]).map(t=>({trip:t,info:{status:t.manualStatus||'Scheduled'}}));}
function v78Info(t){if(typeof v75TripInfo==='function') return v75TripInfo(t);if(typeof v71TripStatus==='function') return v71TripStatus(t);return {status:t.manualStatus||'Scheduled',boarding:new Date(),dep:new Date()};}
function v78Time(t){try{return typeof v71DisplayTime==='function'?v71DisplayTime(t):String(t||'-')}catch(e){return String(t||'-')}}
function v78Route(t){return t.routeLabel || (typeof v77RouteLabel==='function'?v77RouteLabel(t.route):typeof v71RouteLabel==='function'?v71RouteLabel(t.route):(ROUTES[t.route]?.label||t.route||'-'));}
function v78StatusClass(status){status=String(status||'').toLowerCase();if(status.includes('cancel')||status.includes('hold'))return 'bad';if(status.includes('delay')||status.includes('soon')||status.includes('closed'))return 'warn';return 'ok'}
function v78OpenRecords(){v78EnsureData();return {claims:state.data.claims.filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')).length,evidence:state.data.cases.filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')).length,unlinkedEvidence:state.data.cases.filter(x=>!x.claimId).length,unlockedEvidence:state.data.cases.filter(x=>!x.locked).length,lowScore:state.data.cases.filter(x=>Number(x.score||0)<70).length,noTripClaims:state.data.claims.filter(x=>!x.tripCode).length,noTripBaggage:state.data.transactions.filter(x=>!x.tripCode).length};}
function v78Issues(){v78EnsureData();const rows=v78Rows(), open=v78OpenRecords(), issues=[];const missingGate=rows.filter(r=>!r.trip.gate||/tba/i.test(r.trip.gate)).slice(0,4);const missingVessel=rows.filter(r=>!r.trip.vessel||/vessel$/i.test(r.trip.vessel)).slice(0,4);const delayed=rows.filter(r=>/Delayed|Cancelled|Hold/i.test(r.info.status||r.trip.manualStatus||''));const boarding=rows.filter(r=>/Boarding|Departing Soon/i.test(r.info.status||''));if(!rows.length)issues.push({level:'bad',title:'No trips loaded',detail:'Prepare today\'s vessel board before counter operations.'});if(missingGate.length)issues.push({level:'warn',title:'Gate / pier needs confirmation',detail:missingGate.map(r=>r.trip.code).join(', ')});if(missingVessel.length)issues.push({level:'warn',title:'Vessel name incomplete',detail:missingVessel.map(r=>r.trip.code).join(', ')});if(delayed.length)issues.push({level:'bad',title:'Exception trips need staff notice',detail:delayed.map(r=>r.trip.code+' '+(r.info.status||r.trip.manualStatus)).join(', ')});if(boarding.length)issues.push({level:'ok',title:'Active boarding watch',detail:boarding.map(r=>r.trip.code).join(', ')});if(open.claims)issues.push({level:'warn',title:'Open passenger claims',detail:String(open.claims)+' claim(s) still need review.'});if(open.unlinkedEvidence)issues.push({level:'warn',title:'Evidence not linked to claim',detail:String(open.unlinkedEvidence)+' evidence record(s) need PSN + Last Name matching.'});if(open.lowScore)issues.push({level:'warn',title:'Low evidence completeness score',detail:String(open.lowScore)+' record(s) need better photo pair/details.'});if(open.noTripBaggage)issues.push({level:'ok',title:'Baggage estimates without trip link',detail:String(open.noTripBaggage)+' estimate(s) can still be valid, but trip link improves audit.'});return issues.slice(0,8);}
function v78QualityScore(){v78EnsureData();const rows=v78Rows(), open=v78OpenRecords();let score=100;if(!rows.length)score-=30;score-=Math.min(20, rows.filter(r=>!r.trip.gate||/tba/i.test(r.trip.gate)).length*4);score-=Math.min(18, rows.filter(r=>!r.trip.vessel||/vessel$/i.test(r.trip.vessel)).length*3);score-=Math.min(20, rows.filter(r=>/Delayed|Cancelled|Hold/i.test(r.info.status||r.trip.manualStatus||'')).length*5);score-=Math.min(18, open.unlinkedEvidence*4);score-=Math.min(15, open.lowScore*3);score-=Math.min(10, open.noTripClaims*1);return Math.max(0,Math.min(100,Math.round(score)));}
function v78OpsMetrics(){v78EnsureData();const rows=v78Rows();const grouped={boarding:0,soon:0,scheduled:0,departed:0,closed:0,delayed:0,cancelled:0};rows.forEach(r=>{const s=String(r.info.status||r.trip.manualStatus||'Scheduled');if(/Boarding/i.test(s))grouped.boarding++;else if(/Soon/i.test(s))grouped.soon++;else if(/Departed/i.test(s))grouped.departed++;else if(/Closed/i.test(s))grouped.closed++;else if(/Delayed|Hold/i.test(s))grouped.delayed++;else if(/Cancelled/i.test(s))grouped.cancelled++;else grouped.scheduled++;});return grouped;}
function v78ActionCenter(title='AI Operations Quality Center'){const score=v78QualityScore(), issues=v78Issues(), m=v78OpsMetrics(), open=v78OpenRecords();return `<div class="v78Ribbon"><div class="v78CommandCard"><div class="cardHead"><div><h3>${esc(title)}</h3><p>Manual command center for readiness, claim/evidence quality, handover, export, and workflow linking.</p></div><span class="badge ${score>=82?'ok':score>=62?'warn':'bad'}">${score}% Ready</span></div><div class="v78Score"><div class="v78ScoreDial" style="--score:${score}"><div><b>${score}</b><span>%</span></div></div><div><b>Quality Readiness</b><p class="muted">Score is calculated only when this screen renders. Staff still confirms important changes.</p><div class="chips"><span class="chip">${m.boarding} boarding</span><span class="chip">${m.soon} soon</span><span class="chip">${m.delayed+m.cancelled} exceptions</span><span class="chip">${open.claims+open.evidence} open workload</span></div></div></div><div class="v78IssueList">${issues.length?issues.map(x=>`<div class="v78Issue"><div><strong>${esc(x.title)}</strong><span>${esc(x.detail)}</span></div><em class="v78Tag ${x.level}">${x.level.toUpperCase()}</em></div>`).join(''):'<div class="v78Issue"><div><strong>No urgent quality issues</strong><span>Current local records look complete for handover.</span></div><em class="v78Tag ok">OK</em></div>'}</div></div><div class="v78CommandCard"><h3>One-Tap Manual Tools</h3><p>These tools do not run in the background. They execute only when staff presses a button.</p><div class="v78ActionGrid"><button onclick="renderApp('board')"><b>🛳️ Port Board</b><span>Open vessel command view</span></button><button onclick="v78RelinkWorkflows()"><b>🔗 Relink Records</b><span>Match trip/claim/evidence safely</span></button><button onclick="v78ExportDutyPacket('txt')"><b>📦 Duty Packet</b><span>Export operational handover</span></button><button onclick="v78ExportRiskCSV()"><b>⚠️ Risk CSV</b><span>Download quality issue list</span></button><button onclick="v78OpenRoleMatrix()"><b>🛡️ Role Matrix</b><span>Review access by role</span></button><button onclick="v78OpenQuickActions()"><b>⚙️ Action Modal</b><span>More controlled utilities</span></button></div></div></div>`;}
function v78AppendToGrid(html){const content=$('content');if(!content)return;const grid=content.querySelector('.grid');if(grid)grid.insertAdjacentHTML('afterbegin',html);else content.insertAdjacentHTML('beforeend',html);}
function v78InjectDashboard(){const content=$('content');if(!content)return;content.insertAdjacentHTML('afterbegin',v78ActionCenter(state.role==='admin'?'Admin AI Operations Quality Center':state.role==='cashier'?'Cashier Quality Workbench':'Passenger Service Hub Quality View'));}
function v78BoardFooter(){const rows=v78Rows();const next=rows.find(r=>!/Departed|Cancelled/i.test(r.info.status||''));return `<div class="card span12"><div class="cardHead"><div><h3>V78 Boarding Quality Control</h3><p>Manual quality tools for vessel board readiness. No status is changed unless staff confirms.</p></div><span class="badge ${v78QualityScore()>=82?'ok':'warn'}">${v78QualityScore()}% Readiness</span></div><div class="v78BoardStrip"><div class="v78StripItem"><b>${rows.length}</b><small>Total vessel trips</small></div><div class="v78StripItem"><b>${next?esc(next.trip.code):'-'}</b><small>Next actionable trip</small></div><div class="v78StripItem"><b>${v78OpenRecords().claims}</b><small>Open claims</small></div><div class="v78StripItem"><b>${v78OpenRecords().evidence}</b><small>Evidence queue</small></div></div><div class="miniActions" style="margin-top:12px"><button class="primary" onclick="v78ManualClosePastBoarding()">Suggest Close Past Boarding</button><button onclick="v78PrintPublicBoard()">Print Public Board</button><button onclick="v78ExportDutyPacket('txt')">Export Duty Packet</button><button onclick="v78ExportTripsPlusCSV()">Export Trips + Readiness CSV</button></div><div class="notice" style="margin-top:12px">V78 only calculates suggestions on screen render or button press. Manual trip statuses are not overwritten secretly.</div></div>`;}
function v78CalculatorFooter(){const last=state.lastCalc;return `<div class="card span12"><div class="cardHead"><div><h3>Baggage Estimate Quality Guard</h3><p>Preserves the organized calculator UI while adding clearer official controls.</p></div><span class="badge ok">Baggage-only receipt</span></div><div class="v78NoticeGrid"><div class="v78Proof"><b>Validation</b><p class="muted">Passenger count and baggage weight are checked before saving. Business allowance remains 20kg, regular/student/minor remain 10kg.</p></div><div class="v78Proof"><b>Latest Estimate</b><p class="muted">${last?`${esc(last.routeLabel||v78Route(last))} · ${Number(last.kg||last.weight||0).toFixed(1)}kg · ${peso(last.baggage||last.grand||0)}`:'No live estimate yet.'}</p></div></div><div class="miniActions" style="margin-top:12px"><button onclick="v78ValidateCurrentEstimate()">Check Current Estimate</button><button onclick="v78ExportLatestEstimate()">Export Latest Estimate</button><button onclick="renderApp('settlement')">Open Settlement</button></div></div>`;}
function v78EvidenceFooter(){const open=v78OpenRecords();return `<div class="card span12"><div class="cardHead"><div><h3>Evidence Integrity Control</h3><p>Manual-only quality checks for official baggage damage records.</p></div><span class="badge ${open.unlinkedEvidence||open.lowScore?'warn':'ok'}">${open.unlinkedEvidence+open.lowScore} issue(s)</span></div><div class="v78BoardStrip"><div class="v78StripItem"><b>${state.data.cases.length}</b><small>Total evidence records</small></div><div class="v78StripItem"><b>${state.data.cases.filter(x=>x.locked).length}</b><small>Locked official records</small></div><div class="v78StripItem"><b>${open.unlinkedEvidence}</b><small>Not linked to claim</small></div><div class="v78StripItem"><b>${open.lowScore}</b><small>Low score records</small></div></div><div class="miniActions" style="margin-top:12px"><button class="primary" onclick="v78RelinkWorkflows()">Relink by PSN + Last Name</button><button onclick="v78ExportEvidencePacket()">Export Evidence Packet</button><button onclick="renderApp('queue')">Open Review Queue</button></div></div>`;}
function v78QueueFooter(){return `<div class="card span12"><div class="cardHead"><div><h3>Review Queue Commander</h3><p>Prioritize missing claim links, low-score evidence, unlocked records, and open claim statuses.</p></div><button class="small" onclick="v78ExportRiskCSV()">Risk CSV</button></div>${v78MiniRiskTable()}</div>`;}
function v78MiniRiskTable(){const issues=[];state.data.cases.forEach(x=>{if(!x.claimId)issues.push(['Evidence',x.psn||'-','No linked claim',x.status||'-']);if(Number(x.score||0)<70)issues.push(['Evidence',x.psn||'-','Low evidence score '+(x.score||0)+'%',x.status||'-']);if(!x.locked)issues.push(['Evidence',x.psn||'-','Record not locked official',x.status||'-']);});state.data.claims.forEach(x=>{if(!x.tripCode)issues.push(['Claim',x.psn||'-','No trip link',x.status||'-']);if(!['Done','Rejected','Closed'].includes(x.status||''))issues.push(['Claim',x.psn||'-','Still open',x.status||'-']);});return issues.length?`<table class="v78MiniTable"><tbody>${issues.slice(0,12).map(r=>`<tr><td><b>${esc(r[0])}</b></td><td>${esc(r[1])}</td><td>${esc(r[2])}</td><td>${esc(r[3])}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">No immediate review risks found.</div>';}
function v78ValidateCurrentEstimate(){try{const d=typeof compute==='function'?compute(false):state.lastCalc;if(!d){toast('No estimate to validate');return}const problems=[];if(Number(d.pax||0)<1)problems.push('Passenger count must be at least 1.');if(Number(d.kg||d.weight||0)<0)problems.push('Weight cannot be negative.');if(!d.route&&!d.routeLabel)problems.push('Route is required.');if(Number(d.charge||0)===0)problems.push('Within free baggage allowance.');modal(`<div class="modalHead"><h3>Baggage Estimate Validation</h3><button class="small" onclick="closeModal()">✕</button></div><div class="notice ${problems.length?'':'alertGood'}">${problems.length?problems.map(esc).join('<br>'):'Estimate looks ready for saving or receipt preview.'}</div><div class="compactList" style="margin-top:12px"><div class="compactRow"><span>Route</span><b>${esc(d.routeLabel||'')}</b></div><div class="compactRow"><span>Passengers</span><b>${Number(d.pax||1)}</b></div><div class="compactRow"><span>Total weight</span><b>${Number(d.kg||d.weight||0).toFixed(2)} kg</b></div><div class="compactRow"><span>Baggage estimate</span><b>${peso(d.baggage||d.grand||0)}</b></div></div>`);audit('Baggage validation check',d.routeLabel||'current estimate');save();}catch(e){toast('Could not validate estimate')}}
function v78ExportLatestEstimate(){const d=state.lastCalc;if(!d){toast('Compute an estimate first');return}const txt=`OceanJet Baggage Estimate\nVersion: ${APP_VERSION}\nGenerated: ${today()}\nTrip: ${d.tripCode||'-'} ${d.vessel||''}\nRoute: ${d.routeLabel||''}\nPassengers: ${d.pax||1}\nClass: ${d.clsLabel||d.cls||''}\nMode: ${d.mode||d.type||'normal'}\nTotal KG: ${Number(d.kg||d.weight||0).toFixed(2)}\nFree Allowance: ${Number(d.free||0).toFixed(2)} kg\nChargeable KG: ${Number(d.charge||0).toFixed(2)}\nBaggage Estimate: ${peso(d.baggage||d.grand||0)}\nPrepared via OceanJet PortDesk.`;download('OceanJet_V78_Baggage_Estimate_'+Date.now()+'.txt',txt,'text/plain');audit('Baggage estimate export',d.routeLabel||'latest');save();toast('Estimate exported');}
function v78RelinkWorkflows(){v78EnsureData();let claimLinks=0,tripLinks=0,opsCounts=0;state.data.cases.forEach(e=>{if(!e.claimId){const c=state.data.claims.find(c=>(c.psn||'').toLowerCase()===(e.psn||'').toLowerCase()&&(c.last||'').toLowerCase()===(e.last||'').toLowerCase());if(c){e.claimId=c.id;c.evidenceId=e.id;c.status=c.status==='Open'?'Review':(e.status||'Review');claimLinks++;if(c.tripCode&&!e.tripCode){Object.assign(e,{tripId:c.tripId,tripCode:c.tripCode,vessel:c.vessel,gate:c.gate,departureTime:c.departureTime});tripLinks++;}}}if(e.tripCode&&!e.tripId){const t=state.data.trips.find(t=>String(t.code).toLowerCase()===String(e.tripCode).toLowerCase());if(t){e.tripId=t.id;tripLinks++;}}});state.data.claims.forEach(c=>{if(c.tripCode&&!c.tripId){const t=state.data.trips.find(t=>String(t.code).toLowerCase()===String(c.tripCode).toLowerCase());if(t){c.tripId=t.id;tripLinks++;}}});state.data.trips.forEach(t=>{t.ops ||= {};t.ops.claims=state.data.claims.filter(c=>c.tripId===t.id||c.tripCode===t.code).length;t.ops.evidence=state.data.cases.filter(c=>c.tripId===t.id||c.tripCode===t.code).length;t.ops.baggage=state.data.transactions.filter(c=>c.tripId===t.id||c.tripCode===t.code).length;opsCounts++;});state.data.v78.lastQualityRun=today();audit('V78 workflow relink',`claim links ${claimLinks}, trip links ${tripLinks}, trip counters ${opsCounts}`);save();toast(`Relink complete: ${claimLinks} claim, ${tripLinks} trip`);if(state.view==='dashboard')dashboard();else if(state.view==='damage')damage();else if(state.view==='queue')queue();else if(state.view==='board')board();}
function v78ExportRiskCSV(){const rows=[];v78Issues().forEach(x=>rows.push({type:'operations',level:x.level,title:x.title,detail:x.detail,time:today()}));state.data.cases.forEach(x=>{if(!x.claimId)rows.push({type:'evidence',level:'warn',title:'No linked claim',detail:`${x.psn||''} ${x.last||''}`,time:x.time});if(Number(x.score||0)<70)rows.push({type:'evidence',level:'warn',title:'Low evidence score',detail:`${x.psn||''} ${x.score||0}%`,time:x.time});});state.data.claims.forEach(x=>{if(!x.tripCode)rows.push({type:'claim',level:'ok',title:'No trip link',detail:`${x.psn||''} ${x.last||''}`,time:x.time});});download('OceanJet_V78_Quality_Risks_'+Date.now()+'.csv',csv(rows),'text/csv');audit('V78 risk CSV export',String(rows.length)+' rows');save();toast('Risk CSV exported');}
function v78ExportTripsPlusCSV(){const rows=v78Rows().map(r=>{const t=r.trip,i=r.info;return {code:t.code,vessel:t.vessel,route:v78Route(t),gate:t.gate,time:t.time,boarding: i.boarding? (typeof v71DisplayTimeFromDate==='function'?v71DisplayTimeFromDate(i.boarding):String(i.boarding)):'',status:i.status||t.manualStatus||'',booked:t.ops?.booked||'',checkedIn:t.ops?.checkedIn||'',boarded:t.ops?.boarded||'',claims:t.ops?.claims||0,evidence:t.ops?.evidence||0,baggage:t.ops?.baggage||0,note:t.note||''};});download('OceanJet_V78_Trips_Readiness_'+Date.now()+'.csv',csv(rows),'text/csv');audit('V78 trips readiness CSV export',String(rows.length)+' trips');save();toast('Trips readiness CSV exported');}
function v78ExportEvidencePacket(){const pack={version:APP_VERSION,exportedAt:new Date().toISOString(),score:v78QualityScore(),evidence:state.data.cases.map(x=>({id:x.id,time:x.time,psn:x.psn,last:x.last,route:x.routeLabel,tripCode:x.tripCode||'',vessel:x.vessel||'',type:x.type,status:x.status,score:x.score,locked:!!x.locked,claimId:x.claimId||'',notes:x.notes||''}))};download('OceanJet_V78_Evidence_Integrity_Packet_'+Date.now()+'.json',JSON.stringify(pack,null,2),'application/json');audit('V78 evidence packet export',String(pack.evidence.length)+' records');save();toast('Evidence packet exported');}
function v78ExportDutyPacket(format='txt'){v78EnsureData();const rows=v78Rows(), score=v78QualityScore(), open=v78OpenRecords();const lines=rows.map(r=>{const t=r.trip,i=r.info;return `- ${t.code||'-'} / ${t.vessel||'-'} / ${v78Route(t)} / ${t.gate||'-'} / ${v78Time(t.time)} / ${i.status||t.manualStatus||'-'}`}).join('\n');const risk=v78Issues().map(x=>`- [${x.level.toUpperCase()}] ${x.title}: ${x.detail}`).join('\n')||'- No urgent risk flagged';const txt=`OceanJet PortDesk V78 Duty Packet\nGenerated: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nReadiness Score: ${score}%\nTrips: ${rows.length}\nOpen Claims: ${open.claims}\nEvidence Queue: ${open.evidence}\nBaggage Estimates: ${state.data.transactions.length}\n\nTrip Board:\n${lines||'-'}\n\nQuality / Risk Notes:\n${risk}\n\nLatest Audit:\n${state.data.audit.slice(0,30).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail}`).join('\n')||'-'}\n\nPrepared via OceanJet PortDesk.`;state.data.v78.lastPacket=today();audit('V78 duty packet export',`${score}% readiness`);save();download('OceanJet_V78_Duty_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Duty packet exported');}
function v78PrintPublicBoard(){const rows=v78Rows();modal(`<div class="modalHead"><h3>Printable Public Vessel Board</h3><button class="small" onclick="closeModal()">✕</button></div><div class="printArea"><h2>OceanJet Vessel Board</h2><p><b>Generated:</b> ${esc(today())}</p><table><thead><tr><th>Trip</th><th>Vessel</th><th>Route</th><th>Gate</th><th>Boarding</th><th>Departure</th><th>Status</th></tr></thead><tbody>${rows.map(r=>{const t=r.trip,i=r.info;return `<tr><td>${esc(t.code||'-')}</td><td>${esc(t.vessel||'-')}</td><td>${esc(v78Route(t))}</td><td>${esc(t.gate||'-')}</td><td>${esc(i.boarding&&typeof v71DisplayTimeFromDate==='function'?v71DisplayTimeFromDate(i.boarding):'-')}</td><td>${esc(v78Time(t.time))}</td><td>${esc(i.status||t.manualStatus||'-')}</td></tr>`}).join('')}</tbody></table><p>For staff confirmation only. Subject to operational change.</p></div><div class="v78Signature noPrint"><div>Prepared by</div><div>Checked by</div><div>Duty Officer</div></div><button class="primary block noPrint" style="margin-top:12px" onclick="window.print()">Print Vessel Board</button>`);audit('Public vessel board opened','print view');save();}
function v78ManualClosePastBoarding(){const rows=v78Rows().filter(r=>{const status=String(r.info.status||r.trip.manualStatus||'');return /Departed|Closed|Cancelled/i.test(status)&&!/Closed|Cancelled/i.test(r.trip.manualStatus||'');});if(!rows.length){toast('No past boarding trips need closing');return}if(!confirm(`Mark ${rows.length} past boarding trip(s) as Closed?`))return;rows.forEach(r=>{r.trip.manualStatus='Closed';r.trip.updatedAt=today();});audit('V78 manual close boarding',String(rows.length)+' trip(s) closed by staff');save();toast('Past boarding closed');board();}
function v78OpenRoleMatrix(){const rows=[['Passenger','Passenger Hub, trips, claim form, claim tracking, baggage estimate'],['Cashier','Port board view, baggage estimate, evidence studio, queue, receipt, settlement'],['Admin','Full command center, port ops, reports, quality, automation, system tools']];modal(`<div class="modalHead"><h3>Role Access Matrix</h3><button class="small" onclick="closeModal()">✕</button></div><div class="tableWrap"><table><thead><tr><th>Role</th><th>Visible Workflow</th></tr></thead><tbody>${rows.map(r=>`<tr><td><b>${esc(r[0])}</b></td><td>${esc(r[1])}</td></tr>`).join('')}</tbody></table></div><div class="notice" style="margin-top:12px">Role badge, dashboard, sidebar, and bottom navigation refresh through one role state update after login.</div>`);}
