runDiagnostics = function(){v78EnsureData();let d={};try{d=v78PreviousDiagnostics()||{}}catch(e){d={error:String(e)}}d.v78={version:APP_VERSION,store:STORE,readiness:v78QualityScore(),roleNav:(NAVS[state.role]||[]).map(x=>x[0]).join(', '),workflowIssues:v78Issues().length,trips:(state.data.trips||[]).length,claims:(state.data.claims||[]).length,evidence:(state.data.cases||[]).length,baggage:(state.data.transactions||[]).length,manualOnly:'true',backgroundRepair:'not installed by V78'};const out=$('diagOut');if(out)out.innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>';return d;};
openQuickHelp = function(){modal(`<div class="modalHead"><h3>OceanJet PortDesk V78 Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>V78 continues from the latest full source and preserves the organized V55-style baggage calculator layout.</li><li>Role navigation is expanded: Admin has direct Port Ops, Quality, Settlement, Reports, and System access; Cashier has Board, Baggage, Evidence, Queue, Receipt, and Settlement.</li><li>The new AI Operations Quality Center adds readiness score, risk list, duty packet export, trip readiness CSV, evidence integrity packet, and role matrix.</li><li>Workflow relinking is manual: it runs only when staff presses Relink Records and logs the action.</li><li>Damage Evidence Studio remains manual-only. No auto scanner, no camera auto-capture, and no hidden navigation or role changes were added.</li></ul>`);};
verifyCoreFunctions = function(){const missing=['dashboard','board','calculator','damage','queue','runDiagnostics','v78QualityScore','v78RelinkWorkflows','v78ExportDutyPacket','setActiveRole'].filter(k=>typeof window[k]!=='function');if(missing.length){console.warn('OceanJet V78 missing functions:',missing.join(', '));}else{console.info('OceanJet V78 core functions OK');}};



