/* ======================================================================
   V79 AI-MANAGED DUTY COMMAND UPGRADE
   Built on latest V78/V76 full source. Event-driven only.
   Adds duty briefing, closeout, evidence chain-of-custody, baggage audit,
   operations readiness, and stronger dashboard/system reports.
   No setInterval, no DOM observer, no recovery overlay, no scanner automation.
   ====================================================================== */
function v79InjectStyles(){
  if(document.getElementById('v79DutyStyles')) return;
  const css=`
  .v79Panel{border:1px solid rgba(0,184,217,.28);background:linear-gradient(135deg,rgba(0,184,217,.12),rgba(35,196,131,.055));border-radius:24px;padding:16px;box-shadow:var(--shadow)}
  .v79ScoreRing{width:92px;height:92px;border-radius:50%;display:grid;place-items:center;background:conic-gradient(var(--ok) calc(var(--score)*1%),rgba(255,255,255,.12) 0);position:relative;margin:auto}.v79ScoreRing:after{content:"";position:absolute;inset:10px;border-radius:50%;background:var(--card)}.v79ScoreRing b{position:relative;z-index:2;font-size:1.45rem}.v79CommandGrid{display:grid;grid-template-columns:1.15fr .85fr;gap:14px;align-items:start}.v79MetricGrid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.v79Metric{border:1px solid var(--line);background:rgba(255,255,255,.045);border-radius:17px;padding:12px;display:grid;gap:4px}.v79Metric span{color:var(--muted);font-size:.76rem;text-transform:uppercase;letter-spacing:.06em;font-weight:950}.v79Metric b{font-size:1.25rem}.v79Metric small{color:var(--muted);font-weight:750}.v79RiskList{display:grid;gap:8px}.v79Risk{display:flex;gap:10px;align-items:flex-start;border:1px solid var(--line);background:rgba(255,255,255,.045);border-radius:15px;padding:10px}.v79Risk i{font-style:normal;width:28px;height:28px;border-radius:999px;display:grid;place-items:center;background:rgba(247,183,49,.16)}.v79Risk.high i{background:rgba(255,92,122,.18)}.v79Risk.ok i{background:rgba(35,196,131,.16)}.v79CheckGrid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.v79Check{display:flex;gap:10px;align-items:flex-start;border:1px solid var(--line);border-radius:15px;padding:10px;background:rgba(255,255,255,.045);cursor:pointer}.v79Check input{width:18px;height:18px;margin-top:2px}.v79Check b{display:block}.v79Check span{display:block;color:var(--muted);font-size:.82rem;margin-top:3px}.v79ActionGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.v79ActionGrid button{text-align:left;min-height:86px;display:grid;align-content:start;gap:5px}.v79ActionGrid button span{color:var(--muted);font-size:.82rem}.v79DutyText{min-height:138px}.v79PublicBoard{background:#fff;color:#111;border-radius:22px;padding:22px;box-shadow:0 14px 38px rgba(0,0,0,.18)}.v79PublicBoard h2{text-align:center;margin:0 0 10px}.v79PublicBoard .now{text-align:center;font-size:1.45rem;font-weight:950;margin:12px 0}.v79PublicBoard .trip{border:1px solid #ddd;border-radius:16px;padding:12px;margin:8px 0}.v79PublicBoard .status{display:inline-block;border-radius:999px;padding:5px 9px;background:#eef7ff;font-weight:850}.v79RateTable{display:grid;grid-template-columns:repeat(4,1fr);gap:9px}.v79RateCell{border:1px solid var(--line);border-radius:14px;padding:10px;background:rgba(255,255,255,.045)}.v79RateCell b{display:block}.v79RateCell span{font-size:.78rem;color:var(--muted)}.v79Signature{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-top:18px}.v79Signature div{border-top:1px solid #222;text-align:center;padding-top:8px;font-size:.82rem}
  @media(max-width:940px){.v79CommandGrid{grid-template-columns:1fr}.v79MetricGrid{grid-template-columns:repeat(2,1fr)}.v79ActionGrid{grid-template-columns:repeat(2,1fr)}.v79CheckGrid{grid-template-columns:1fr}.v79RateTable{grid-template-columns:repeat(2,1fr)}}
  @media(max-width:560px){.v79MetricGrid,.v79ActionGrid,.v79RateTable{grid-template-columns:1fr}.v79Panel{padding:13px}.v79Signature{grid-template-columns:1fr}.content{padding-bottom:calc(var(--bottom) + 120px)}}
  @media print{.noPrint,.topbar,.sidebar,.bottomNav,.drawerOverlay,.toast{display:none!important}.app{display:block}.content{padding:0;max-width:none}.card,.hero{box-shadow:none!important}.v79PublicBoard{box-shadow:none;border:0}}
  `;
  const tag=document.createElement('style');tag.id='v79DutyStyles';tag.textContent=css;document.head.appendChild(tag);
}
function v79Today(){return typeof v71YMD==='function'?v71YMD():new Date().toISOString().slice(0,10)}
function v79EnsureExtras(){
  if(typeof ensureData==='function'){};
  state.data.trips ||= [];
  state.data.v79 ||= {day:{},routeNotices:{},lastCloseout:'',lastRelink:'',packetCount:0};
  const day=v79Today();
  state.data.v79.day[day] ||= {checks:{},notes:'',closeout:{}};
  state.data.cases ||= [];state.data.claims ||= [];state.data.transactions ||= [];state.data.receipts ||= [];state.data.audit ||= [];
}
const v79BaseEnsureData = ensureData;
ensureData = function(){v79BaseEnsureData();v79EnsureExtras();};
function v79TripRows(){try{if(typeof v78Rows==='function') return v78Rows();}catch(e){} try{if(typeof v77TripRows==='function') return v77TripRows().map(r=>({trip:r.trip,info:r.info||{status:r.trip.manualStatus||'Scheduled'}}));}catch(e){} return (state.data.trips||[]).map(t=>({trip:t,info:{status:t.manualStatus||'Scheduled'}}));}
function v79StatusCounts(){const rows=v79TripRows();const counts={Scheduled:0,Boarding:0,'Departing Soon':0,Departed:0,Delayed:0,Cancelled:0,Closed:0};rows.forEach(r=>{const s=r.info?.status||r.trip?.manualStatus||'Scheduled';counts[s]=(counts[s]||0)+1});return {rows,counts};}
function v79OpenRecords(){return [...(state.data.claims||[]).map(x=>({...x,_kind:'Claim'})),...(state.data.cases||[]).map(x=>({...x,_kind:'Evidence'}))].filter(x=>!['Done','Rejected','Closed'].includes(x.status||''));}
function v79MissingEvidencePairs(){return (state.data.cases||[]).filter(x=>!(x.photos&&x.photos.stub)||!(x.photos&&x.photos.damage));}
function v79UnlinkedRecords(){return [...(state.data.claims||[]),...(state.data.cases||[]),...(state.data.transactions||[])].filter(x=>!x.tripId&&!x.tripCode&&(x.route||x.routeLabel));}
function v79Score(){
  v79EnsureExtras();
  let score=100; const {rows,counts}=v79StatusCounts();
  if(!rows.length) score-=14;
  rows.forEach(r=>{const t=r.trip||{}; if(!t.code)score-=2;if(!t.vessel)score-=2;if(!t.route)score-=2;if(!t.gate||/TBA/i.test(t.gate))score-=1;if(!t.time)score-=2;});
  if(v79MissingEvidencePairs().length) score-=Math.min(16,v79MissingEvidencePairs().length*4);
  if(v79UnlinkedRecords().length) score-=Math.min(10,v79UnlinkedRecords().length*2);
  if((state.data.audit||[]).length<3) score-=4;
  if(typeof storagePercent==='function' && storagePercent()>82) score-=8;
  if((counts.Delayed||0)+(counts.Cancelled||0)>0) score-=4;
  const day=state.data.v79.day[v79Today()]||{checks:{}}; const checks=Object.values(day.checks||{}).filter(Boolean).length; score+=Math.min(8,checks);
  return Math.max(0,Math.min(99,Math.round(score)));
}
function v79Risks(limit=8){
  v79EnsureExtras(); const risks=[]; const {rows,counts}=v79StatusCounts();
  if(!rows.length) risks.push(['high','No vessel trips loaded','Load Cebu day plan or create today\'s first trip.']);
  rows.filter(r=>!(r.trip?.vessel)).slice(0,3).forEach(r=>risks.push(['high','Trip missing vessel',`${r.trip?.code||'Trip'} needs vessel name.`]));
  rows.filter(r=>!r.trip?.gate||/TBA/i.test(r.trip?.gate||'')).slice(0,3).forEach(r=>risks.push(['med','Gate not finalized',`${r.trip?.code||'Trip'} needs gate/pier assignment.`]));
  const missing=v79MissingEvidencePairs(); if(missing.length) risks.push(['high','Incomplete evidence pairs',`${missing.length} case(s) missing claim-stub or damage image.`]);
  const unlinked=v79UnlinkedRecords(); if(unlinked.length) risks.push(['med','Records not linked to trip',`${unlinked.length} record(s) can be relinked for cleaner audit.`]);
  if((counts.Delayed||0)>0) risks.push(['med','Delayed trips active',`${counts.Delayed} delayed trip(s) need passenger notice.`]);
  if((counts.Cancelled||0)>0) risks.push(['high','Cancelled trips active',`${counts.Cancelled} cancelled trip(s) need claim/receipt review.`]);
  if(typeof storagePercent==='function'&&storagePercent()>80) risks.push(['med','Storage getting high',`${storagePercent()}% local storage estimate. Export backup.`]);
  if(!risks.length) risks.push(['ok','No critical operational flags','Duty board, records, and evidence are ready.']);
  return risks.slice(0,limit);
}
function v79RiskHtml(limit){return `<div class="v79RiskList">${v79Risks(limit).map(r=>`<div class="v79Risk ${r[0]==='high'?'high':r[0]==='ok'?'ok':''}"><i>${r[0]==='high'?'!':r[0]==='ok'?'✓':'•'}</i><div><b>${esc(r[1])}</b><div class="tiny">${esc(r[2])}</div></div></div>`).join('')}</div>`;}
function v79MetricsHtml(){const s=v79StatusCounts(), rows=s.rows; const open=v79OpenRecords(); return `<div class="v79MetricGrid"><div class="v79Metric"><span>Readiness</span><b>${v79Score()}%</b><small>AI quality score</small></div><div class="v79Metric"><span>Trips</span><b>${rows.length}</b><small>${s.counts.Boarding||0} boarding · ${s.counts['Departing Soon']||0} soon</small></div><div class="v79Metric"><span>Open Work</span><b>${open.length}</b><small>claims + evidence</small></div><div class="v79Metric"><span>Evidence Gap</span><b>${v79MissingEvidencePairs().length}</b><small>missing pair items</small></div><div class="v79Metric"><span>Baggage</span><b>${state.data.transactions.length}</b><small>saved estimates</small></div><div class="v79Metric"><span>Linked</span><b>${Math.max(0,state.data.transactions.length+state.data.claims.length+state.data.cases.length-v79UnlinkedRecords().length)}</b><small>trip-related records</small></div><div class="v79Metric"><span>Storage</span><b>${typeof storageKB==='function'?storageKB():0} KB</b><small>${typeof storagePercent==='function'?storagePercent():0}% estimate</small></div><div class="v79Metric"><span>Audit</span><b>${state.data.audit.length}</b><small>local actions</small></div></div>`;}
function v79DutyChecks(){return [
  ['shift','Shift staff and port verified','Cashier/Admin name, port, and start time are set.'],
  ['trips','Today\'s trips reviewed','Vessel, route, gate, boarding/departure time checked.'],
  ['baggage','Baggage calculator tested','One test estimate generated or calculator opened.'],
  ['evidence','Evidence pairing ready','Claim-stub + damage image flow checked.'],
  ['claims','Claim desk ready','PSN + Last Name claim workflow checked.'],
  ['backup','Backup plan ready','Admin knows where to export JSON/CSV.'],
  ['handover','Handover notes prepared','Important trip/claim/evidence notes entered.'],
  ['public','Public board checked','Now Boarding and next departure display verified.']
];}
function v79CheckRow(k,label,desc){const day=state.data.v79.day[v79Today()];return `<label class="v79Check"><input type="checkbox" ${day.checks[k]?'checked':''} onchange="v79ToggleCheck('${k}',this.checked)"><div><b>${esc(label)}</b><span>${esc(desc)}</span></div></label>`;}
function v79ToggleCheck(key,val){v79EnsureExtras();state.data.v79.day[v79Today()].checks[key]=!!val;audit('Duty checklist updated',`${key}: ${val?'ready':'pending'}`);save();if(state.view==='briefing') briefing();else toast('Checklist updated');}
function v79SaveNotes(){v79EnsureExtras();state.data.v79.day[v79Today()].notes=($('v79Notes')?.value||'').trim();audit('Duty notes saved','briefing notes updated');save();toast('Duty notes saved');}
function v79CloseoutSet(key,val){v79EnsureExtras();state.data.v79.day[v79Today()].closeout[key]=!!val;audit('Closeout checklist updated',`${key}: ${val?'done':'pending'}`);save();if(state.view==='briefing') briefing();}
function v79CloseoutRows(){const opts=[['backup','Backup exported'],['audit','Audit reviewed'],['cash','Settlement checked'],['claims','Claims/evidence handed over'],['board','Boarding board closed/checked'],['cache','GitHub/cache note reviewed']]; const c=state.data.v79.day[v79Today()].closeout||{}; return `<div class="v79CheckGrid">${opts.map(o=>`<label class="v79Check"><input type="checkbox" ${c[o[0]]?'checked':''} onchange="v79CloseoutSet('${o[0]}',this.checked)"><div><b>${esc(o[1])}</b><span>Required before shift handover.</span></div></label>`).join('')}</div>`;}
function briefing(){
  v79InjectStyles();v79EnsureExtras();setTitle('Duty Command Center','Briefing, readiness, closeout, and packets');
  const day=state.data.v79.day[v79Today()]; const checked=Object.values(day.checks||{}).filter(Boolean).length; const checks=v79DutyChecks();
  $('content').innerHTML=hero('Duty Command Center','One staff-controlled page for start-of-day readiness, operational risks, notes, closeout, and printable/exportable packets.','V79 Duty')+`<div class="grid"><div class="card span4"><div class="cardHead"><div><h3>Readiness Score</h3><p>Calculated from trips, evidence, links, storage, and checklist.</p></div><span class="badge ${v79Score()>=84?'ok':v79Score()>=68?'warn':'bad'}">${v79Score()}%</span></div><div class="v79ScoreRing" style="--score:${v79Score()}"><b>${v79Score()}</b></div><div class="miniActions"><button class="primary" onclick="v79RelinkWorkflows()">Relink Records</button><button onclick="runDiagnostics()">Diagnostics</button></div><div id="diagOut" class="notice" style="margin-top:12px">Ready.</div></div><div class="card span8"><div class="cardHead"><div><h3>Operations Snapshot</h3><p>Vessel, claims, evidence, baggage, storage, and audit.</p></div><button class="small" onclick="renderApp('board')">Open Port Ops</button></div>${v79MetricsHtml()}</div><div class="card span7"><div class="cardHead"><div><h3>Start-of-Day Checklist</h3><p>${checked}/${checks.length} items completed for ${esc(v79Today())}.</p></div><span class="badge ${checked===checks.length?'ok':'warn'}">Manual</span></div><div class="v79CheckGrid">${checks.map(x=>v79CheckRow(x[0],x[1],x[2])).join('')}</div></div><div class="card span5"><div class="cardHead"><div><h3>Top Risks</h3><p>Review before opening the counter.</p></div><span class="badge ${v79Risks().some(r=>r[0]==='high')?'bad':'ok'}">${v79Risks().length} flag(s)</span></div>${v79RiskHtml(8)}</div><div class="card span7"><div class="cardHead"><div><h3>Duty Notes</h3><p>Saved locally for today and included in handover packets.</p></div></div><textarea id="v79Notes" class="v79DutyText" placeholder="Gate changes, passenger advisories, vessel notes, claim follow-up, cashier reminders...">${esc(day.notes||'')}</textarea><div class="miniActions"><button class="primary" onclick="v79SaveNotes()">Save Notes</button><button onclick="v79PrintBriefing()">Print Briefing</button></div></div><div class="card span5"><div class="cardHead"><div><h3>Closeout Checklist</h3><p>Use before ending shift.</p></div></div>${v79CloseoutRows()}</div><div class="card span12"><div class="cardHead"><div><h3>Packet & Export Center</h3><p>Manual exports only. Nothing runs in background.</p></div><span class="badge ok">Staff controlled</span></div><div class="v79ActionGrid"><button onclick="v79ExportDutyPacket('briefing')"><b>Briefing TXT</b><span>Trips, risks, notes</span></button><button onclick="v79ExportDutyPacket('closeout')"><b>Closeout TXT</b><span>End-shift packet</span></button><button onclick="v79ExportChainCSV()"><b>Evidence Chain CSV</b><span>Official custody list</span></button><button onclick="v79ExportRateCardCSV()"><b>Baggage Rate CSV</b><span>Route slab audit</span></button><button onclick="v79OpenPublicBoard()"><b>Public Vessel Board</b><span>Printable display</span></button><button onclick="downloadJSON()"><b>Full Backup</b><span>JSON with photos</span></button></div></div></div>`;
  refreshRoleUI();
}
function v79RelinkWorkflows(){
  v79EnsureExtras(); const trips=state.data.trips||[]; let changed=0;
  function best(rec){if(rec.tripId&&trips.some(t=>t.id===rec.tripId)) return null; const hay=[rec.tripCode,rec.vessel,rec.routeLabel,rec.route].join(' ').toLowerCase(); return trips.find(t=>hay&&[t.code,t.vessel,t.routeLabel,t.route].join(' ').toLowerCase().includes((rec.tripCode||'').toLowerCase())&&rec.tripCode) || trips.find(t=>rec.route&&t.route===rec.route) || null;}
  [...state.data.claims,...state.data.cases,...state.data.transactions].forEach(r=>{const t=best(r); if(t){r.tripId=t.id;r.tripCode=t.code;r.vessel=t.vessel;r.route=r.route||t.route;r.routeLabel=r.routeLabel||t.routeLabel||v79RouteLabel(t.route);changed++;}});
  state.data.v79.lastRelink=today(); audit('V79 workflow relink',`${changed} record(s) linked to trips`); save(); toast(`${changed} record(s) relinked`); if(state.view==='briefing') briefing();
}
function v79RouteLabel(route){return (ROUTES&&ROUTES[route]&&ROUTES[route].label)||String(route||'').replace(/_/g,' → ')}
function v79PacketText(mode){
  v79EnsureExtras(); const d=state.data.v79.day[v79Today()]||{}; const s=v79StatusCounts();
  const lines=[]; lines.push('OCEANJET PORTDESK V79 '+(mode==='closeout'?'CLOSEOUT':'DUTY BRIEFING')); lines.push('Generated: '+today()); lines.push('Role: '+cap(state.role)); lines.push('Readiness: '+v79Score()+'%'); lines.push('');
  lines.push('TRIPS'); s.rows.forEach(r=>lines.push(`- ${r.trip.code||'Trip'} | ${r.trip.vessel||'Vessel TBA'} | ${r.trip.routeLabel||v79RouteLabel(r.trip.route)} | ${r.trip.gate||'Gate TBA'} | ${r.trip.time||'-'} | ${r.info.status||r.trip.manualStatus||'Scheduled'}`));
  lines.push(''); lines.push('RISKS'); v79Risks(20).forEach(r=>lines.push(`- [${r[0].toUpperCase()}] ${r[1]}: ${r[2]}`));
  lines.push(''); lines.push('COUNTS'); lines.push(`Claims: ${state.data.claims.length}`); lines.push(`Evidence: ${state.data.cases.length}`); lines.push(`Baggage estimates: ${state.data.transactions.length}`); lines.push(`Audit records: ${state.data.audit.length}`);
  lines.push(''); lines.push('NOTES'); lines.push(d.notes||'No duty notes entered.');
  if(mode==='closeout'){lines.push(''); lines.push('CLOSEOUT'); const c=d.closeout||{}; Object.keys(c).forEach(k=>lines.push(`- ${k}: ${c[k]?'done':'pending'}`));}
  return lines.join('\n');
}
function v79ExportDutyPacket(mode='briefing'){v79EnsureExtras();state.data.v79.packetCount=(state.data.v79.packetCount||0)+1;if(mode==='closeout')state.data.v79.lastCloseout=today();audit('V79 duty packet export',mode);save();download(`OceanJet_PortDesk_V79_${mode}_${Date.now()}.txt`,v79PacketText(mode),'text/plain');toast('Duty packet downloaded');}
function v79PrintBriefing(){modal(`<div class="modalHead noPrint"><h3>Printable Duty Briefing</h3><button class="small" onclick="closeModal()">✕</button></div><pre class="mono" style="white-space:pre-wrap">${esc(v79PacketText('briefing'))}</pre><button class="primary block noPrint" onclick="window.print()">Print</button>`)}
function v79OpenPublicBoard(){
  v79EnsureExtras(); const rows=v79TripRows().slice(0,8); const active=rows.find(r=>['Boarding','Departing Soon'].includes(r.info?.status))||rows.find(r=>!['Departed','Cancelled','Closed'].includes(r.info?.status))||rows[0];
  modal(`<div class="modalHead noPrint"><h3>Public Vessel Board</h3><button class="small" onclick="closeModal()">✕</button></div><div class="v79PublicBoard"><h2>OCEANJET PORT OPERATIONS</h2>${active?`<div class="now">${['Boarding','Departing Soon'].includes(active.info.status)?'NOW BOARDING':'NEXT DEPARTURE'}: ${esc(active.trip.code||'OJ')}</div><div style="text-align:center"><b>${esc(active.trip.vessel||'OceanJet Vessel')}</b><br>${esc(active.trip.routeLabel||v79RouteLabel(active.trip.route))} · ${esc(active.trip.gate||'Gate TBA')}</div>`:'<div class="now">NO ACTIVE TRIP</div>'}<hr>${rows.map(r=>`<div class="trip"><span class="status">${esc(r.info.status||r.trip.manualStatus||'Scheduled')}</span> <b>${esc(r.trip.code||'OJ')}</b> · ${esc(r.trip.vessel||'Vessel TBA')}<br><small>${esc(r.trip.routeLabel||v79RouteLabel(r.trip.route))} · Gate ${esc(r.trip.gate||'TBA')} · Departure ${esc(r.trip.time||'-')}</small></div>`).join('')}<div class="v79Signature"><div>Gate Staff</div><div>Cashier</div><div>Duty Officer</div></div></div><button class="primary block noPrint" style="margin-top:12px" onclick="window.print()">Print Board</button>`);audit('V79 public board opened','print/display');save();
}
function v79RateRows(){const keys=(typeof V77_CALC_ROUTES!=='undefined'?V77_CALC_ROUTES:Object.keys(ROUTES||{})).filter(k=>ROUTES[k]);return keys.map(k=>{const r=ROUTES[k];const n=r.slab?.normal||[0,0,0];const f=r.slab?.fragile||[0,0,0];return {route:r.label,normal:`${n[0]}/${n[1]}/${n[2]}`,fragile:`${f[0]}/${f[1]}/${f[2]}`,travel:r.travel||''};});}
function v79BaggageAuditCard(){const d=state.lastCalc||(typeof v79PrevCompute==='function'?v79PrevCompute(false):{});const route=$('calcRoute')?.value||d.route||'cebu_maasin';const r=ROUTES[route]||{};const rates=(r.slab&&r.slab[($('calcMode')?.value||d.mode||'normal')])||[0,0,0];return `<div class="card span12" id="v79BaggageAudit"><div class="cardHead"><div><h3>Baggage Formula Audit</h3><p>Preserves organized calculator UI while showing staff-verifiable slab rates.</p></div><span class="badge ok">Baggage-only</span></div><div class="v79RateTable"><div class="v79RateCell"><span>Route</span><b>${esc(r.label||v79RouteLabel(route))}</b></div><div class="v79RateCell"><span>Free Allowance</span><b>Tourist 10kg / Business 20kg</b></div><div class="v79RateCell"><span>Slab Rates</span><b>${rates.map(x=>peso(x)).join(' · ')}</b></div><div class="v79RateCell"><span>Last Estimate</span><b>${peso(d.baggage||d.grand||0)}</b></div></div><div class="miniActions"><button onclick="v79ExportRateCardCSV()">Export Rate CSV</button><button onclick="v79CopyBaggageFormula()">Copy Formula Summary</button></div></div>`;}
function v79CopyBaggageFormula(){const d=typeof compute==='function'?compute(false):(state.lastCalc||{});const text=`OceanJet baggage estimate\nRoute: ${d.routeLabel||''}\nPassengers: ${d.pax||''}\nWeight: ${d.weight||d.kg||0} kg\nFree allowance: ${d.freeTotal||d.free||0} kg\nChargeable/excess: ${d.excess||d.charge||0} kg\nTier/Slab 1: ${peso(d.t1||d.slab?.c1||0)}\nTier/Slab 2: ${peso(d.t2||d.slab?.c2||0)}\nTier/Slab 3: ${peso(d.t3||d.slab?.c3||0)}\nBaggage estimate: ${peso(d.baggage||d.grand||0)}`;navigator.clipboard?.writeText(text).then(()=>toast('Formula copied')).catch(()=>modal(`<pre class="mono">${esc(text)}</pre>`));}
