function v79EvidenceChainCard(){const complete=(state.data.cases||[]).filter(x=>x.photos?.stub&&x.photos?.damage).length;const locked=(state.data.cases||[]).filter(x=>x.locked).length;return `<div class="card span12"><div class="cardHead"><div><h3>Evidence Chain-of-Custody</h3><p>Manual official controls for complete paired evidence records.</p></div><span class="badge ${v79MissingEvidencePairs().length?'warn':'ok'}">${locked}/${complete} locked</span></div><div class="v79MetricGrid"><div class="v79Metric"><span>Complete Pairs</span><b>${complete}</b><small>stub + damage</small></div><div class="v79Metric"><span>Locked</span><b>${locked}</b><small>official records</small></div><div class="v79Metric"><span>Incomplete</span><b>${v79MissingEvidencePairs().length}</b><small>needs review</small></div><div class="v79Metric"><span>Open Queue</span><b>${v79OpenRecords().length}</b><small>claims/evidence</small></div></div><div class="miniActions"><button class="primary" onclick="v79SealCompleteEvidence()">Lock Complete Evidence</button><button onclick="v79ExportChainCSV()">Export Chain CSV</button><button onclick="renderApp('queue')">Open Queue</button></div></div>`;}
function v79SealCompleteEvidence(){const rows=(state.data.cases||[]).filter(x=>!x.locked&&x.psn&&x.last&&x.photos?.stub&&x.photos?.damage);if(!rows.length){toast('No complete unlocked evidence');return}if(!confirm(`Lock ${rows.length} complete evidence record(s)? Locked records are marked official.`))return;rows.forEach(x=>{x.locked=true;x.lockedAt=today();x.status=x.status||'Ready for Review';x.chainId=x.chainId||('OJ-EVD-'+String(x.id||uid('case')).slice(-8).toUpperCase());});audit('V79 evidence locked',`${rows.length} complete record(s)`);save();toast('Evidence locked');if(state.view==='damage') damage();else if(state.view==='queue') queue();}
function v79ExportChainCSV(){const rows=(state.data.cases||[]).map(x=>({time:x.time||'',chainId:x.chainId||'',psn:x.psn||'',last:x.last||'',trip:x.tripCode||'',route:x.routeLabel||'',type:x.type||'',score:x.score||evidenceScore?.(x)||'',locked:x.locked?'YES':'NO',lockedAt:x.lockedAt||'',hasStub:x.photos?.stub?'YES':'NO',hasDamage:x.photos?.damage?'YES':'NO',status:x.status||''}));download('OceanJet_PortDesk_V79_Evidence_Chain_'+Date.now()+'.csv',csv(rows),'text/csv');audit('V79 evidence chain CSV export',`${rows.length} record(s)`);save();toast('Evidence chain CSV downloaded');}
