function v80InjectStyles(){
  if(document.getElementById('v80CommandStyles')) return;
  const css=`
  .v80Tower{border:1px solid rgba(0,184,217,.32);background:linear-gradient(145deg,rgba(0,184,217,.15),rgba(35,196,131,.07));border-radius:26px;padding:16px;box-shadow:var(--shadow)}
  .v80HeroStrip{display:grid;grid-template-columns:1.05fr .95fr;gap:14px;align-items:stretch}.v80Now{border:1px solid rgba(0,184,217,.35);border-radius:22px;padding:16px;background:rgba(0,184,217,.1);display:grid;gap:9px}.v80Now h2{margin:0;font-size:1.55rem}.v80Now .big{font-size:2rem;font-weight:950;line-height:1}.v80Now .sub{color:var(--muted);font-weight:800}.v80BoardGrid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.v80Cell{border:1px solid var(--line);background:rgba(255,255,255,.045);border-radius:18px;padding:12px;min-height:84px}.v80Cell span{display:block;color:var(--muted);font-size:.76rem;text-transform:uppercase;letter-spacing:.07em;font-weight:950}.v80Cell b{font-size:1.36rem}.v80Cell small{color:var(--muted);font-weight:750}.v80LaneGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.v80Lane{border:1px solid var(--line);background:rgba(255,255,255,.035);border-radius:20px;padding:12px;min-height:150px}.v80Lane h4{margin:0 0 10px}.v80TripMini{border:1px solid rgba(255,255,255,.12);background:rgba(255,255,255,.045);border-radius:16px;padding:10px;margin:8px 0;display:grid;gap:6px}.v80TripMini .top{display:flex;gap:8px;justify-content:space-between;align-items:center}.v80TripMini .meta{display:flex;flex-wrap:wrap;gap:7px;color:var(--muted);font-size:.82rem;font-weight:750}.v80TripMini .actions{display:flex;gap:7px;flex-wrap:wrap}.v80Issue{border:1px solid var(--line);border-radius:16px;padding:10px;background:rgba(255,255,255,.045);display:flex;gap:10px;align-items:flex-start}.v80Issue+.v80Issue{margin-top:8px}.v80Issue i{font-style:normal;width:30px;height:30px;border-radius:999px;display:grid;place-items:center;background:rgba(247,183,49,.16)}.v80Issue.high i{background:rgba(255,92,122,.18)}.v80Issue.ok i{background:rgba(35,196,131,.16)}.v80Timeline{display:grid;gap:8px}.v80TimeRow{display:grid;grid-template-columns:82px 1fr auto;gap:10px;align-items:center;border:1px solid var(--line);border-radius:15px;padding:10px;background:rgba(255,255,255,.04)}.v80TimeRow .time{font-weight:950}.v80TimeRow .trip b{display:block}.v80TimeRow .trip span{display:block;color:var(--muted);font-size:.82rem}.v80Pill{display:inline-flex;align-items:center;gap:5px;border-radius:999px;padding:5px 9px;font-weight:900;font-size:.76rem;border:1px solid var(--line)}.v80Pill.ok{background:rgba(35,196,131,.12);color:#baf7dd}.v80Pill.warn{background:rgba(247,183,49,.14);color:#ffe4a3}.v80Pill.bad{background:rgba(255,92,122,.15);color:#ffc4cf}.v80Pill.info{background:rgba(0,184,217,.14);color:#b8f5ff}.v80FormGrid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.v80IncidentList{display:grid;gap:8px}.v80Incident{border:1px solid var(--line);background:rgba(255,255,255,.04);border-radius:16px;padding:10px}.v80Incident .top{display:flex;justify-content:space-between;gap:10px}.v80RoleMatrix{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.v80RoleBox{border:1px solid var(--line);border-radius:17px;padding:12px;background:rgba(255,255,255,.04)}.v80RoleBox ul{margin:8px 0 0;padding-left:18px;color:var(--muted)}.v80FooterPad{height:calc(var(--bottom) + 55px)}
  @media(max-width:980px){.v80HeroStrip{grid-template-columns:1fr}.v80BoardGrid{grid-template-columns:repeat(2,1fr)}.v80LaneGrid{grid-template-columns:1fr}.v80RoleMatrix{grid-template-columns:1fr}.v80TimeRow{grid-template-columns:70px 1fr}.v80TimeRow>span:last-child{grid-column:1/-1;justify-self:start}.v80FormGrid{grid-template-columns:1fr}}
  @media(max-width:560px){.v80Tower{padding:13px}.v80BoardGrid{grid-template-columns:1fr}.v80Now .big{font-size:1.55rem}.v80Cell b{font-size:1.15rem}.content{padding-bottom:calc(var(--bottom) + 130px)}}
  `;
  const tag=document.createElement('style');tag.id='v80CommandStyles';tag.textContent=css;document.head.appendChild(tag);
}
function v80Ensure(){
  if(typeof ensureData==='function'){};
  state.data.trips ||= [];
  state.data.claims ||= [];
  state.data.cases ||= [];
  state.data.transactions ||= [];
  state.data.receipts ||= [];
  state.data.audit ||= [];
  state.data.v80 ||= {settings:{boardMins:12,soonMins:5,departGraceMins:10,closeMins:0},incidents:[],shiftNotes:'',lastPacket:'',reconcileCount:0};
  state.data.v80.settings ||= {boardMins:12,soonMins:5,departGraceMins:10,closeMins:0};
  state.data.v80.incidents ||= [];
}
const v80PrevEnsureData=ensureData;
ensureData=function(){v80PrevEnsureData();v80Ensure();};
function v80YMD(){try{return (typeof v79Today==='function'?v79Today():new Date().toISOString().slice(0,10));}catch(e){return new Date().toISOString().slice(0,10)}}
function v80RouteLabel(t){return t?.routeLabel||((typeof v77RouteLabel==='function')?v77RouteLabel(t?.route):((ROUTES&&ROUTES[t?.route])?ROUTES[t.route].label:(t?.route||'-')))}
function v80TripTime(t){return t?.time||t?.departureTime||t?.depart||t?.departure||''}
function v80ParseTime(raw){
  const s=String(raw||'').trim(); const m=s.match(/(\d{1,2})\s*:\s*(\d{2})\s*(AM|PM)?/i); if(!m) return null;
  let h=Number(m[1]), mi=Number(m[2]); const ap=(m[3]||'').toUpperCase();
  if(ap==='PM'&&h<12)h+=12; if(ap==='AM'&&h===12)h=0;
  const d=new Date(); d.setHours(h,mi,0,0); return d;
}
function v80TimeLabel(d){if(!d)return '-';try{return d.toLocaleTimeString('en-PH',{hour:'numeric',minute:'2-digit'});}catch(e){return String(d)}}
function v80TripRows(){
  try{if(typeof v79TripRows==='function') return v79TripRows().map(r=>({trip:r.trip,info:r.info||v80Status(r.trip)}));}catch(e){}
  try{if(typeof v77TripRows==='function') return v77TripRows().map(r=>({trip:r.trip,info:r.info||v80Status(r.trip)}));}catch(e){}
  return (state.data.trips||[]).map(t=>({trip:t,info:v80Status(t)}));
}
function v80Status(t){
  v80Ensure(); const cfg=state.data.v80.settings||{}; const manual=t?.manualStatus||t?.statusOverride||t?.status;
  const hard=['Delayed','Cancelled','Departed','Closed'];
  const dep=v80ParseTime(v80TripTime(t)); let suggested='Scheduled', phase='Not within boarding window', boarding=null, soon=null, departedAt=null;
  if(dep){
    boarding=new Date(dep.getTime()-(Number(cfg.boardMins)||12)*60000);
    soon=new Date(dep.getTime()-(Number(cfg.soonMins)||5)*60000);
    departedAt=new Date(dep.getTime()+(Number(cfg.departGraceMins)||10)*60000);
    const now=new Date();
    if(now>=departedAt) suggested='Departed'; else if(now>=dep) suggested='Closed'; else if(now>=soon) suggested='Departing Soon'; else if(now>=boarding) suggested='Boarding';
    phase=suggested==='Scheduled'?`Boarding opens ${v80TimeLabel(boarding)}`:suggested==='Boarding'?`Gate active until ${v80TimeLabel(dep)}`:suggested==='Departing Soon'?`Final call before ${v80TimeLabel(dep)}`:suggested==='Closed'?`Grace window until ${v80TimeLabel(departedAt)}`:'Scheduled departure elapsed';
  }
  const status=hard.includes(manual)?manual:(manual==='Boarding'||manual==='Departing Soon'||manual==='Scheduled'?manual:suggested);
  return {status,suggested,manual:manual||'',boarding,departure:dep,departedAt,phase,source:manual?'Manual/recorded':'Time suggestion'};
}
function v80Badge(status){const s=String(status||'Scheduled');const cls=s==='Boarding'||s==='Departed'?'ok':s==='Delayed'||s==='Closed'||s==='Departing Soon'?'warn':s==='Cancelled'?'bad':'info';return `<span class="v80Pill ${cls}">${esc(s)}</span>`}
function v80Summary(){
  v80Ensure(); const rows=v80TripRows().map(r=>({trip:r.trip,info:v80Status(r.trip)}));
  const buckets={Scheduled:[],Boarding:[], 'Departing Soon':[], Closed:[], Departed:[], Delayed:[], Cancelled:[]};
  rows.forEach(r=>{(buckets[r.info.status] ||= []).push(r)});
  const byDep=[...rows].filter(r=>r.info.departure).sort((a,b)=>a.info.departure-b.info.departure);
  return {rows,buckets,now:buckets.Boarding[0]||buckets['Departing Soon'][0]||null,next:byDep.find(r=>!['Departed','Cancelled','Closed'].includes(r.info.status))||null,openClaims:(state.data.claims||[]).filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')).length,reviewEvidence:(state.data.cases||[]).filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')).length,estimates:(state.data.transactions||[]).length,incidents:(state.data.v80.incidents||[]).filter(x=>x.status!=='Resolved')};
}
function v80MetricCards(){const s=v80Summary();return `<div class="v80BoardGrid"><div class="v80Cell"><span>Now Boarding</span><b>${s.now?esc(s.now.trip.code||'-'):'-'}</b><small>${s.now?esc(v80RouteLabel(s.now.trip)):'No active gate'}</small></div><div class="v80Cell"><span>Next Departure</span><b>${s.next?esc(s.next.trip.code||'-'):'-'}</b><small>${s.next?v80TimeLabel(s.next.info.departure):'No upcoming trip'}</small></div><div class="v80Cell"><span>Trips Today</span><b>${s.rows.length}</b><small>${s.buckets.Delayed.length} delayed · ${s.buckets.Cancelled.length} cancelled</small></div><div class="v80Cell"><span>Open Work</span><b>${s.openClaims+s.reviewEvidence}</b><small>${s.openClaims} claims · ${s.reviewEvidence} evidence</small></div></div>`}
function v80HeroBoard(){const s=v80Summary(), now=s.now, next=s.next;return `<div class="v80HeroStrip"><div class="v80Now"><span class="badge ok">Command Control</span><h2>${now?'Now Boarding':'Boarding Monitor'}</h2><div class="big">${now?esc(now.trip.code||'-'):'No active boarding'}</div><div class="sub">${now?`${esc(now.trip.vessel||'Vessel TBA')} · ${esc(v80RouteLabel(now.trip))} · Gate ${esc(now.trip.gate||'TBA')}`:'Create or open a trip to begin boarding control.'}</div>${now?`<div>${v80Badge(now.info.status)} <span class="tiny">Boarding ${v80TimeLabel(now.info.boarding)} · Depart ${v80TimeLabel(now.info.departure)}</span></div>`:''}</div><div class="v80Now"><span class="badge warn">Next Movement</span><h2>${next?'Next Departure':'No upcoming departure'}</h2><div class="big">${next?esc(next.trip.code||'-'):'-'}</div><div class="sub">${next?`${esc(next.trip.vessel||'Vessel TBA')} · ${esc(v80RouteLabel(next.trip))} · ${v80TimeLabel(next.info.departure)}`:'Load trips or add a schedule for today.'}</div>${next?`<div>${v80Badge(next.info.status)} <span class="tiny">${esc(next.info.phase)}</span></div>`:''}</div></div>`}
function v80Issues(limit=8){
  const s=v80Summary(), issues=[];
  if(!s.rows.length) issues.push(['high','No trips loaded','Add today\'s vessel trips to activate the operations board.']);
  s.rows.filter(r=>!r.trip.vessel).slice(0,3).forEach(r=>issues.push(['high','Missing vessel',`${r.trip.code||'Trip'} needs vessel name before public display.`]));
  s.rows.filter(r=>!r.trip.gate||/TBA/i.test(r.trip.gate||'')).slice(0,3).forEach(r=>issues.push(['med','Gate not assigned',`${r.trip.code||'Trip'} needs gate/pier area.`]));
  s.rows.filter(r=>r.info.suggested!==r.info.status&&!['Delayed','Cancelled','Closed','Departed'].includes(r.info.status)).slice(0,3).forEach(r=>issues.push(['med','Status suggestion differs',`${r.trip.code||'Trip'} can be ${r.info.suggested}. Staff may confirm manually.`]));
  const pairGaps=(state.data.cases||[]).filter(x=>!(x.photos&&x.photos.stub)||!(x.photos&&x.photos.damage)); if(pairGaps.length) issues.push(['high','Evidence pair gaps',`${pairGaps.length} case(s) missing stub/damage pair.`]);
  const unlinked=[...(state.data.claims||[]),...(state.data.cases||[]),...(state.data.transactions||[])].filter(x=>!x.tripId&&!x.tripCode&&(x.route||x.routeLabel)); if(unlinked.length) issues.push(['med','Unlinked workflow records',`${unlinked.length} record(s) could be linked to a trip code.`]);
  if(s.incidents.length) issues.push(['med','Open incidents',`${s.incidents.length} active note(s) in command desk.`]);
  if(!issues.length) issues.push(['ok','Operations clear','No critical command-control issues detected.']);
  return issues.slice(0,limit);
}
function v80IssuesHtml(limit=8){return `<div>${v80Issues(limit).map(x=>`<div class="v80Issue ${x[0]==='high'?'high':x[0]==='ok'?'ok':''}"><i>${x[0]==='high'?'!':x[0]==='ok'?'✓':'?'}</i><div><b>${esc(x[1])}</b><div class="tiny">${esc(x[2])}</div></div></div>`).join('')}</div>`}
function v80TimelineHtml(limit=8){const rows=v80Summary().rows.filter(r=>r.info.departure).sort((a,b)=>a.info.departure-b.info.departure).slice(0,limit);return `<div class="v80Timeline">${rows.length?rows.map(r=>`<div class="v80TimeRow"><span class="time">${v80TimeLabel(r.info.departure)}</span><div class="trip"><b>${esc(r.trip.code||'-')} · ${esc(r.trip.vessel||'Vessel TBA')}</b><span>${esc(v80RouteLabel(r.trip))} · Gate ${esc(r.trip.gate||'TBA')} · Boarding ${v80TimeLabel(r.info.boarding)}</span></div>${v80Badge(r.info.status)}</div>`).join(''):'<div class="notice">No trip timeline yet.</div>'}</div>`}
function v80LaneHtml(title,rows,empty){return `<div class="v80Lane"><h4>${esc(title)}</h4>${rows.length?rows.map(r=>`<div class="v80TripMini"><div class="top"><b>${esc(r.trip.code||'-')}</b>${v80Badge(r.info.status)}</div><div class="meta"><span>${esc(r.trip.vessel||'Vessel TBA')}</span><span>${esc(v80RouteLabel(r.trip))}</span><span>Gate ${esc(r.trip.gate||'TBA')}</span><span>${v80TimeLabel(r.info.departure)}</span></div><div class="actions"><button class="small" onclick="v80TripControl('${esc(r.trip.id||r.trip.code||'')}')">Control</button><button class="small" onclick="v80SetTripStatus('${esc(r.trip.id||r.trip.code||'')}','${esc(r.info.suggested)}')">Use Suggestion</button></div></div>`).join(''):`<div class="notice">${esc(empty)}</div>`}</div>`}
function v80LanesHtml(){const b=v80Summary().buckets;return `<div class="v80LaneGrid">${v80LaneHtml('Now / Soon',[...b.Boarding,...b['Departing Soon']],'No active boarding window.')}${v80LaneHtml('Exceptions',[...b.Delayed,...b.Cancelled,...b.Closed],'No delayed, cancelled, or closed trips.')}${v80LaneHtml('Departed',b.Departed.slice(0,6),'No departed trips recorded yet.')}</div>`}
function v80IncidentHtml(){const list=state.data.v80.incidents||[];return `<div class="v80IncidentList">${list.length?list.map(x=>`<div class="v80Incident"><div class="top"><b>${esc(x.title||'Incident')}</b><span>${v80Badge(x.status||'Open')}</span></div><div class="tiny">${esc(x.time||'')} · ${esc(x.tripCode||'No trip')} · ${esc(x.owner||'Staff')}</div><p>${esc(x.note||'')}</p><div class="miniActions"><button class="small good" onclick="v80ResolveIncident('${esc(x.id)}')">Resolve</button><button class="small danger" onclick="v80DeleteIncident('${esc(x.id)}')">Delete</button></div></div>`).join(''):'<div class="notice">No incident notes yet.</div>'}</div>`}
function v80TripOptions(selected){const rows=v80Summary().rows;return `<option value="">No specific trip</option>`+rows.map(r=>`<option value="${esc(r.trip.id||r.trip.code||'')}" ${selected&&(selected===(r.trip.id||r.trip.code))?'selected':''}>${esc(r.trip.code||'-')} · ${esc(r.trip.vessel||'Vessel TBA')} · ${esc(v80RouteLabel(r.trip))}</option>`).join('')}
function v80Control(){v80InjectStyles();v80Ensure();setTitle('Command Control','V80 operations quality and trip workflow');$('content').innerHTML=hero('Command Control Tower','AI-managed, staff-controlled operations view for trips, claims, evidence, baggage, and handover.','V80')+`<div class="grid"><div class="card span12 v80Tower">${v80HeroBoard()}<div style="margin-top:12px">${v80MetricCards()}</div></div><div class="card span8"><div class="cardHead"><div><h3>Trip Status Lanes</h3><p>Manual overrides remain visible. Time suggestions do not secretly overwrite staff decisions.</p></div><div class="miniActions"><button class="small primary" onclick="renderApp('board')">Open Trip Board</button><button class="small" onclick="v80ExportTripsCSV()">Export Trips CSV</button></div></div>${v80LanesHtml()}</div><div class="card span4"><div class="cardHead"><div><h3>Command Risk List</h3><p>Actionable items for today.</p></div><span class="badge ${v80Issues()[0]?.[0]==='ok'?'ok':'warn'}">${v80Issues().length} checks</span></div>${v80IssuesHtml(7)}</div><div class="card span7"><div class="cardHead"><div><h3>Departure Timeline</h3><p>Boarding time uses ${Number(state.data.v80.settings.boardMins)||12} minutes before departure.</p></div><button class="small" onclick="v80OpenSettings()">Logic Settings</button></div>${v80TimelineHtml(10)}</div><div class="card span5"><div class="cardHead"><div><h3>Incident Desk</h3><p>Manual notes for delays, claims, baggage, or gate coordination.</p></div><button class="small primary" onclick="v80OpenIncidentModal()">Add Note</button></div>${v80IncidentHtml()}</div><div class="card span12"><div class="cardHead"><div><h3>Workflow Actions</h3><p>Manual exports and relinking tools. No hidden background action.</p></div><span class="badge ok">Staff Controlled</span></div><div class="quick"><button onclick="v80ReconcileWorkflows()"><span class="ico">🔗</span><b>Relink Workflows</b><span class="tiny">Match claims/evidence/estimates by trip route or code</span></button><button onclick="v80ExportDutyPacket()"><span class="ico">📦</span><b>Command Packet</b><span class="tiny">TXT handover summary</span></button><button onclick="v80ExportIssuesCSV()"><span class="ico">⚠️</span><b>Risk CSV</b><span class="tiny">Export risk list</span></button><button onclick="v80OpenPublicDisplay()"><span class="ico">🖥️</span><b>Public Board</b><span class="tiny">Print vessel display</span></button></div></div><div class="v80FooterPad span12"></div></div>`;refreshRoleUI&&refreshRoleUI();}
function v80OpenSettings(){v80Ensure();const c=state.data.v80.settings;modal(`<div class="modalHead"><h3>V80 Boarding Logic Settings</h3><button class="small" onclick="closeModal()">✕</button></div><div class="formGrid"><label>Boarding starts minutes before departure<input id="v80BoardMins" type="number" min="5" max="45" value="${Number(c.boardMins)||12}"></label><label>Departing soon minutes before departure<input id="v80SoonMins" type="number" min="1" max="20" value="${Number(c.soonMins)||5}"></label><label>Departed grace minutes after departure<input id="v80GraceMins" type="number" min="0" max="45" value="${Number(c.departGraceMins)||10}"></label></div><div class="notice" style="margin-top:12px">These settings only affect staff-visible suggestions. They do not secretly change trips.</div><div class="miniActions"><button class="primary" onclick="v80SaveSettings()">Save Settings</button><button onclick="closeModal()">Cancel</button></div>`)}
function v80SaveSettings(){const c=state.data.v80.settings;c.boardMins=Math.max(5,Number($('v80BoardMins')?.value)||12);c.soonMins=Math.max(1,Number($('v80SoonMins')?.value)||5);c.departGraceMins=Math.max(0,Number($('v80GraceMins')?.value)||10);audit('V80 boarding logic updated',`Board ${c.boardMins}m · Soon ${c.soonMins}m · Grace ${c.departGraceMins}m`);save();closeModal();v80Control();toast('Boarding logic saved')}
function v80FindTrip(id){return (state.data.trips||[]).find(t=>(t.id||t.code)===id)||null}
function v80SetTripStatus(id,status){const t=v80FindTrip(id);if(!t){toast('Trip not found');return}t.manualStatus=status||v80Status(t).suggested;t.lastUpdated=today();audit('V80 trip status confirmed',`${t.code||id} → ${t.manualStatus}`);save();renderApp(state.view||'control');toast('Trip status updated')}
function v80TripControl(id){const t=v80FindTrip(id);if(!t){toast('Trip not found');return}const info=v80Status(t);modal(`<div class="modalHead"><h3>Trip Control · ${esc(t.code||id)}</h3><button class="small" onclick="closeModal()">✕</button></div><div class="formGrid"><label>Vessel<input id="v80TripVessel" value="${esc(t.vessel||'')}"></label><label>Gate / Pier<input id="v80TripGate" value="${esc(t.gate||'')}"></label><label>Status<select id="v80TripStatus"><option ${info.status==='Scheduled'?'selected':''}>Scheduled</option><option ${info.status==='Boarding'?'selected':''}>Boarding</option><option ${info.status==='Departing Soon'?'selected':''}>Departing Soon</option><option ${info.status==='Closed'?'selected':''}>Closed</option><option ${info.status==='Departed'?'selected':''}>Departed</option><option ${info.status==='Delayed'?'selected':''}>Delayed</option><option ${info.status==='Cancelled'?'selected':''}>Cancelled</option></select></label><label>Departure Time<input id="v80TripTime" value="${esc(v80TripTime(t))}"></label><label style="grid-column:1/-1">Control Note<textarea id="v80TripNote" placeholder="Reason for delay/closing/reopen, gate instruction, vessel remarks">${esc(t.opsNote||'')}</textarea></label></div><div class="notice" style="margin-top:12px">Suggested by time: <b>${esc(info.suggested)}</b>. Manual status is staff-controlled and logged.</div><div class="miniActions"><button class="primary" onclick="v80SaveTripControl('${esc(t.id||t.code)}')">Save Trip Control</button><button onclick="v80SetTripStatus('${esc(t.id||t.code)}','${esc(info.suggested)}')">Use Suggestion</button><button class="danger" onclick="v80SafeDeleteTrip('${esc(t.id||t.code)}')">Delete Trip</button></div>`)}
function v80SaveTripControl(id){const t=v80FindTrip(id);if(!t)return; t.vessel=($('v80TripVessel')?.value||'').trim();t.gate=($('v80TripGate')?.value||'').trim();t.manualStatus=$('v80TripStatus')?.value||'Scheduled';t.time=($('v80TripTime')?.value||v80TripTime(t)).trim();t.departureTime=t.time;t.opsNote=($('v80TripNote')?.value||'').trim();t.lastUpdated=today();audit('V80 trip control saved',`${t.code||id} · ${t.manualStatus}`);save();closeModal();renderApp(state.view||'control');toast('Trip control saved')}
function v80SafeDeleteTrip(id){const t=v80FindTrip(id);if(!t)return;if(!confirm(`Delete trip ${t.code||id}? This cannot be undone.`))return;state.data.trips=state.data.trips.filter(x=>(x.id||x.code)!==id);audit('V80 trip deleted',t.code||id);save();closeModal();renderApp('control');toast('Trip deleted')}
function v80OpenIncidentModal(){modal(`<div class="modalHead"><h3>Add Command Note</h3><button class="small" onclick="closeModal()">✕</button></div><div class="v80FormGrid"><label>Trip<select id="v80IncTrip">${v80TripOptions('')}</select></label><label>Status<select id="v80IncStatus"><option>Open</option><option>Watching</option><option>Resolved</option></select></label><label>Owner<input id="v80IncOwner" placeholder="Cashier / Admin / Gate staff"></label><label>Title<input id="v80IncTitle" placeholder="Delay, claim, gate, baggage, customer concern"></label><label style="grid-column:1/-1">Note<textarea id="v80IncNote" placeholder="Write the action taken or issue to monitor"></textarea></label></div><div class="miniActions"><button class="primary" onclick="v80SaveIncident()">Save Note</button><button onclick="closeModal()">Cancel</button></div>`)}
function v80SaveIncident(){const trip=v80FindTrip($('v80IncTrip')?.value||'');const item={id:uid('v80inc'),time:today(),tripId:trip?.id||'',tripCode:trip?.code||'',vessel:trip?.vessel||'',route:trip?v80RouteLabel(trip):'',status:$('v80IncStatus')?.value||'Open',owner:($('v80IncOwner')?.value||state.data.shift.staff||'Staff').trim(),title:($('v80IncTitle')?.value||'Command note').trim(),note:($('v80IncNote')?.value||'').trim()};state.data.v80.incidents.unshift(item);state.data.v80.incidents=state.data.v80.incidents.slice(0,80);audit('V80 command note saved',`${item.tripCode||'General'} · ${item.title}`);save();closeModal();renderApp('control');toast('Command note saved')}
function v80ResolveIncident(id){const x=(state.data.v80.incidents||[]).find(i=>i.id===id);if(!x)return;x.status='Resolved';x.resolvedAt=today();audit('V80 command note resolved',`${x.tripCode||'General'} · ${x.title}`);save();renderApp('control');toast('Note resolved')}
function v80DeleteIncident(id){const x=(state.data.v80.incidents||[]).find(i=>i.id===id);if(!x)return;if(!confirm('Delete this command note?'))return;state.data.v80.incidents=state.data.v80.incidents.filter(i=>i.id!==id);audit('V80 command note deleted',x.title||id);save();renderApp('control');toast('Note deleted')}
function v80ReconcileWorkflows(){v80Ensure();let linked=0;const trips=state.data.trips||[];function pick(x){return trips.find(t=>(x.tripCode&&t.code===x.tripCode)||(x.route&&t.route===x.route)||(x.routeLabel&&v80RouteLabel(t)===x.routeLabel))} [...state.data.claims,...state.data.cases,...state.data.transactions].forEach(x=>{if(x.tripCode||x.tripId)return;const t=pick(x);if(t){x.tripId=t.id||'';x.tripCode=t.code||'';x.vessel=t.vessel||'';x.gate=t.gate||'';x.departureTime=v80TripTime(t);linked++;}});state.data.v80.reconcileCount=(state.data.v80.reconcileCount||0)+1;audit('V80 workflow relink',`${linked} record(s) linked to trips`);save();renderApp(state.view||'control');toast(linked+' record(s) linked')}
function v80ExportTripsCSV(){const rows=v80Summary().rows.map(r=>({code:r.trip.code||'',vessel:r.trip.vessel||'',route:v80RouteLabel(r.trip),gate:r.trip.gate||'',boarding:v80TimeLabel(r.info.boarding),departure:v80TimeLabel(r.info.departure),status:r.info.status,suggested:r.info.suggested,lastUpdated:r.trip.lastUpdated||''}));download('OceanJet_V80_Trips_Command_'+Date.now()+'.csv',csv(rows),'text/csv');audit('V80 trip CSV export',String(rows.length)+' trips');save();toast('Trip CSV downloaded')}
function v80ExportIssuesCSV(){const rows=v80Issues(50).map(x=>({severity:x[0],issue:x[1],detail:x[2]}));download('OceanJet_V80_Command_Risks_'+Date.now()+'.csv',csv(rows),'text/csv');audit('V80 risk CSV export',String(rows.length)+' issues');save();toast('Risk CSV downloaded')}
function v80ExportDutyPacket(){const s=v80Summary();const tripLines=s.rows.map(r=>`- ${r.trip.code||'-'} / ${r.trip.vessel||'-'} / ${v80RouteLabel(r.trip)} / Gate ${r.trip.gate||'TBA'} / Boarding ${v80TimeLabel(r.info.boarding)} / Depart ${v80TimeLabel(r.info.departure)} / ${r.info.status}`).join('\n');const issueLines=v80Issues(30).map(x=>`- [${x[0].toUpperCase()}] ${x[1]}: ${x[2]}`).join('\n');const inc=(state.data.v80.incidents||[]).slice(0,20).map(x=>`- ${x.time} / ${x.tripCode||'General'} / ${x.status} / ${x.title}: ${x.note}`).join('\n');const txt=`OceanJet PortDesk V82 Command Packet\nGenerated: ${today()}\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\nRole: ${state.role}\n\nSUMMARY\nTrips: ${s.rows.length}\nNow Boarding: ${s.now?s.now.trip.code:'-'}\nNext Departure: ${s.next?s.next.trip.code+' '+v80TimeLabel(s.next.info.departure):'-'}\nOpen Claims: ${s.openClaims}\nEvidence Review: ${s.reviewEvidence}\nBaggage Estimates: ${s.estimates}\nOpen Incidents: ${s.incidents.length}\n\nTRIP BOARD\n${tripLines||'-'}\n\nCOMMAND RISKS\n${issueLines||'-'}\n\nINCIDENT NOTES\n${inc||'-'}\n\nLATEST AUDIT\n${state.data.audit.slice(0,35).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail}`).join('\n')}`;state.data.v80.lastPacket=today();audit('V80 command packet export','TXT handover');save();download('OceanJet_V80_Command_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('Command packet downloaded')}
function v80OpenPublicDisplay(){const s=v80Summary();modal(`<div class="modalHead noPrint"><h3>Public Vessel Board</h3><button class="small" onclick="closeModal()">✕</button></div><div class="printArea"><h2 style="text-align:center">OceanJet Vessel Board</h2><p style="text-align:center">${esc(today())}</p>${v80HeroBoard()}<h3>Today\'s Departures</h3>${v80TimelineHtml(12)}</div><div class="miniActions noPrint"><button class="primary" onclick="window.print()">Print Board</button><button onclick="closeModal()">Close</button></div>`)}
function v80DashboardPanel(){return `<div class="card span12 v80Tower"><div class="cardHead"><div><h3>V80 Command Snapshot</h3><p>Trip board, open work, baggage estimates, and evidence readiness in one place.</p></div><button class="small primary" onclick="renderApp('control')">Open Command Control</button></div>${v80MetricCards()}<div style="margin-top:12px">${v80IssuesHtml(4)}</div></div>`}
function v80BoardFooter(){return `<div class="card span12"><div class="cardHead"><div><h3>V80 Smart Boarding Actions</h3><p>Manual confirmation for time-based status suggestions and incident notes.</p></div><button class="small primary" onclick="renderApp('control')">Command Control</button></div>${v80LanesHtml()}</div>`}
function v80EvidenceQA(){const gaps=(state.data.cases||[]).filter(x=>!(x.photos&&x.photos.stub)||!(x.photos&&x.photos.damage));const locked=(state.data.cases||[]).filter(x=>x.locked).length;return `<div class="card span12"><div class="cardHead"><div><h3>V80 Evidence QA</h3><p>Manual-only evidence quality check, chain of custody, and pair completeness.</p></div><span class="badge ${gaps.length?'warn':'ok'}">${gaps.length?'Needs Review':'Ready'}</span></div><div class="v80BoardGrid"><div class="v80Cell"><span>Evidence Cases</span><b>${state.data.cases.length}</b><small>local records</small></div><div class="v80Cell"><span>Complete Pairs</span><b>${Math.max(0,state.data.cases.length-gaps.length)}</b><small>stub + damage</small></div><div class="v80Cell"><span>Locked</span><b>${locked}</b><small>official records</small></div><div class="v80Cell"><span>Linked Trips</span><b>${state.data.cases.filter(x=>x.tripCode).length}</b><small>trip code visible</small></div></div></div>`}
