const v80PrevSystem=system;system=function(){v80InjectStyles();v80Ensure();v80PrevSystem();v80Append(`<div class="card span12"><div class="cardHead"><div><h3>V80 System Integrity</h3><p>Command-control module, role navigation, and workflow QA checks.</p></div><button class="small" onclick="runDiagnostics()">Run Diagnostics</button></div>${v80MetricCards()}<div style="margin-top:12px">${v80IssuesHtml(6)}</div><div class="miniActions"><button class="primary" onclick="renderApp('control')">Open Command Control</button><button onclick="v80ReconcileWorkflows()">Relink Records</button><button onclick="v80ExportDutyPacket()">Export Command Packet</button></div></div>`);v80RefreshChrome();};
const v80PrevSaveClaim=saveClaim;saveClaim=function(){const before=(state.data.claims||[]).length;v80PrevSaveClaim();const after=(state.data.claims||[]).length;if(after>before){const rec=state.data.claims[0];rec.commandVersion='V80';audit('V80 claim workflow indexed',`${rec.psn||''} ${rec.last||''}${rec.tripCode?' · '+rec.tripCode:''}`);save();}};
const v80PrevSaveTransaction=saveTransaction;saveTransaction=function(){const before=(state.data.transactions||[]).length;v80PrevSaveTransaction();const after=(state.data.transactions||[]).length;if(after>before){const rec=state.data.transactions[0];rec.commandVersion='V80';audit('V80 baggage workflow indexed',`${rec.tripCode?rec.tripCode+' · ':''}${rec.routeLabel||''} · ${peso(rec.baggage||rec.grand||0)}`);save();}};
const v80PrevDownloadJSON=downloadJSON;downloadJSON=function(){v80Ensure();state.data.v80.lastPacket=today();state.data.automation.lastBackup=today();audit('V80 full backup export','manual JSON with command-control metadata');save();download('OceanJet_PortDesk_V80_Backup_'+Date.now()+'.json',JSON.stringify({version:APP_VERSION,exportedAt:new Date().toISOString(),commandSummary:v80Summary(),risks:v80Issues(40),data:state.data},null,2),'application/json');toast('V80 backup downloaded')};
const v80PrevRunDiagnostics=runDiagnostics;runDiagnostics=function(){v80Ensure();let base={};try{base=v80PrevRunDiagnostics()||{};}catch(e){base={previousDiagnosticsError:String(e)}}const html=document.documentElement.innerHTML;const d={...base,v80:{version:APP_VERSION,store:STORE,commandControl:'ON',roleNav:(NAVS[state.role]||[]).map(x=>x[0]).join(', '),trips:v80Summary().rows.length,openIncidents:v80Summary().incidents.length,risks:v80Issues(50).length,unpairedEvidence:(state.data.cases||[]).filter(x=>!(x.photos&&x.photos.stub)||!(x.photos&&x.photos.damage)).length,workflowRelinks:state.data.v80.reconcileCount||0,loopRepair:/\bset\s*Interval\s*\(/i.test(html)?'FOUND in legacy text/diagnostic':'none added by V80',domObserver:html.includes('Mutation'+'Observer(')?'FOUND':'none added by V80',manualEvidence:'ON',baggageUi:'organized V55-style preserved'}};const out=$('diagOut');if(out)out.innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>';return d;};
