verifyCoreFunctions=function(){const missing=['dashboard','board','calculator','damage','queue','v80Control','v80ExportDutyPacket','v80ReconcileWorkflows','setActiveRole'].filter(k=>typeof window[k]!=='function');if(missing.length){console.warn('OceanJet V80 missing functions:',missing.join(', '));}else{console.info('OceanJet V80 core functions OK');}};
v80RefreshChrome();



/* ======================================================================
   V81 AI-MANAGED CONTROL FLOOR UPGRADE
   Real event-driven code layer built on V80/V76 full source.
   Preserves organized V55-style baggage calculator UI, baggage-only receipt,
   role-based navigation, and manual evidence workflows.
   No recovery loops, no observer repair, no setInterval UI fixing,
   no auto scanner/capture. All helpers are staff-triggered and logged.
   ====================================================================== */
function v81InjectStyles(){
  if(document.getElementById('v81ControlFloorStyles')) return;
  const css=`
  .v81Floor{border:1px solid rgba(0,184,217,.34);background:linear-gradient(145deg,rgba(0,184,217,.14),rgba(35,196,131,.075));border-radius:28px;padding:16px;box-shadow:var(--shadow)}
  .v81Header{display:grid;grid-template-columns:1fr auto;gap:14px;align-items:center;margin-bottom:14px}.v81Header h2{margin:0;font-size:1.5rem}.v81Header p{margin:5px 0 0;color:var(--muted)}
  .v81ScoreRing{width:112px;height:112px;border-radius:999px;display:grid;place-items:center;background:conic-gradient(var(--ok) calc(var(--score)*1%),rgba(255,255,255,.12) 0);position:relative}.v81ScoreRing:before{content:"";position:absolute;inset:8px;border-radius:inherit;background:var(--card)}.v81ScoreRing b{position:relative;font-size:1.45rem}.v81ScoreRing span{position:relative;font-size:.7rem;color:var(--muted);font-weight:900;text-transform:uppercase;letter-spacing:.07em}
  .v81OpsGrid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.v81OpsTile{border:1px solid var(--line);background:rgba(255,255,255,.045);border-radius:18px;padding:12px;min-height:92px}.v81OpsTile span{display:block;color:var(--muted);font-size:.75rem;text-transform:uppercase;letter-spacing:.06em;font-weight:950}.v81OpsTile b{font-size:1.35rem}.v81OpsTile small{display:block;color:var(--muted);margin-top:3px;font-weight:750}
  .v81RunList{display:grid;gap:9px}.v81RunItem{display:grid;grid-template-columns:auto 1fr auto;gap:10px;align-items:start;border:1px solid var(--line);background:rgba(255,255,255,.04);border-radius:16px;padding:10px}.v81RunItem i{font-style:normal;width:30px;height:30px;border-radius:999px;display:grid;place-items:center;background:rgba(0,184,217,.13)}.v81RunItem.warn i{background:rgba(247,183,49,.17)}.v81RunItem.bad i{background:rgba(255,92,122,.16)}.v81RunItem b{display:block}.v81RunItem span{display:block;color:var(--muted);font-size:.84rem;margin-top:2px}.v81RunItem button{white-space:nowrap}
  .v81LaneGrid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.v81Lane{border:1px solid var(--line);background:rgba(255,255,255,.035);border-radius:18px;padding:11px;min-height:130px}.v81Lane h4{margin:0 0 8px}.v81Mini{border:1px solid rgba(255,255,255,.11);background:rgba(255,255,255,.045);border-radius:14px;padding:9px;margin:7px 0}.v81Mini b{display:block}.v81Mini span{display:block;color:var(--muted);font-size:.82rem}.v81Mini small{display:block;color:var(--soft);font-size:.75rem;margin-top:3px}
  .v81Badge{display:inline-flex;align-items:center;gap:6px;border-radius:999px;padding:6px 9px;border:1px solid var(--line);font-weight:950;font-size:.75rem}.v81Badge.ok{background:rgba(35,196,131,.14);color:#b7f7dc}.v81Badge.warn{background:rgba(247,183,49,.15);color:#ffe1a4}.v81Badge.bad{background:rgba(255,92,122,.14);color:#ffc2ce}.v81Badge.info{background:rgba(0,184,217,.13);color:#b9f7ff}
  .v81Matrix{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.v81Box{border:1px solid var(--line);background:rgba(255,255,255,.04);border-radius:17px;padding:12px}.v81Box h4{margin:0 0 8px}.v81Box ul{margin:8px 0 0;padding-left:18px;color:var(--muted)}
  .v81Checklist{display:grid;grid-template-columns:repeat(2,1fr);gap:8px}.v81Check{display:flex!important;align-items:flex-start;gap:9px;border:1px solid var(--line);background:rgba(255,255,255,.04);border-radius:14px;padding:10px}.v81Check input{width:19px;height:19px;margin-top:2px}.v81Check span{font-weight:850}.v81Check small{display:block;color:var(--muted);font-weight:650;margin-top:2px}
  .v81SearchBox{display:grid;grid-template-columns:1fr auto;gap:8px}.v81TableMini{overflow:auto;border:1px solid var(--line);border-radius:16px}.v81TableMini table{min-width:560px}.v81FooterSpace{height:calc(var(--bottom) + 70px)}
  .v81QaPanel{border:1px solid rgba(0,184,217,.28);background:linear-gradient(135deg,rgba(0,184,217,.08),rgba(255,255,255,.035));border-radius:22px;padding:14px}.v81QaRows{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.v81QaCell{border:1px solid var(--line);border-radius:15px;padding:10px;background:rgba(255,255,255,.04)}.v81QaCell span{display:block;color:var(--muted);font-size:.73rem;font-weight:900;text-transform:uppercase}.v81QaCell b{font-size:1.05rem}.v81QaCell small{display:block;color:var(--muted);margin-top:3px}
  @media(max-width:1020px){.v81OpsGrid,.v81LaneGrid{grid-template-columns:repeat(2,1fr)}.v81Matrix{grid-template-columns:1fr}.v81QaRows{grid-template-columns:1fr 1fr}.v81Header{grid-template-columns:1fr}.v81ScoreRing{width:96px;height:96px}}
  @media(max-width:620px){.v81Floor{padding:13px}.v81OpsGrid,.v81LaneGrid,.v81Checklist,.v81QaRows{grid-template-columns:1fr}.v81RunItem{grid-template-columns:auto 1fr}.v81RunItem button{grid-column:1/-1}.v81SearchBox{grid-template-columns:1fr}.content{padding-bottom:calc(var(--bottom) + 132px)!important}}
  `;
  const tag=document.createElement('style');tag.id='v81ControlFloorStyles';tag.textContent=css;document.head.appendChild(tag);
}
function v81Ensure(){
  state.data.trips ||= [];
  state.data.claims ||= [];
  state.data.cases ||= [];
  state.data.transactions ||= [];
  state.data.audit ||= [];
  state.data.receipts ||= [];
  state.data.v81 ||= {createdAt:today(),shiftChecks:{},handoverNotes:'',lastPacket:'',searchCount:0,manualFixes:0,readinessTarget:99};
  state.data.v81.shiftChecks ||= {};
}
const v81PreviousEnsureData = ensureData;
ensureData = function(){v81PreviousEnsureData();v81Ensure();};
function v81Rows(){try{return v80TripRows().map(r=>({trip:r.trip,info:v80Status(r.trip)}));}catch(e){return (state.data.trips||[]).map(t=>({trip:t,info:{status:t.status||'Scheduled',phase:'-',boarding:null,departure:null}}));}}
function v81StatusKey(s){s=String(s||'Scheduled');return s==='Boarding'||s==='Departed'?'ok':s==='Delayed'||s==='Closed'||s==='Departing Soon'?'warn':s==='Cancelled'?'bad':'info'}
function v81StatusBadge(s){return `<span class="v81Badge ${v81StatusKey(s)}">${esc(s||'Scheduled')}</span>`}
function v81Money(n){try{return typeof v76Money==='function'?v76Money(n):peso(n||0)}catch(e){return '₱'+Number(n||0).toFixed(2)}}
function v81Readiness(){
  v81Ensure(); const rows=v81Rows(), nowRows=rows.filter(r=>['Boarding','Departing Soon'].includes(r.info.status));
  const active=rows.filter(r=>!['Departed','Cancelled'].includes(r.info.status));
  const missingVessel=active.filter(r=>!(r.trip.vessel||'').trim()).length;
  const missingGate=active.filter(r=>!(r.trip.gate||'').trim()).length;
  const noTime=active.filter(r=>!(r.trip.time||r.trip.departureTime||'').trim()).length;
  const unpaired=(state.data.cases||[]).filter(x=>!(x.photos&&x.photos.stub)||!(x.photos&&x.photos.damage)).length;
  const unlocked=(state.data.cases||[]).filter(x=>(x.photos&&x.photos.stub&&x.photos.damage)&&!x.locked).length;
  const unlinkedClaims=(state.data.claims||[]).filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')&&!x.tripCode).length;
  const unlinkedBaggage=(state.data.transactions||[]).filter(x=>!x.tripCode).slice(0,25).length;
  const backupAge=(state.data.automation&&state.data.automation.lastBackup)?0:1;
  let penalties=missingVessel*8+missingGate*6+noTime*8+unpaired*10+unlocked*4+unlinkedClaims*4+Math.min(12,unlinkedBaggage*1)+backupAge*5;
  const score=Math.max(1,Math.min(99,99-penalties));
  const warnings=[];
  if(!rows.length) warnings.push(['bad','No trip board data','Add at least one vessel trip for today.','renderApp(\'board\')']);
  if(missingVessel) warnings.push(['warn','Missing vessel names',`${missingVessel} active trip(s) need vessel names.`, 'renderApp(\'board\')']);
  if(missingGate) warnings.push(['warn','Missing gate / pier',`${missingGate} active trip(s) need boarding location.`, 'renderApp(\'board\')']);
  if(noTime) warnings.push(['bad','Missing departure time',`${noTime} active trip(s) cannot calculate boarding status.`, 'renderApp(\'board\')']);
  if(unpaired) warnings.push(['bad','Incomplete evidence pairs',`${unpaired} evidence case(s) are missing stub or damage photo.`, 'renderApp(\'damage\')']);
  if(unlocked) warnings.push(['warn','Complete evidence not locked',`${unlocked} complete evidence pair(s) can be officially locked.`, 'v81LockCompleteEvidence()']);
  if(unlinkedClaims) warnings.push(['warn','Claims without trip link',`${unlinkedClaims} open claim(s) are not linked to trip code.`, 'renderApp(\'queue\')']);
  if(unlinkedBaggage) warnings.push(['info','Baggage estimates without trip',`${unlinkedBaggage} recent estimate(s) can be linked when trip is known.`, 'renderApp(\'calculator\')']);
  if(backupAge) warnings.push(['info','Backup reminder','No latest backup marker found in this store.', 'downloadJSON()']);
  if(!warnings.length) warnings.push(['ok','Control floor clear','All primary workflow checks look ready.','v81ExportControlPacket()']);
  return {score,rows,nowRows,active,missingVessel,missingGate,noTime,unpaired,unlocked,unlinkedClaims,unlinkedBaggage,warnings,backupAge};
}
function v81ScoreHtml(score){return `<div class="v81ScoreRing" style="--score:${Number(score)||0}"><div style="position:relative;text-align:center"><b>${Number(score)||0}%</b><br><span>ready</span></div></div>`}
function v81OpsTiles(){const s=v81Readiness(); const buckets={Boarding:0,'Departing Soon':0,Scheduled:0,Closed:0,Departed:0,Delayed:0,Cancelled:0};s.rows.forEach(r=>{buckets[r.info.status]=(buckets[r.info.status]||0)+1});return `<div class="v81OpsGrid"><div class="v81OpsTile"><span>Now Boarding</span><b>${buckets.Boarding+buckets['Departing Soon']}</b><small>${s.nowRows[0]?.trip?.code||'No active boarding'}</small></div><div class="v81OpsTile"><span>Total Trips</span><b>${s.rows.length}</b><small>${buckets.Departed} departed · ${buckets.Scheduled} scheduled</small></div><div class="v81OpsTile"><span>Open Claims</span><b>${(state.data.claims||[]).filter(x=>!['Done','Rejected','Closed'].includes(x.status||'')).length}</b><small>${s.unlinkedClaims} missing trip link</small></div><div class="v81OpsTile"><span>Evidence QA</span><b>${(state.data.cases||[]).length}</b><small>${s.unpaired} incomplete · ${s.unlocked} unlockable</small></div></div>`}
function v81RunList(limit=8){const s=v81Readiness();return `<div class="v81RunList">${s.warnings.slice(0,limit).map(w=>`<div class="v81RunItem ${w[0]}"><i>${w[0]==='ok'?'✓':w[0]==='bad'?'!':'•'}</i><div><b>${esc(w[1])}</b><span>${esc(w[2])}</span></div><button class="small" onclick="${w[3]}">Open</button></div>`).join('')}</div>`}
function v81LaneHtml(){const rows=v81Rows();const lanes=['Boarding','Departing Soon','Scheduled','Closed','Departed','Delayed','Cancelled'];return `<div class="v81LaneGrid">${lanes.map(l=>{const subset=rows.filter(r=>r.info.status===l).slice(0,5);return `<div class="v81Lane"><h4>${esc(l)} <span class="tiny">${subset.length}</span></h4>${subset.length?subset.map(r=>`<div class="v81Mini"><b>${esc(r.trip.code||'-')} · ${esc(r.trip.vessel||'Vessel TBA')}</b><span>${esc(v80RouteLabel(r.trip))}</span><small>${esc(r.trip.gate||'Gate TBA')} · Board ${esc(v80TimeLabel(r.info.boarding))} · Depart ${esc(v80TimeLabel(r.info.departure))}</small></div>`).join(''):'<div class="empty">No trips.</div>'}</div>`}).join('')}</div>`}
function v81ChecklistHtml(){const checks=[['manifest','Manifest count checked','Passenger/baggage counts match active trip board.'],['gate','Gate and pier signage checked','Public board and gate location are clear.'],['evidence','Evidence queue reviewed','Incomplete pairs are known before turnover.'],['cashier','Cashier settlement checked','Baggage estimates and receipts are ready.'],['claims','Open claims reviewed','Urgent passenger issues identified.'],['backup','Backup/export packet prepared','Handover packet can be downloaded.']];const obj=state.data.v81.shiftChecks||{};return `<div class="v81Checklist">${checks.map(c=>`<label class="v81Check"><input type="checkbox" ${obj[c[0]]?'checked':''} onchange="v81ToggleCheck('${c[0]}',this.checked)"><span>${esc(c[1])}<small>${esc(c[2])}</small></span></label>`).join('')}</div>`}
function v81ToggleCheck(key,val){v81Ensure();state.data.v81.shiftChecks[key]=!!val;audit('V81 checklist updated',`${key}: ${val?'checked':'unchecked'}`);save();toast('Checklist updated')}
function v81ControlFloor(){v81InjectStyles();v81Ensure();const r=v81Readiness();setTitle('Control Floor','V81 AI-managed operations control');$('content').innerHTML=hero('Operations Control Floor','One professional command surface for boarding, baggage, claims, evidence, QA, exports, and role workflow.','V81 Control')+`<div class="grid"><div class="card span12 v81Floor"><div class="v81Header"><div><h2>Readiness Command</h2><p>Staff-triggered checks only. Suggestions do not secretly change trip status, roles, tabs, evidence, or navigation.</p></div>${v81ScoreHtml(r.score)}</div>${v81OpsTiles()}</div><div class="card span7"><div class="cardHead"><div><h3>Priority Run Sheet</h3><p>Highest-impact workflow items first.</p></div><button class="small primary" onclick="v81ExportControlPacket()">Export Packet</button></div>${v81RunList(10)}</div><div class="card span5"><div class="cardHead"><div><h3>Shift Checklist</h3><p>Manual duty controls for start/mid/end shift.</p></div><span class="badge ok">Manual</span></div>${v81ChecklistHtml()}</div><div class="card span12"><div class="cardHead"><div><h3>Trip Lanes</h3><p>Boarding status from V80 logic plus V81 workflow quality layer.</p></div><div class="miniActions"><button class="small" onclick="renderApp('board')">Open Trip Board</button><button class="small" onclick="v81OpenCommandSearch()">Search</button></div></div>${v81LaneHtml()}</div><div class="card span6"><div class="cardHead"><div><h3>Cross-Module Link Map</h3><p>Find what is connected to trips and what still needs staff review.</p></div><button class="small" onclick="v81ReconcileSmartLinks()">Relink Safely</button></div>${v81LinkMapHtml()}</div><div class="card span6"><div class="cardHead"><div><h3>Role Access Matrix</h3><p>Current role visibility and control expectations.</p></div><span class="badge ${state.role==='admin'?'bad':state.role==='cashier'?'warn':'ok'}">${esc(cap(state.role))}</span></div>${v81RoleMatrix()}</div><div class="card span12"><div class="cardHead"><div><h3>Control Exports</h3><p>Download staff handover data without changing records.</p></div><span class="badge ok">GitHub Pages Safe</span></div><div class="quick"><button onclick="v81ExportControlPacket()"><span class="ico">📦</span><b>V81 Control Packet</b><span class="tiny">TXT handover</span></button><button onclick="v80ExportTripsCSV()"><span class="ico">🛳️</span><b>Trip CSV</b><span class="tiny">Vessel board</span></button><button onclick="v81ExportWorkflowJSON()"><span class="ico">🧾</span><b>Workflow JSON</b><span class="tiny">Links + QA</span></button><button onclick="downloadJSON()"><span class="ico">💾</span><b>Full Backup</b><span class="tiny">All data</span></button></div></div><div class="v81FooterSpace span12"></div></div>`;v81RefreshChrome();}
function v81LinkMapHtml(){const trips=(state.data.trips||[]).length;const txLinked=(state.data.transactions||[]).filter(x=>x.tripCode).length;const claimLinked=(state.data.claims||[]).filter(x=>x.tripCode).length;const caseLinked=(state.data.cases||[]).filter(x=>x.tripCode).length;const receiptsLinked=(state.data.receipts||[]).filter(x=>x.tripCode).length;return `<div class="v81OpsGrid" style="grid-template-columns:repeat(2,1fr)"><div class="v81OpsTile"><span>Trips</span><b>${trips}</b><small>source board</small></div><div class="v81OpsTile"><span>Baggage Linked</span><b>${txLinked}</b><small>${(state.data.transactions||[]).length} estimates total</small></div><div class="v81OpsTile"><span>Claims Linked</span><b>${claimLinked}</b><small>${(state.data.claims||[]).length} claims total</small></div><div class="v81OpsTile"><span>Evidence Linked</span><b>${caseLinked}</b><small>${receiptsLinked} receipts linked</small></div></div>`}
function v81RoleMatrix(){const rows={passenger:['Passenger Hub','Trips & Boarding','Claim form','Claim tracker','Baggage estimate'],cashier:['Cashier Counter','Baggage estimate','Evidence Studio','Review Queue','Port Operations view'],admin:['Admin Command Center','Full trip control','Evidence/claim review','Reports/System tools','Control Floor exports']};return `<div class="v81Matrix">${Object.entries(rows).map(([k,list])=>`<div class="v81Box"><h4>${esc(cap(k))}</h4><ul>${list.map(x=>`<li>${esc(x)}</li>`).join('')}</ul></div>`).join('')}</div>`}
function v81BaggageQA(){let d=null;try{d=(typeof v67LastCalc!=='undefined'&&v67LastCalc)||compute(false);}catch(e){d=null}const linked=d&&d.tripCode;const over=d?Number(d.excess||0)>0:false;const rows=d?[['Route',d.routeLabel||'-',d.routeNote||''],['Allowance',`${Number(d.freeTotal||0).toFixed(1)} kg`,`${d.allowance||0} kg × ${d.pax||1} pax`],['Excess',`${Number(d.excess||0).toFixed(1)} kg`,over?'Chargeable':'Within free allowance'],['Tier Total',v81Money(d.baggage||0),d.mode==='normal'?'Baggage-only estimate':'Fragile/Special mode'],['Trip Link',linked?d.tripCode:'Not linked',linked?`${d.vessel||''} ${d.gate||''}`:'Optional but recommended for duty records'],['Receipt',d?'Ready after compute':'Compute first','Passenger fare excluded']]:[];return `<div class="card span12"><div class="cardHead"><div><h3>V81 Baggage Formula QA</h3><p>Preserves the organized calculator layout while checking readiness, route, allowance, excess, tier total, and baggage-only receipt.</p></div><span class="badge ${d?'ok':'warn'}">${d?'Computed':'Waiting'}</span></div><div class="v81QaPanel"><div class="v81QaRows">${rows.map(x=>`<div class="v81QaCell"><span>${esc(x[0])}</span><b>${esc(String(x[1]))}</b><small>${esc(String(x[2]||''))}</small></div>`).join('')||'<div class="empty">Enter calculator details to see QA.</div>'}</div><div class="miniActions" style="margin-top:12px"><button onclick="compute(false);renderApp('calculator')">Refresh QA</button><button onclick="copyCalcQuote()">Copy Estimate</button><button onclick="downloadReceipt()">Download Receipt</button></div></div></div>`}
function v81EvidenceOps(){const r=v81Readiness();const locked=(state.data.cases||[]).filter(x=>x.locked).length;const official=(state.data.cases||[]).filter(x=>x.photos&&x.photos.stub&&x.photos.damage).length;return `<div class="card span12"><div class="cardHead"><div><h3>V81 Evidence Operations QA</h3><p>Manual chain-of-custody checks for official stub + damage evidence pairs.</p></div><span class="badge ${r.unpaired?'warn':'ok'}">${r.unpaired?'Needs review':'Clean pairs'}</span></div><div class="v81OpsGrid"><div class="v81OpsTile"><span>Total Evidence</span><b>${(state.data.cases||[]).length}</b><small>device-local records</small></div><div class="v81OpsTile"><span>Complete Pairs</span><b>${official}</b><small>stub + damage image</small></div><div class="v81OpsTile"><span>Locked</span><b>${locked}</b><small>official records</small></div><div class="v81OpsTile"><span>Needs Pairing</span><b>${r.unpaired}</b><small>manual upload only</small></div></div><div class="miniActions" style="margin-top:12px"><button onclick="v81LockCompleteEvidence()">Lock Complete Pairs</button><button onclick="v81ExportWorkflowJSON()">Export Workflow JSON</button><button onclick="renderApp('queue')">Open Review Queue</button></div></div>`}
function v81LockCompleteEvidence(){v81Ensure();let count=0;(state.data.cases||[]).forEach(x=>{if(x.photos&&x.photos.stub&&x.photos.damage&&!x.locked){x.locked=true;x.lockedAt=today();x.lockedBy=state.role;x.chainStatus='Official locked pair';count++;}});audit('V81 evidence complete-pair lock',`${count} pair(s) locked`);save();toast(count?`${count} evidence pair(s) locked`:'No unlockable complete pairs');try{renderApp(state.view)}catch(e){}}
function v81ReconcileSmartLinks(){v81Ensure();let links=0;const trips=state.data.trips||[];const findByRoute=(route)=>trips.find(t=>(t.route||'')===route)||null;(state.data.claims||[]).forEach(x=>{if(!x.tripCode){const t=findByRoute(x.route);if(t){Object.assign(x,{tripId:t.id,tripCode:t.code,vessel:t.vessel,gate:t.gate,departureTime:t.departureTime||t.time});links++;}}});(state.data.cases||[]).forEach(x=>{if(!x.tripCode){const claim=(state.data.claims||[]).find(c=>c.psn===x.psn&&String(c.last||'').toLowerCase()===String(x.last||'').toLowerCase());if(claim&&claim.tripCode){Object.assign(x,{tripId:claim.tripId,tripCode:claim.tripCode,vessel:claim.vessel,gate:claim.gate,departureTime:claim.departureTime});links++;}}});state.data.v81.manualFixes=(state.data.v81.manualFixes||0)+links;audit('V81 smart workflow relink',`${links} record(s) linked by route or PSN/last-name claim match`);save();toast(links?`${links} records linked`:'No safe links found');try{renderApp(state.view)}catch(e){}}
function v81OpenCommandSearch(){v81Ensure();state.data.v81.searchCount=(state.data.v81.searchCount||0)+1;save();modal(`<div class="modalHead"><h3>V81 Command Search</h3><button class="small" onclick="closeModal()">✕</button></div><p class="muted">Search trips, baggage estimates, claims, evidence, and audit records.</p><div class="v81SearchBox"><input id="v81SearchInput" placeholder="PSN, last name, trip code, route, vessel, issue..." oninput="v81RunSearch(this.value)"><button class="primary" onclick="v81RunSearch(document.getElementById('v81SearchInput').value)">Search</button></div><div id="v81SearchResults" style="margin-top:12px"></div>`);setTimeout(()=>{try{document.getElementById('v81SearchInput').focus()}catch(e){}},60)}
function v81RunSearch(q){q=String(q||'').trim().toLowerCase();const box=document.getElementById('v81SearchResults');if(!box)return;if(!q){box.innerHTML='<div class="empty">Type a keyword to search local records.</div>';return}const rows=[];(state.data.trips||[]).forEach(x=>{const txt=[x.code,x.vessel,x.routeLabel,v80RouteLabel(x),x.gate,x.status,x.time,x.departureTime].join(' ').toLowerCase();if(txt.includes(q))rows.push(['Trip',x.code||'-',`${v80RouteLabel(x)} · ${x.vessel||''} · ${x.gate||''}`,'renderApp(\'board\')']);});(state.data.transactions||[]).forEach(x=>{const txt=[x.psn,x.tripCode,x.routeLabel,x.vessel,x.baggage,x.kg].join(' ').toLowerCase();if(txt.includes(q))rows.push(['Baggage',x.psn||x.tripCode||'-',`${x.routeLabel||''} · ${v81Money(x.baggage||x.grand||0)}`,'renderApp(\'calculator\')']);});(state.data.claims||[]).forEach(x=>{const txt=[x.psn,x.last,x.tripCode,x.routeLabel,x.type,x.item,x.desc,x.status].join(' ').toLowerCase();if(txt.includes(q))rows.push(['Claim',`${x.psn||'-'} ${x.last||''}`,`${x.type||''} · ${x.status||''} · ${x.tripCode||'no trip'}`,'renderApp(\'track\')']);});(state.data.cases||[]).forEach(x=>{const txt=[x.psn,x.last,x.tripCode,x.routeLabel,x.type,x.color,x.size,x.damage,x.notes,x.status].join(' ').toLowerCase();if(txt.includes(q))rows.push(['Evidence',`${x.psn||'-'} ${x.last||''}`,`${x.type||''} · score ${x.score||0}% · ${x.tripCode||'no trip'}`,'renderApp(\'damage\')']);});(state.data.audit||[]).forEach(x=>{const txt=[x.action,x.detail,x.role,x.time].join(' ').toLowerCase();if(txt.includes(q))rows.push(['Audit',x.action||'-',`${x.time||''} · ${x.detail||''}`,'renderApp(\'reports\')']);});box.innerHTML=rows.length?`<div class="v81TableMini"><table><thead><tr><th>Type</th><th>Record</th><th>Details</th><th></th></tr></thead><tbody>${rows.slice(0,40).map(r=>`<tr><td>${esc(r[0])}</td><td><b>${esc(r[1])}</b></td><td>${esc(r[2])}</td><td><button class="small" onclick="closeModal();${r[3]}">Open</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No matching local records.</div>'}
function v81ExportControlPacket(){const r=v81Readiness();const rows=r.rows.map(x=>`- ${x.trip.code||'-'} / ${x.trip.vessel||'Vessel TBA'} / ${v80RouteLabel(x.trip)} / ${x.trip.gate||'Gate TBA'} / ${x.info.status} / Board ${v80TimeLabel(x.info.boarding)} / Depart ${v80TimeLabel(x.info.departure)}`).join('\n');const risk=r.warnings.map(w=>`- [${w[0].toUpperCase()}] ${w[1]}: ${w[2]}`).join('\n');const checks=Object.entries(state.data.v81.shiftChecks||{}).map(([k,v])=>`- ${k}: ${v?'checked':'open'}`).join('\n');const txt=`OceanJet PortDesk V82 Control Floor Packet\nGenerated: ${today()}\nVersion: ${APP_VERSION}\nRole: ${state.role}\nReadiness: ${r.score}%\nPort: ${state.data.shift.port||'Cebu'}\nStaff: ${state.data.shift.staff||'-'}\n\nTRIP BOARD\n${rows||'-'}\n\nPRIORITY RUN SHEET\n${risk||'-'}\n\nSHIFT CHECKLIST\n${checks||'-'}\n\nLINK MAP\nTrips: ${(state.data.trips||[]).length}\nBaggage linked: ${(state.data.transactions||[]).filter(x=>x.tripCode).length}/${(state.data.transactions||[]).length}\nClaims linked: ${(state.data.claims||[]).filter(x=>x.tripCode).length}/${(state.data.claims||[]).length}\nEvidence linked: ${(state.data.cases||[]).filter(x=>x.tripCode).length}/${(state.data.cases||[]).length}\n\nRECENT AUDIT\n${(state.data.audit||[]).slice(0,40).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail||''}`).join('\n')}`;state.data.v81.lastPacket=today();audit('V81 control floor packet export','TXT handover packet');save();download('OceanJet_V81_Control_Floor_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('V81 control packet downloaded')}
function v81ExportWorkflowJSON(){const r=v81Readiness();const payload={version:APP_VERSION,exportedAt:new Date().toISOString(),readiness:r.score,checks:state.data.v81.shiftChecks||{},trips:v81Rows().map(x=>({id:x.trip.id,code:x.trip.code,vessel:x.trip.vessel,route:v80RouteLabel(x.trip),gate:x.trip.gate,status:x.info.status,boarding:v80TimeLabel(x.info.boarding),departure:v80TimeLabel(x.info.departure)})),links:{transactions:(state.data.transactions||[]).map(x=>({id:x.id,psn:x.psn,tripCode:x.tripCode,route:x.routeLabel,baggage:x.baggage||x.grand})),claims:(state.data.claims||[]).map(x=>({id:x.id,psn:x.psn,last:x.last,tripCode:x.tripCode,status:x.status,type:x.type})),evidence:(state.data.cases||[]).map(x=>({id:x.id,psn:x.psn,last:x.last,tripCode:x.tripCode,status:x.status,score:x.score,locked:!!x.locked,hasStub:!!(x.photos&&x.photos.stub),hasDamage:!!(x.photos&&x.photos.damage)}))},warnings:r.warnings,audit:(state.data.audit||[]).slice(0,80)};audit('V81 workflow JSON export','links and QA packet');save();download('OceanJet_V81_Workflow_QA_'+Date.now()+'.json',JSON.stringify(payload,null,2),'application/json');toast('Workflow JSON downloaded')}
