    state.data.trips.push({id:key,autoScheduleKey:key,code:t.code,vessel:t.vessel,route:t.route,routeLabel:t.routeLabel,time:t.time,departureTime:t.departureTime,boardingTime:t.boardingTime,gate:t.gate,note:t.remarks||'Restored from schedule',autoSchedule:true,updatedAt:today()});
