function makeReceiptFromTxn(id){const x=(state.data.transactions||[]).find(a=>a.id===id); if(!x){toast('Estimate not found');return;} const amount=Number(x.baggage||x.grand||0); state.data.receipts.unshift({id:uid('receipt'),time:today(),psn:x.psn||'',name:'',route:x.route,routeLabel:x.routeLabel||v82RouteLabel(x.route),amount,tripCode:x.tripCode||'',vessel:x.vessel||'',gate:x.gate||'',departureTime:x.departureTime||'',boardingTime:x.boardingTime||'',notes:`Baggage estimate only: ${Number(x.kg||x.weight||0).toFixed(1)}kg, ${x.pax||1} pax, per passenger ${v82Money(x.perPax||0)}`}); audit('Baggage estimate receipt created',`${x.tripCode||x.routeLabel||''} ${v82Money(amount)}`); save(); toast('Baggage receipt created'); renderApp('receipt')}
