function v82AutoHero(){const t=v82CurrentAuto(); if(!t) return `<div class="v82AutoHero"><span class="v82Badge warn">No schedule</span><h2>Schedule not loaded</h2><p>Open System Tools or upload updated schedule.</p></div>`; return `<div class="v82AutoHero"><span class="v82Badge ${v82StatusClass(t.status)}">${esc(t.status)}</span><h2>${['Boarding','Departing Soon'].includes(t.status)?'Now Boarding':'Next Vessel'}: ${esc(t.vessel)}</h2><div class="vessel">${esc(t.routeLabel)}</div><p>${esc(t.gate)} · Automatic schedule pick based on current device time.</p><div class="v82AutoGrid"><div class="v82AutoCell"><span>Boarding Time</span><b>${esc(t.boardingTime)}</b></div><div class="v82AutoCell"><span>Departure Time</span><b>${esc(t.departureTime)}</b></div><div class="v82AutoCell"><span>Arrival</span><b>${esc(t.arrivalTime||'-')}</b></div><div class="v82AutoCell"><span>Updated</span><b>${esc(new Date().toLocaleTimeString('en-PH',{hour:'numeric',minute:'2-digit',hour12:true}))}</b></div></div><div class="miniActions v82NoPrint" style="margin-top:12px"><button class="primary" onclick="v82UseTripForBaggage('${esc(t.id)}')">Use for Baggage</button><button onclick="trips()">Open Schedule</button><button onclick="board()">Refresh Now</button></div></div>`}
