function board(){v82InjectStyles();v82EnsureRoutes();v82SyncScheduleTrips();setTitle('Automatic Vessel Board','Schedule-powered now boarding system'); const rows=v82AutoTrips().filter(t=>t.dayIndex===0); const lanes=['Boarding','Departing Soon','Scheduled','Departed','Closed','Delayed','Cancelled']; $('content').innerHTML=hero('Automatic Vessel Boarding Board','The system automatically finds the next vessel and boarding status from the restored schedule using the current device time.','V82 Auto Board')+`<div class="grid"><div class="card span12">${v82AutoHero()}</div><div class="card span12"><div class="cardHead"><div><h3>Today’s Vessel Lanes</h3><p>Generated from restored V55 schedule. Manual trip records remain available in local storage.</p></div><button class="small" onclick="v82ExportScheduleCSV()">Export Schedule CSV</button></div><div class="v82LaneGrid">${lanes.map(l=>{const list=rows.filter(t=>t.status===l);return `<div class="v82Lane"><h4>${esc(l)} <span class="tiny">${list.length}</span></h4>${list.length?list.slice(0,8).map(t=>`<div class="v82TripCard"><b>${esc(t.vessel)} · ${esc(t.status)}</b><span>${esc(t.routeLabel)}</span><small>Board ${esc(t.boardingTime)} · Depart ${esc(t.departureTime)} · Arrive ${esc(t.arrivalTime||'-')}</small><div class="miniActions" style="margin-top:8px"><button class="small" onclick="v82UseTripForBaggage('${esc(t.id)}')">Use</button></div></div>`).join(''):'<div class="empty">No trips.</div>'}</div>`}).join('')}</div></div><div class="card span12"><div class="cardHead"><div><h3>Complete Schedule</h3><p>V55 schedule restored for Cebu routes and Maasin/Surigao connections.</p></div></div>${v82ScheduleSummary()}</div><div class="span12" style="height:80px"></div></div>`;}
function v82ScheduleSummary(){return `<div class="tableWrap"><table><thead><tr><th>Route</th><th>Trips</th><th>First Departure</th><th>Last Departure</th><th>Travel</th></tr></thead><tbody>${Object.entries(V82_SCHEDULES).map(([k,s])=>`<tr><td>${esc(s.title)}</td><td>${s.trips.length}</td><td>${esc(s.trips[0]?.dep||'-')}</td><td>${esc(s.trips[s.trips.length-1]?.dep||'-')}</td><td>${esc(s.travel)}</td></tr>`).join('')}</tbody></table></div>`}
function trips(){v82InjectStyles();v82EnsureRoutes();setTitle('Schedules','Restored OceanJet schedule'); const keys=Object.keys(V82_SCHEDULES); const selected=keys.includes(state.v82ScheduleRoute)?state.v82ScheduleRoute:'cebu_tagbilaran'; $('content').innerHTML=hero('Routes & Schedules','Restored schedule from the older organized system. The automatic vessel board uses this schedule to choose the next trip.','V82 Schedule')+`<div class="grid"><div class="card span4"><div class="cardHead"><div><h3>Route Selector</h3><p>Tap a route to view schedule.</p></div></div><div style="display:grid;gap:8px">${keys.map(k=>`<button class="v82ScheduleRoute ${selected===k?'active':''}" onclick="v82SelectScheduleRoute('${k}')"><b>${esc(V82_SCHEDULES[k].title)}</b><br><small>${esc(V82_SCHEDULES[k].travel)} · ${V82_SCHEDULES[k].trips.length} trip(s)</small></button>`).join('')}</div></div><div class="card span8"><div id="v82ScheduleDetails"></div></div><div class="card span12"><div class="cardHead"><div><h3>Automatic Boarding Logic</h3><p>Boarding starts ${V82_BOARDING_MIN} minutes before departure, departing soon starts ${V82_SOON_MIN} minutes before departure, and closed appears ${V82_DEPART_GRACE_MIN} minutes after departure.</p></div><button class="small primary" onclick="renderApp('board')">Open Auto Board</button></div>${v82AutoHero()}</div><div class="span12" style="height:80px"></div></div>`; v82RenderScheduleDetails(selected);}
