function v82ExportScheduleCSV(){const rows=[];Object.entries(V82_SCHEDULES).forEach(([route,s])=>(s.trips||[]).forEach(t=>rows.push({route:s.title,departure:t.dep,vessel:t.vessel,arrival:t.arr,travel:s.travel,remarks:t.remarks||''}))); download('OceanJet_V82_Restored_Schedule_'+Date.now()+'.csv',csv(rows,['route','departure','vessel','arrival','travel','remarks']),'text/csv');toast('Schedule CSV downloaded')}
