const V83_SYNC_VERSION = 'V83 Google Sync Bridge';
const V83_SYNC_DEFAULTS = {
  endpoint:'', token:'', mode:'compact', includePhotos:false,
  lastPush:'', lastPull:'', lastTest:'', pending:0,
  importedSchedules:null, logs:[], connected:false
};
function v83InjectStyles(){
  if(document.getElementById('v83Style')) return;
  const css=document.createElement('style'); css.id='v83Style'; css.textContent=`
  .v83CloudGrid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px}.v83CloudTile{border:1px solid var(--line);border-radius:18px;padding:13px;background:rgba(255,255,255,.045);display:grid;gap:4px}.v83CloudTile span{font-size:.74rem;text-transform:uppercase;letter-spacing:.04em;color:var(--muted);font-weight:900}.v83CloudTile b{font-size:1.25rem}.v83Status{display:inline-flex;align-items:center;gap:7px;border-radius:999px;padding:7px 11px;font-size:.78rem;font-weight:1000;border:1px solid var(--line)}.v83Status.ok{color:#9cf4d0;background:rgba(35,196,131,.12);border-color:rgba(35,196,131,.35)}.v83Status.warn{color:#ffe4a6;background:rgba(247,183,49,.12);border-color:rgba(247,183,49,.35)}.v83Status.bad{color:#ffb3c2;background:rgba(255,92,122,.12);border-color:rgba(255,92,122,.35)}.v83ActionGrid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}.v83ActionGrid button{text-align:left;display:grid;gap:4px;min-height:92px}.v83ActionGrid button small{color:var(--muted);font-weight:700}.v83CodeBox{white-space:pre-wrap;font-family:ui-monospace,SFMono-Regular,Consolas,monospace;font-size:.78rem;line-height:1.4;max-height:300px;overflow:auto;border:1px solid var(--line);border-radius:16px;padding:12px;background:rgba(0,0,0,.18)}.v83SyncLog{display:grid;gap:8px}.v83SyncLog div{border-left:3px solid rgba(0,184,217,.55);background:rgba(255,255,255,.04);border-radius:12px;padding:9px 10px}.v83SyncLog b{display:block}.v83Mapping{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.v83Mapping div{border:1px solid var(--line);border-radius:16px;padding:10px;background:rgba(255,255,255,.04)}.v83SyncBanner{border:1px solid rgba(0,184,217,.32);border-radius:22px;padding:16px;background:linear-gradient(135deg,rgba(0,184,217,.14),rgba(35,196,131,.08));display:flex;justify-content:space-between;gap:12px;align-items:flex-start}.v83SyncBanner h3{margin:0}.v83SyncBanner p{margin:5px 0 0;color:var(--muted)}
  @media(max-width:900px){.v83CloudGrid,.v83ActionGrid,.v83Mapping{grid-template-columns:1fr}.v83SyncBanner{display:grid}}
  `; document.head.appendChild(css);
}
function v83Ensure(){
  try{ensureData();}catch(e){}
  state.data.cloudSync = {...V83_SYNC_DEFAULTS, ...(state.data.cloudSync||{})};
  state.data.cloudSync.logs ||= [];
  if(state.data.cloudSync.importedSchedules){try{Object.assign(V82_SCHEDULES,state.data.cloudSync.importedSchedules);v82EnsureRoutes();}catch(e){}}
  return state.data.cloudSync;
}
const v83PrevEnsureData = ensureData;
ensureData = function(){v83PrevEnsureData(); state.data.cloudSync = {...V83_SYNC_DEFAULTS, ...(state.data.cloudSync||{})}; state.data.cloudSync.logs ||= [];};
function v83SyncLog(kind,msg,ok=true){const s=v83Ensure();s.logs.unshift({time:today(),kind,msg,ok});s.logs=s.logs.slice(0,30);}
function v83MarkDirty(action,detail){const s=v83Ensure(); if(String(action||'').startsWith('V83 Google')) return; s.pending=(Number(s.pending)||0)+1; s.lastDirty=today();}
const v83PrevAudit = audit;
audit = function(action,detail){v83PrevAudit(action,detail);try{v83MarkDirty(action,detail)}catch(e){}};
const v83PrevSave = save;
save = function(){try{v83Ensure()}catch(e){} return v83PrevSave();};
function v83SyncCounts(){v83Ensure(); return {trips:(state.data.trips||[]).length, schedule:Object.values(V82_SCHEDULES||{}).reduce((a,s)=>a+(s.trips||[]).length,0), claims:(state.data.claims||[]).length, evidence:(state.data.cases||[]).length, baggage:(state.data.transactions||[]).length, receipts:(state.data.receipts||[]).length, audit:(state.data.audit||[]).length};}
function v83SafeEvidenceRecord(x,includePhotos){const y={...x}; if(!includePhotos && y.photos){y.photoSummary={stub:!!y.photos.stub,damage:!!y.photos.damage}; delete y.photos;} return y;}
function v83BuildPayload(kind='snapshot'){
  const s=v83Ensure(); const counts=v83SyncCounts(); const includePhotos=!!s.includePhotos;
  return {app:'OceanJet PortDesk',version:APP_VERSION,bridge:V83_SYNC_VERSION,kind,exportedAt:new Date().toISOString(),store:STORE,role:state.role,counts,
    schedules:V82_SCHEDULES,
    data:{
      trips:(state.data.trips||[]).slice(-500),
      transactions:(state.data.transactions||[]).slice(0,500),
      claims:(state.data.claims||[]).slice(0,500),
      cases:(state.data.cases||[]).slice(0,250).map(x=>v83SafeEvidenceRecord(x,includePhotos)),
      receipts:(state.data.receipts||[]).slice(0,500),
      audit:(state.data.audit||[]).slice(0,250),
      shift:state.data.shift||{},
      cloudSync:{lastPush:s.lastPush,lastPull:s.lastPull,pending:s.pending,mode:s.mode,includePhotos:s.includePhotos}
    }};
}
function v83Endpoint(){return (document.getElementById('syncEndpoint')?.value || v83Ensure().endpoint || '').trim();}
function v83Token(){return (document.getElementById('syncToken')?.value || v83Ensure().token || '').trim();}
function v83SaveSyncSettings(){const s=v83Ensure();s.endpoint=v83Endpoint();s.token=v83Token();s.mode=document.getElementById('syncMode')?.value||s.mode||'compact';s.includePhotos=!!document.getElementById('syncPhotos')?.checked;audit('V83 Google sync settings saved',s.endpoint?'endpoint configured':'no endpoint');save();toast('Google Sync settings saved');try{sync()}catch(e){}}
function v83ClearSyncSettings(){if(!confirm('Clear Google Sync endpoint and token from this device?'))return;const s=v83Ensure();s.endpoint='';s.token='';s.connected=false;s.lastTest='';v83SyncLog('settings','Cloud endpoint cleared',true);audit('V83 Google sync settings cleared','device config removed');save();sync();}
async function v83FetchGoogle(action,payload){const endpoint=v83Endpoint(), token=v83Token(); if(!endpoint){toast('Enter Google Apps Script web app URL first');throw new Error('Missing endpoint');}
  const body=new URLSearchParams(); body.set('action',action); body.set('token',token); if(payload) body.set('payload',JSON.stringify(payload));
  const res=await fetch(endpoint,{method:'POST',body}); const txt=await res.text(); let data; try{data=JSON.parse(txt)}catch(e){data={ok:res.ok,text:txt}}; if(!res.ok || data.ok===false){throw new Error(data.error||txt||('HTTP '+res.status));} return data;}
async function v83TestGoogle(){const s=v83Ensure();try{v83SaveSyncSettings();const data=await v83FetchGoogle('ping',{version:APP_VERSION,deviceTime:new Date().toISOString()});s.connected=true;s.lastTest=today();v83SyncLog('test','Connection OK: '+(data.message||'Apps Script responded'),true);audit('V83 Google sync test','connection OK');save();toast('Google Sync connected');sync();}catch(e){s.connected=false;v83SyncLog('test','Connection failed: '+e.message,false);audit('V83 Google sync test failed',e.message);save();toast('Google Sync failed: '+e.message);sync();}}
async function v83PushGoogle(){const s=v83Ensure();try{v83SaveSyncSettings();const payload=v83BuildPayload(s.mode||'snapshot');const data=await v83FetchGoogle('pushSnapshot',payload);s.lastPush=today();s.pending=0;s.connected=true;v83SyncLog('push','Pushed '+JSON.stringify(payload.counts)+' · '+(data.message||'saved'),true);audit('V83 Google push','snapshot uploaded to bridge');save();toast('Google Sync push complete');sync();}catch(e){v83SyncLog('push','Push failed: '+e.message,false);audit('V83 Google push failed',e.message);save();toast('Push failed: '+e.message);sync();}}
async function v83PullGoogle(){const s=v83Ensure();try{v83SaveSyncSettings();const data=await v83FetchGoogle('pullSchedule',{want:'schedules',version:APP_VERSION});let schedules=data.schedules || data.payload?.schedules || null; if(!schedules && data.data?.schedules) schedules=data.data.schedules; if(schedules){Object.assign(V82_SCHEDULES,schedules);s.importedSchedules=schedules;v82EnsureRoutes();v82SyncScheduleTrips();}
  s.lastPull=today();s.connected=true;v83SyncLog('pull',schedules?'Pulled schedule and refreshed route board':'Connected, but no schedules returned',!!schedules);audit('V83 Google pull',schedules?'schedule imported':'no schedule payload');save();toast(schedules?'Schedule pulled from Google':'No schedule returned');sync();}catch(e){v83SyncLog('pull','Pull failed: '+e.message,false);audit('V83 Google pull failed',e.message);save();toast('Pull failed: '+e.message);sync();}}
function v83DownloadSnapshot(){const p=v83BuildPayload('manual-download');download('OceanJet_V83_Google_Sync_Payload_'+Date.now()+'.json',JSON.stringify(p,null,2),'application/json');audit('V83 Google payload downloaded','manual sync JSON');save();toast('Sync payload downloaded')}
function v83DownloadAppsScript(){download('OceanJet_Google_Sync_AppsScript_Template.txt',v83AppsScriptTemplate(),'text/plain');toast('Apps Script template downloaded')}
function v83CopyAppsScript(){const txt=v83AppsScriptTemplate();navigator.clipboard?.writeText(txt);toast('Apps Script template copied')}
function v83ImportScheduleFile(ev){const f=ev.target.files?.[0];if(!f)return;const rd=new FileReader();rd.onload=()=>{try{const obj=JSON.parse(rd.result);const schedules=obj.schedules||obj;Object.assign(V82_SCHEDULES,schedules);const s=v83Ensure();s.importedSchedules=schedules;v82EnsureRoutes();v82SyncScheduleTrips();audit('V83 schedule JSON imported',Object.keys(schedules).length+' route(s)');save();toast('Schedule JSON imported');try{trips()}catch(e){} }catch(e){toast('Invalid schedule JSON')}};rd.readAsText(f);ev.target.value=''}
function v83AppsScriptTemplate(){return `/* OceanJet PortDesk Google Sync Bridge - Apps Script starter
Deploy: Apps Script > Deploy > New deployment > Web app.
Access: Anyone with link, or your workspace users. Paste the Web App URL in PortDesk Sync Center.
Security: Change TOKEN below. This simple bridge writes snapshots to Google Sheets.
*/
const TOKEN = 'CHANGE_THIS_TOKEN';
const SHEET_NAME = 'OceanJet_PortDesk_Sync';
function doPost(e){
  const action = (e.parameter.action || '').trim();
  const token = (e.parameter.token || '').trim();
  if (TOKEN && token !== TOKEN) return json({ok:false,error:'Invalid token'});
  if (action === 'ping') return json({ok:true,message:'OceanJet Google Sync Bridge online',time:new Date().toISOString()});
  const payload = e.parameter.payload ? JSON.parse(e.parameter.payload) : {};
  if (action === 'pushSnapshot') return saveSnapshot(payload);
  if (action === 'pullSchedule') return json({ok:true,schedules:getLatestSchedule_()});
  return json({ok:false,error:'Unknown action: '+action});
}
function doGet(e){ return doPost(e); }
function saveSnapshot(payload){
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = getSheet_(ss, SHEET_NAME, ['Saved At','Version','Kind','Counts JSON','Payload JSON']);
  sheet.appendRow([new Date(), payload.version || '', payload.kind || '', JSON.stringify(payload.counts || {}), JSON.stringify(payload)]);
  writeRows_(ss,'Trips', payload.data && payload.data.trips || []);
  writeRows_(ss,'Baggage', payload.data && payload.data.transactions || []);
  writeRows_(ss,'Claims', payload.data && payload.data.claims || []);
  writeRows_(ss,'Evidence_Metadata', payload.data && payload.data.cases || []);
  writeRows_(ss,'Receipts', payload.data && payload.data.receipts || []);
  writeRows_(ss,'Audit', payload.data && payload.data.audit || []);
  return json({ok:true,message:'Snapshot saved',savedAt:new Date().toISOString()});
}
function writeRows_(ss,name,rows){
  const sheet = getSheet_(ss,name,[]); sheet.clearContents();
  if(!rows.length){ sheet.getRange(1,1).setValue('No rows'); return; }
  const headers = Object.keys(rows[0]); sheet.getRange(1,1,1,headers.length).setValues([headers]);
  sheet.getRange(2,1,rows.length,headers.length).setValues(rows.map(r=>headers.map(h=> typeof r[h] === 'object' ? JSON.stringify(r[h]) : r[h])));
}
function getLatestSchedule_(){
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName('Schedule_JSON');
  if(!sheet) return null;
  const text = String(sheet.getRange('A1').getValue() || '').trim();
  return text ? JSON.parse(text) : null;
}
function getSheet_(ss,name,headers){ let sh=ss.getSheetByName(name); if(!sh) sh=ss.insertSheet(name); if(headers.length && sh.getLastRow()===0) sh.appendRow(headers); return sh; }
function json(obj){ return ContentService.createTextOutput(JSON.stringify(obj)).setMimeType(ContentService.MimeType.JSON); }
`;}
function v83SheetMappingHtml(){return `<div class="v83Mapping"><div><b>Trips</b><p class="tiny">Trip code, vessel, route, boarding time, departure time, gate, status.</p></div><div><b>Baggage</b><p class="tiny">Baggage estimates, class, pax, kg, free allowance, excess, final baggage fee.</p></div><div><b>Claims</b><p class="tiny">PSN, last name, route, issue type, status, trip link when available.</p></div><div><b>Evidence_Metadata</b><p class="tiny">Official evidence metadata and pair status. Photos are excluded unless you enable include photos.</p></div><div><b>Receipts</b><p class="tiny">Baggage receipt records and printed desk references.</p></div><div><b>Audit</b><p class="tiny">Staff actions, role, date/time, and details.</p></div></div>`}
function v83SyncLogHtml(){const logs=v83Ensure().logs||[];return logs.length?`<div class="v83SyncLog">${logs.slice(0,12).map(x=>`<div><b>${esc(x.kind)} · ${esc(x.time)}</b><span class="tiny">${esc(x.msg)}</span></div>`).join('')}</div>`:'<div class="empty">No sync log yet. Test connection or download payload first.</div>'}
function v83CloudTiles(){const s=v83Ensure(), c=v83SyncCounts();return `<div class="v83CloudGrid"><div class="v83CloudTile"><span>Status</span><b>${s.connected?'Connected':'Local'}</b><small class="tiny">${s.endpoint?'endpoint saved':'no endpoint'}</small></div><div class="v83CloudTile"><span>Pending Changes</span><b>${Number(s.pending)||0}</b><small class="tiny">manual push only</small></div><div class="v83CloudTile"><span>Schedule Trips</span><b>${c.schedule}</b><small class="tiny">auto vessel board</small></div><div class="v83CloudTile"><span>Last Push</span><b>${esc(s.lastPush||'Never')}</b><small class="tiny">Google bridge</small></div></div>`}
function sync(){v83InjectStyles();const s=v83Ensure();setTitle('Google Sync Bridge','Offline-first cloud backup and schedule import');$('content').innerHTML=hero('Google Sync Bridge','Use local browser storage first, then manually push backups to a Google Apps Script bridge for Google Sheets/Drive-style workflow. No hidden background sync.','V83 Cloud')+`<div class="grid"><div class="card span12"><div class="v83SyncBanner"><div><h3>Offline-first + Google backup</h3><p>The app still works without internet. Google Sync is admin-controlled and runs only when staff taps Test, Push, or Pull.</p></div><span class="v83Status ${s.connected?'ok':s.endpoint?'warn':'bad'}">${s.connected?'Connected':s.endpoint?'Configured':'Not configured'}</span></div><div style="margin-top:12px">${v83CloudTiles()}</div></div><div class="card span7"><div class="cardHead"><div><h3>Google Apps Script Endpoint</h3><p>Paste your deployed Web App URL and optional token.</p></div><span class="badge ok">Manual Sync</span></div><div class="formGrid"><label>Web App URL<input id="syncEndpoint" value="${esc(s.endpoint||'')}" placeholder="https://script.google.com/macros/s/.../exec"></label><label>API Token<input id="syncToken" value="${esc(s.token||'')}" placeholder="Optional shared token"></label><label>Sync Mode<select id="syncMode"><option value="compact" ${s.mode==='compact'?'selected':''}>Compact metadata</option><option value="full" ${s.mode==='full'?'selected':''}>Full local records</option></select></label><label style="align-items:start"><span>Evidence Photos</span><span class="tiny">OFF by default to avoid very large uploads.</span><input id="syncPhotos" type="checkbox" ${s.includePhotos?'checked':''}></label></div><div class="miniActions"><button class="primary" onclick="v83SaveSyncSettings()">Save Settings</button><button onclick="v83TestGoogle()">Test Connection</button><button class="danger" onclick="v83ClearSyncSettings()">Clear</button></div><div class="notice" style="margin-top:12px">For GitHub Pages, use Apps Script Web App URL. The app uses simple form POST to avoid complex OAuth setup.</div></div><div class="card span5"><div class="cardHead"><div><h3>Sync Actions</h3><p>Staff-triggered only.</p></div></div><div class="v83ActionGrid"><button class="primary" onclick="v83PushGoogle()"><b>Push to Google</b><small>Trips, baggage, claims, evidence metadata, receipts, audit</small></button><button onclick="v83PullGoogle()"><b>Pull Schedule</b><small>Import Google schedule JSON if available</small></button><button onclick="v83DownloadSnapshot()"><b>Download Payload</b><small>Manual JSON for upload/testing</small></button></div></div><div class="card span6"><div class="cardHead"><div><h3>Google Sheet Mapping</h3><p>The starter bridge creates these tabs.</p></div></div>${v83SheetMappingHtml()}</div><div class="card span6"><div class="cardHead"><div><h3>Apps Script Starter</h3><p>Download or copy, paste into Apps Script, deploy as Web App.</p></div></div><div class="miniActions"><button class="primary" onclick="v83DownloadAppsScript()">Download Template</button><button onclick="v83CopyAppsScript()">Copy Code</button></div><div class="v83CodeBox" style="margin-top:12px">${esc(v83AppsScriptTemplate().slice(0,1600))}\n...</div></div><div class="card span6"><div class="cardHead"><div><h3>Schedule Import</h3><p>Use this if you manually export or receive schedule JSON.</p></div></div><label class="fileBtn">Import Schedule JSON<input type="file" accept="application/json" onchange="v83ImportScheduleFile(event)"></label><div class="notice" style="margin-top:12px">Schedule import updates the automatic vessel board and baggage trip selector on this device.</div></div><div class="card span6"><div class="cardHead"><div><h3>Latest Sync Log</h3><p>Newest first.</p></div></div>${v83SyncLogHtml()}</div><div class="span12" style="height:90px"></div></div>`;v83RefreshChrome();}
