function v83SyncPanel(){const s=v83Ensure();return `<div class="card span12"><div class="cardHead"><div><h3>V83 Google Sync Bridge</h3><p>Offline-first storage with manual Google Apps Script backup/schedule import.</p></div><span class="badge ${s.connected?'ok':s.endpoint?'warn':'bad'}">${s.connected?'Connected':s.endpoint?'Configured':'Local only'}</span></div>${v83CloudTiles()}<div class="miniActions" style="margin-top:12px"><button class="primary" onclick="renderApp('sync')">Open Sync Center</button><button onclick="v83DownloadSnapshot()">Download Sync Payload</button><button onclick="v83DownloadAppsScript()">Apps Script Template</button></div></div>`}
