try{if(NAVS.admin && !NAVS.admin.some(n=>n[0]==='sync')) NAVS.admin.push(['sync','☁️','Cloud Sync']);}catch(e){}
const v83PrevDashboard = dashboard;
dashboard = function(){v83InjectStyles();v83Ensure();v83PrevDashboard(); if(state.role==='admin') v83AppendToGrid(v83SyncPanel()); v83RefreshChrome();};
