const v83PrevRunDiagnostics = runDiagnostics;
runDiagnostics = function(){let base={};try{base=v83PrevRunDiagnostics()||{};}catch(e){base={previousDiagnosticsError:String(e)}}const s=v83Ensure(), c=v83SyncCounts();const d={...base,v83:{version:APP_VERSION,store:STORE,cloudSync:{endpointConfigured:!!s.endpoint,connected:!!s.connected,lastPush:s.lastPush||'',lastPull:s.lastPull||'',pending:s.pending||0,includePhotos:!!s.includePhotos},counts:c,storageMode:'offline first with manual Google Apps Script bridge',hiddenBackgroundSync:'none',newRepairLoops:'none added by V83'}};const out=$('diagOut');if(out)out.innerHTML='<pre class="mono">'+esc(JSON.stringify(d,null,2))+'</pre>';return d;};
openQuickHelp = function(){modal(`<div class="modalHead"><h3>OceanJet PortDesk V83 Notes</h3><button class="small" onclick="closeModal()">✕</button></div><ul><li>V83 adds an offline-first Google Sync Bridge for manual Google Sheets/Apps Script backup and schedule import.</li><li>The app still uses browser storage first, so it can work without internet.</li><li>Google Sync runs only when Admin taps Test, Push, Pull, Download Payload, or exports the Apps Script template.</li><li>Baggage calculator keeps the organized V55-style UI and baggage-only receipt from V82.</li><li>The automatic vessel board still chooses the next vessel from the schedule based on current device time.</li><li>No recovery loop, scanner automation, DOM observer repair, interval UI repair, or hidden navigation fixer was added.</li></ul>`)};
const v83PrevVerifyCoreFunctions = verifyCoreFunctions;
