function v84ControlPacket(){const t=v84PickTrip();const out=v84Ensure().outbox||[];const txt=`OceanJet PortDesk V84 Control Packet\nGenerated: ${today()}\nRole: ${state.role}\n\nCURRENT / NEXT VESSEL\n${t?`${t.vessel} / ${t.routeLabel}\nStatus: ${t.status}\nBoarding: ${t.boardingTime}\nDeparture: ${t.departureTime}\nGate: ${t.gate||'TBA'}\nAction: ${v84NextTripText(t)}`:'No trip'}\n\nCOUNTS\nClaims: ${(state.data.claims||[]).length}\nEvidence: ${(state.data.cases||[]).length}\nBaggage estimates: ${(state.data.transactions||[]).length}\nReceipts: ${(state.data.receipts||[]).length}\nOutbox: ${out.length}\n\nOUTBOX\n${out.slice(0,40).map(x=>`- ${x.time} / ${x.module} / ${x.action} / ${x.detail}`).join('\n')||'-'}\n\nRECENT AUDIT\n${(state.data.audit||[]).slice(0,30).map(a=>`- ${a.time} / ${a.role} / ${a.action} / ${a.detail||''}`).join('\n')}`;state.data.v84.lastControlPacket=today();audit('V84 control packet export','TXT');save();download('OceanJet_V84_Control_Packet_'+Date.now()+'.txt',txt,'text/plain');toast('V84 control packet downloaded')}
const v84PrevSystem = system;
